-- Poems batch 343
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d5e8fdea-caad-4e8d-9ced-b384ed0e125b','有感三首  其二','張耒','宋','宋诗','song-poetry','','[]','羣兒鞭笞學官府，翁憐癡兒傍笑侮。',64,'全唐诗/poet.song.64000.json','["羣兒鞭笞學官府，翁憐癡兒傍笑侮。", "翁出坐曹鞭復呵，賢於羣兒能幾何。", "兒曹相鞭以爲戲，翁怒鞭人血流地。", "等爲戲劇誰後先，我笑謂翁兒更賢。"]'),
('33854721-5358-421f-bfc5-580be6bfeb93','有感三首  其三','張耒','宋','宋诗','song-poetry','','[]','南風霏霏麥花落，豆田漠漠初垂角。',64,'全唐诗/poet.song.64000.json','["南風霏霏麥花落，豆田漠漠初垂角。", "山邊夜半一犂雨，田父高歌待收穫。", "雨多蕭蕭蠶簇寒，蠶婦低眉憂繭單。", "人生多求復多怨，天工供爾良獨難。"]'),
('dbd6c7ca-d3b1-4661-81dc-bc4d082427c2','題大蘇凈居寺','張耒','宋','宋诗','song-poetry','','[]','平生愛山如好德，未嘗一飯忘泉石。',160,'全唐诗/poet.song.64000.json','["平生愛山如好德，未嘗一飯忘泉石。", "大蘇山下松栢林，路盡重門照金碧。", "思公得道神所相，指示巖幽駐瓶錫。", "天台妙教源欲啟，來此一酌曹溪滴。", "兩公道場守龍象，兵火暫晦終輝赫。", "撞鐘伐鼓食千指，皆二大士之餘力。", "縈紆石磴造山頂，上有玉人方燕寂。", "北軒三伏飛冰雪，一日掠盡淮山色。", "東遊塵土我實倦，道過化城聊暫息。", "青鞋布襪舊家風，此身終效名山役。"]'),
('5d752fc4-e708-4562-99f8-4b294ffc0db2','客過','張耒','宋','宋诗','song-poetry','','[]','歲窮北風卷平楚，張子畏寒深閉戶。',64,'全唐诗/poet.song.64000.json','["歲窮北風卷平楚，張子畏寒深閉戶。", "叩門過我者爲誰，束带出見亦良苦。", "俯眉謂客子勿瞋，我心善煩勿多語。", "天寒酒賤曷不飲，安用造謁勤如許。"]'),
('3fcefe1e-7c6c-471d-9fbd-df24d755b89c','謁客','張耒','宋','宋诗','song-poetry','','[]','入門投刺吏翩翩，我非欲見禮則然。',64,'全唐诗/poet.song.64000.json','["入門投刺吏翩翩，我非欲見禮則然。", "異哉賓主兩無語，客起疾走如避然。", "我已不恭愧昔賢，忍使塗炭朝衣冠。", "人生暫聚鴻集川，春風吹飛何後先。"]'),
('e9a1be8b-7d4a-4a31-9410-de846a10dfd0','迎客','張耒','宋','宋诗','song-poetry','','[]','城門抱關皆老兵，問客來早天未明。',64,'全唐诗/poet.song.64000.json','["城門抱關皆老兵，問客來早天未明。", "我笑老翁勿嘲訕，我愧古人百千萬。", "道傍赫赫翁所見，寒熱郡國欺鄉縣。", "人之所畏敢不畏，嗟我此翁安得慢。"]'),
('33065891-1ae2-4378-82cb-0e854bf0fdd8','局中晝睡','張耒','宋','宋诗','song-poetry','','[]','鳥啼花開千萬思，春色醉人成午睡。',96,'全唐诗/poet.song.64000.json','["鳥啼花開千萬思，春色醉人成午睡。", "燒香掃地一室間，藜床布枕平生事。", "君知章華久寂寞，楚夢無人憚青兕。", "東風轉野作晴雷，蕩蹙山川作紅翠。", "白日下照七澤寬，孤城樓觀失餘寒。", "頗怪故山頻入夢，年來真厭楚人餐。"]'),
('a75d6aa1-c4fb-4e76-8c62-c2c2f9865080','園花盛開秬病不能觀作詩諭之','張耒','宋','宋诗','song-poetry','','[]','東風著花花披靡，花風吹人人欲醉。',64,'全唐诗/poet.song.64000.json','["東風著花花披靡，花風吹人人欲醉。", "老翁逢花如啜醨，强自挹酌終無味。", "鬭紅鬭綠態千萬，長笑花工夸幻事。", "若知空色無異觀，世上何曾有桃李。"]'),
('d5996d80-e93d-415b-a022-2b5724c5f9a2','小孤山','張耒','宋','宋诗','song-poetry','','[]','一峰枝水孤劍立，古廟開簾雙臉紅。',80,'全唐诗/poet.song.64000.json','["一峰枝水孤劍立，古廟開簾雙臉紅。", "水邊古木老龍蟄，山下水色磨青銅。", "我來扁舟望有禱，萬頃春水清溶溶。", "明神報我意加厚，嗟我薦獻愧不豐。", "重遊知復在何日，俯仰天地身飄蓬。"]'),
('e0393677-0328-4984-a025-415a04d2d3fc','初伏大雨呈无咎','張耒','宋','宋诗','song-poetry','','[]','初伏炎炎坐湯釜，長安行人汗沾土。',128,'全唐诗/poet.song.64000.json','["初伏炎炎坐湯釜，長安行人汗沾土。", "誰傾江海作清凉，玄雲駕風橫白雨。", "普陀真人甘露手，能使渴乏厭膏乳。", "且欲當風展簟眠，敢辭避漏移床苦。", "清貧學士卧陶齋，壁上墨君澹無語。", "翰林但解嘲苜蓿，彭宣不得窺歌舞。", "聯詩得句笑出省，策馬涉泥歸閉戶。", "床頭餘榼定何嫌，窗外石榴堪薦俎。"]'),
('a927b256-da4d-4c8b-a57d-c2ea3d026b6d','謝黄師是惠碧瓷枕','張耒','宋','宋诗','song-poetry','','[]','鞏人作枕堅且青，故人贈我消炎蒸。',96,'全唐诗/poet.song.64000.json','["鞏人作枕堅且青，故人贈我消炎蒸。", "持之入室凉風生，腦寒髮冷泥丸驚。", "夢入瑶都碧玉城，仙翁支頤飯未成。", "鶴鳴月高夜三更，報秋不勞桐葉聲。", "我老耽書睡苦輕，遶床惟有書縱橫。", "不如華堂伴玉屏，寶鈿敧斜雲髻傾。"]'),
('30a03136-99fa-4828-bbf6-4569946dc279','到陳午憩小舍有任王二君子惠牡丹二盤皆絕品也是日風雨大寒明日作此詩呈希古','張耒','宋','宋诗','song-poetry','','[]','初來淮陽春已晚，下里數楹聊寢飯。',176,'全唐诗/poet.song.64000.json','["初來淮陽春已晚，下里數楹聊寢飯。", "此邦花時人若狂，我初稅駕遊獨懶。", "任王二君真解事，來致兩盤紅紫爛。", "天姝國艷照蔀屋，持供佛像安敢慢。", "江湖逢春豈無花，格頑色賤皆可揀。", "誓觀中州燕趙態，一洗千里窮荒眼。", "風波歷盡還故郡，此願誰知輒先滿。", "那知中夕忽凜烈，卧擁牛衣眠失旦。", "名園泥淖安可入，坐惜殘芳風雨散。", "東鄰夫子亦嗜酒，卧聽午雞方起盥。", "晴明猶及一寓目，我老尚能揮大盞。"]'),
('065eb419-b69b-440e-8267-010deb7baae6','次韵答天啟','張耒','宋','宋诗','song-poetry','','[]','黄鍾無聲登瓦釜，蔡子青衫在塵土。',128,'全唐诗/poet.song.64000.json','["黄鍾無聲登瓦釜，蔡子青衫在塵土。", "逼人爽氣百步寒，知子胸中有風雨。", "三年河東走胡馬，絕口魚蝦便酪乳。", "歸來萬卷付一讀，不學兒曹用心苦。", "周瑜陸遜久寂寞，千年北客嘲吳語。", "莫徒彩筆雲錦張，要是寶劍蛟龍舞。", "天兵百萬老西北，快馬如飛不出戶。", "眼看六纛出麒麟，走取單于置刀俎。"]'),
('4f92fe31-6dfe-47eb-9c02-b04a138ce8ad','麞猿圖','張耒','宋','宋诗','song-poetry','','[]','陰巖萬古無纖塵，木石翠潤無冬春。',88,'全唐诗/poet.song.64000.json','["陰巖萬古無纖塵，木石翠潤無冬春。", "時哉兩猿掛復蹲，其一抱子爲屈伸。", "下有遊貆意甚馴，雄雌嬉遊循水濱。", "沐猴遇麞愕欲奔，據高自得俯而捫。", "懸之門堂閱疑真，妙哉易生筆有神，以此成名以終身。"]'),
('4578cf71-8ad6-400c-b415-01a7bb32eb6e','謝錢穆父惠高麗扇','張耒','宋','宋诗','song-poetry','','[]','三韓使者文章公，東夷守臣親掃宮。',64,'全唐诗/poet.song.64000.json','["三韓使者文章公，東夷守臣親掃宮。", "清嚴不受橐中獻，萬里歸來兩松扇。", "六月長安汗如洗，豈意落我懷袖裏。", "中州翦就霜雪紈，千年淳風古箕子。"]'),
('7fdcfead-26c3-4cd4-a650-84ad77d4fa62','聞蛩有感','張耒','宋','宋诗','song-poetry','','[]','遙夜飛螢動秋思，獨卧空山驚晚歲。',160,'全唐诗/poet.song.64000.json','["遙夜飛螢動秋思，獨卧空山驚晚歲。", "可堪六月已聞蛩，日暮咿咿響庭際。", "關河多風氣蕭索，碧樹先秋早摇落。", "鳴機夜織常怨寒，白紵吳衫苦輕薄。", "年年促織誰最悲，堂上美人愁翠眉。", "清砧搗練對殘月，玉筯啼紅裁遠衣。", "唐風詩人勸其主，行邁苦遲嗟歲暮。", "山城聽汝已三年，三年白髮多於故。", "飄飄秋夢到江湖，我欲東歸鱠碧鱸。", "安能爲爾將雙淚，歲歲風前沾客裾。"]'),
('1d291309-5786-4e2c-b298-742f5a748e00','赴亳州教官次韵和中書錢舍人及亳州守晁美叔見贈','張耒','宋','宋诗','song-poetry','','[]','久知疏慵難應接，勉强一官親訟牒。',320,'全唐诗/poet.song.64000.json','["久知疏慵難應接，勉强一官親訟牒。", "羈窮正似鳩無巢，擺去不如魚有鬣。", "從來書史鈍蹊徑，更歎詩騷窮事業。", "幾思狐白易絮纊，羞褫舊服求新裌。", "又憐夸毗竟何得，把玩區區一蚊睫。", "久知趨向合饑寒，正藉文章漫嚅囁。", "紫微丈人椽作筆，誰得羸師傳諜諜。", "知擒敢慢武侯縱，有穽前知魯侯敜。", "荒蕪滿編求指摘，望以餘光分暐燁。", "乃蒙稱屈力褒揚，不意糞壤藏諸篋。", "獲如丘陵飽則可，良御不悅猶非獵。", "平生遇賞有君子，處世雖鈍吾知捷。", "清閒得食學官祿，願以詩書填吻頰。", "牙懸喜校鄴侯籤，藤織新成沈郎笈。", "晁公聲名三十載，餘事筆蹤傳法帖。", "紫芝眉宇望不遠，屈指數日無旬浹。", "黄衫健步書見賜，紫誥除官等何躐。", "久懷薄技待後乘，宣管盈囊紙來歙。", "坐乖前計空惋悵，袖裏從今雙手壓。", "醉歸應被官長瞋，來飽徒勞方朔臘。"]'),
('b81e6818-c5eb-4867-9d36-c0b23f11b853','暑毒不可過又每爲賓客見擾午寢不安奉懷邠老之無事也','張耒','宋','宋诗','song-poetry','','[]','桃李成塵鶯未老，梧桐未落蛩已多。',64,'全唐诗/poet.song.64000.json','["桃李成塵鶯未老，梧桐未落蛩已多。", "杜門高卧作閒計，挾策讀書如懶何。", "頗遭褦襶驚午夢，正坐熱行官不呵。", "柯山大隠羲皇上，清風一榻無經過。"]'),
('252017d9-98e5-4516-858e-b3731dd65260','和立之消梅','張耒','宋','宋诗','song-poetry','','[]','木奴度淮輒爲枳，后皇嗇之理應爾。',64,'全唐诗/poet.song.64000.json','["木奴度淮輒爲枳，后皇嗇之理應爾。", "青梅千里江南春，何時相逢車馬塵。", "我衰病齒不能酸，微香觸鼻舌生泉。", "想見曹瞞老狡獪，指林駐馬三軍前。"]'),
('dc58658e-72e8-469d-8e62-e5e42672e86e','送歐陽經赴蒲圻','張耒','宋','宋诗','song-poetry','','[]','異時堂飲洋川酒，幾喚扁舟度樊口。',64,'全唐诗/poet.song.64000.json','["異時堂飲洋川酒，幾喚扁舟度樊口。", "兩山泉石多故人，送子南行一回首。", "蒲圻小縣聊讀書，當使里閭無呻吁。", "結束歸來接臺省，不應厭食武昌魚。"]'),
('1890c4ca-6dcb-4f03-a33b-40d267e85b59','蘇叔黨呂知止許下見訪叔黨有詩戲贈以此奉答','張耒','宋','宋诗','song-poetry','','[]','三年齊安有江山，可當中原故人面。',112,'全唐诗/poet.song.64000.json','["三年齊安有江山，可當中原故人面。", "北來塵埃逢故人，眼前却作江山見。", "君似江山定不疏，能出吾言世亦無。", "蘇郎下筆妙無敵，呂郎與談驚未識。", "鳳雛驥子未宜輕，囊空各有千金璧。", "贈君錦繡與瓊瑶，報我琅玕金錯刀。", "溪毛潢汙未相棄，歲暮與君甘縕袍。"]'),
('12517958-ac31-484d-bab4-c9cb650fbecb','不寐','張耒','宋','宋诗','song-poetry','','[]','荒庭雨多秋草侵，秋蛩相語秋夜深。',64,'全唐诗/poet.song.64000.json','["荒庭雨多秋草侵，秋蛩相語秋夜深。", "草蟲暗飛羽格磔，星河影高天淡白。", "騷人多懷夜不眠，老松微吟風颯然。", "山川浩蕩何日還，晚空漫漫白露寒。"]'),
('9652c2ab-0eaf-4df0-a727-1a0475aba8ed','對蓮花戲寄晁應之','張耒','宋','宋诗','song-poetry','','[]','平池碧玉秋波瑩，綠雲擁扇青瑶柄。',96,'全唐诗/poet.song.64000.json','["平池碧玉秋波瑩，綠雲擁扇青瑶柄。", "水宮仙女鬭新妝，輕步凌波踏明鏡。", "彩橋下有雙鴛戲，曾託鴛鴦問深意。", "半開微斂竟無言，裛露微微洒秋淚。", "晁郎神仙好風格，須遣仙娥伴仙客。", "人間萬事苦參差，吹盡清香不來摘。"]'),
('02fc9b6f-5e8d-459a-b0a1-dc5f4320a9e5','上元旦早起贈同遊者','張耒','宋','宋诗','song-poetry','','[]','夜來人散殘更月，曉陌空存舊車轍。',64,'全唐诗/poet.song.64000.json','["夜來人散殘更月，曉陌空存舊車轍。", "彩燈城市已春風，寒木人家猶臘雪。", "强起相逢酒未醒，殘膏宿火尚熒熒。", "歸來更拂障泥錦，重約黄昏信馬行。"]'),
('ab8edecb-ca5d-41ce-814f-fab45bcc3dee','贈李德載','張耒','宋','宋诗','song-poetry','','[]','男兒當讀五車書，輟業應須蓋棺日。',64,'全唐诗/poet.song.64000.json','["男兒當讀五車書，輟業應須蓋棺日。", "人生事業要强學，譬彼欲耕須逮濕。", "李郎落落奇丈夫，美玉應須作圭璧。", "請將便腹包五車，汲汲講摩如故疾。"]'),
('247c5de1-d514-4e3e-814f-be97932d4161','蒙恩守東魯不意流落之餘聖朝升之藩鎮感而成詩復用李文舉韵','張耒','宋','宋诗','song-poetry','','[]','我詩四十心不動，寵辱悠悠付春風。',128,'全唐诗/poet.song.64000.json','["我詩四十心不動，寵辱悠悠付春風。", "聖朝湔洗諸老成，顧我衰晚名亦共。", "魯人詩書久寂寞，間壁不歸書府送。", "道衰洙泗忽千載，後來爲政誰輕重。", "平時擇守要有補，豈但坐使民供貢。", "吾邦邑子有游夏，未肯無言受愚弄。", "天王有意蘇疲俗，何術與紓鞭箠痛。", "應須問道東家翁，必也斯民使無訟。"]'),
('156456a3-fcec-49b9-8e3b-71b4fba5773d','遊武昌','張耒','宋','宋诗','song-poetry','','[]','一葉橫江凌浩渺，李君見我迎門笑。',256,'全唐诗/poet.song.64000.json','["一葉橫江凌浩渺，李君見我迎門笑。", "鵝黄初熟醅旋壓，書室焚香地新掃。", "淋漓歌笑不知夜，竹榻枕藉眠諸少。", "老人被煖覺獨晚，驚起東南日如燒。", "四明陳子定愛客，生火寒廳邀我到。", "盤殽香潔具俄頃，鱠斫寒魚初出沼。", "仲謀霸氣久寂寞，元子亭基尚危峭。", "荆榛荒梗上石磴，人物清江開野廟。", "暮投明府快一飲，主意殷勤賓屢釂。", "星河破碎歸中夜，明日清淮理歸棹。", "王家園館靜人眼，挂壁於菟疑欲齩。", "殺雞爲黍辦倉卒，看畫烹茶每醉飽。", "還家閉門空寂歷，勝境目前皆了了。", "茲遊可再誰汝嗇，老懶似不能輕矯。", "西山得霜瘦如削，蕭寺崢嶸出粉篠。", "幸於腰髀猶足使，與子凌寒恣遊眺。"]'),
('f1f38935-5fb6-4460-ad1f-ce1822c86f45','春日','張耒','宋','宋诗','song-poetry','','[]','堂堂春日躍出山，郊原草木皆清新。',64,'全唐诗/poet.song.64000.json','["堂堂春日躍出山，郊原草木皆清新。", "千紅萬紫各有態，正自酬酢勞精神。", "短籬誰家小桃李，雖復幽陋亦可人。", "但知痛飲莫辭病，數年幽憂難具陳。"]'),
('648fafe3-634e-4ae2-a808-65f88755d8f8','送孫志康赴高陽','張耒','宋','宋诗','song-poetry','','[]','三觴草草豈足飲，聊具數刻留君歡。',128,'全唐诗/poet.song.64000.json','["三觴草草豈足飲，聊具數刻留君歡。", "年來故友半零落，每念及此傷肺肝。", "淮陽窮栖幸見子，胸中鬰結爲少寬。", "奈何舍我去不顧，薄宦謀食何艱難。", "陳郊窮秋苦雨霽，積雨未受短日乾。", "念君匹馬走坡坂，蒙犯霜雪勤征鞍。", "吾遭坎壈皆自取，之燕何得南其轅。", "雖然男子豈常爾，且復養此凌雲翰。"]'),
('4cc0e977-9482-41e0-8694-4a39db14c0a2','贈李德載二首  其一','張耒','宋','宋诗','song-poetry','','[]','我家外翁天下士，欲以文章付孫子。',64,'全唐诗/poet.song.64000.json','["我家外翁天下士，欲以文章付孫子。", "愛君丱角已食牛，屬書筆下無停字。", "願君飽讀大父書，學到莫憂名不似。", "重教我輩見風流，更以餘波變鄉里。"]'),
('ad813c54-94b8-4a60-87d7-4525f2e8acfd','贈李德載二首  其二','張耒','宋','宋诗','song-poetry','','[]','長翁波濤萬頃陂，少翁巉秀千尋麓。',64,'全唐诗/poet.song.64000.json','["長翁波濤萬頃陂，少翁巉秀千尋麓。", "黄郎蕭蕭日下鶴，陳子峭峭霜中竹。", "秦文蒨藻舒桃李，晁論崢嶸走金玉。", "六公文字滿人間，君欲高飛附鴻鵠。"]'),
('82b95f81-9a95-456b-8130-69271be033b7','秋曉','張耒','宋','宋诗','song-poetry','','[]','老人不睡秋夜長，五更鼓角鳴東堂。',64,'全唐诗/poet.song.64000.json','["老人不睡秋夜長，五更鼓角鳴東堂。", "悲蛩床下欲無語，黄葉瓦清新有霜。", "雁聲相應江南北，斗杓欲下天中央。", "老人山尊有美酒，岸巾先酌一杯嘗。"]'),
('1ec1ea61-cf62-4bd5-9e9d-e6886023bb86','東方','張耒','宋','宋诗','song-poetry','','[]','東方未明更五鼓，星河寥寥寒雁度。',64,'全唐诗/poet.song.64000.json','["東方未明更五鼓，星河寥寥寒雁度。", "鐺鐺鳴鐸誰家車，陌上驅牛輾霜去。", "北風吹面足踏冰，村南早飯天未明。", "年年輸稅洛陽城，慎莫後期官有刑。"]'),
('cf0456bf-37d3-4951-9741-b213f9d50d1b','寒蛩','張耒','宋','宋诗','song-poetry','','[]','寒蛩振翼聲騷騷，夜深月影在蓬蒿。',64,'全唐诗/poet.song.64000.json','["寒蛩振翼聲騷騷，夜深月影在蓬蒿。", "老人雖眠睫不交，愁窗人寂燈無膏。", "荒城鳴金睥睨高，北斗下挹江南濤。", "悲笳三奏老雞號，晨光出山開泬寥。"]'),
('9839f9d5-98b3-4c12-9755-9ff7647e809d','秋雨小酌贈賈七','張耒','宋','宋诗','song-poetry','','[]','出門秋雨泥漫漫，嗟我后土何時乾。',160,'全唐诗/poet.song.64000.json','["出門秋雨泥漫漫，嗟我后土何時乾。", "官曹事休歸舍卧，破屋淅淅西風寒。", "弱妻傾榼勸我起，稚子笑語爭杯盤。", "我生樂事但如此，爲爾一醉愁腸寬。", "仕途翩翩鬭巧捷，華裾鮮縠相追攀。", "老來百事覺羞恥，懶伴兒女塗鉛丹。", "賈郎豪華獨異我，粉腮玉指雙鴉鬟。", "清眸侑酒醉百盞，肯咀貧甕寒虀酸。", "堂前菊花日以好，落砌槭槭梧桐殘。", "當謀痛飲待九日，豪氣一壓龍山桓。"]'),
('d1e1860b-a623-49ff-9a41-84e107f06224','山海','張耒','宋','宋诗','song-poetry','','[]','愚公移山寧不智，精衛填海未必癡。',96,'全唐诗/poet.song.64000.json','["愚公移山寧不智，精衛填海未必癡。", "深谷爲陵岸爲谷，海水亦有揚塵時。", "杞人憂天固可笑，而不憂者安從知。", "聖言世界有成壞，况此馬體之毫釐。", "老人行世頭已白，見盡世間惟歎息。", "俯眉袖手飽飯行，那更從人問通塞。"]'),
('ed6fd1e4-ee1d-40b8-87ec-0eb7a8c5143c','將至官坡登一土岡望復州作','張耒','宋','宋诗','song-poetry','','[]','茫茫夢澤連禾黍，斷壠橫岡散平楚。',64,'全唐诗/poet.song.64000.json','["茫茫夢澤連禾黍，斷壠橫岡散平楚。", "登高試望竟陵城，孤烟落日知何處。", "舊遊如夢去莫挽，客愁冉冉還如故。", "他年若問鴻軒人，堂下薔薇應解語。"]'),
('5690cd1e-90cd-461a-81ca-998ea8200ed2','送子野大夫罷兖倅歸汶上','張耒','宋','宋诗','song-poetry','','[]','愛君記覽老不衰，日日早起先鳴雞。',80,'全唐诗/poet.song.64000.json','["愛君記覽老不衰，日日早起先鳴雞。", "白頭未蒙國士知，佐郡秩滿寂寞歸。", "我辭魑魅得一麾，逢君話舊相嗟咨。", "幾年東壁無光輝，不知武庫實在茲。", "上書薦君非我職，臨分一醉當無辭。"]'),
('72215770-3508-40c8-851f-8d28a5d9ca79','晨起苦寒','張耒','宋','宋诗','song-poetry','','[]','夜霜漫屋風折竹，我乃與君在空谷。',64,'全唐诗/poet.song.64000.json','["夜霜漫屋風折竹，我乃與君在空谷。", "平生一衲度嚴寒，塊守深爐體生粟。", "大潘借馬貸監河，小潘無事仰屋歌。", "妻兒號寒劇雁鵝，詩書滿腹將何如。"]'),
('7d3b57f6-4242-42a7-adf0-dcffad6cd8dc','舟次安州孝感縣偶感寒疾卧病舟中復大風不可解舟晚方離去','張耒','宋','宋诗','song-poetry','','[]','船頭風聲鳴萬鼓，扁舟繫纜沙邊樹。',64,'全唐诗/poet.song.64000.json','["船頭風聲鳴萬鼓，扁舟繫纜沙邊樹。", "船中病客晝閉篷，睡起空江日亭午。", "雞犬蕭條數家縣，市聲已變淮南語。", "長年三老喚不醒，一葉波間去如舞。"]'),
('526e36d7-7ebc-4f37-952a-606d1965ba7e','和大雪折木','張耒','宋','宋诗','song-poetry','','[]','季秋木葉未全落，西風卷雲飛雪作。',224,'全唐诗/poet.song.64000.json','["季秋木葉未全落，西風卷雲飛雪作。", "奔騰傾倒來不停，頃刻山川失寥廓。", "白頭老翁仰天歎，一生未見可吁愕。", "但悲無食饑凍死，何暇更議陰陽錯。", "樵車不來椽數盡，仰徹屋茅烹莧藿。", "坐愁窮臘安可度，律管未改初冬朔。", "我居堂前有大榆，百年老幹龍鱗剝。", "夜聲疑是神物伐，參天大枝脆如斮。", "披簷擲瓦事未測，起坐明燈徹其幄。", "命乖久遭窮鬼笑，當慮壓覆崩厥角。", "鹿山長官當此時，高樓大飲縱歡謔。", "兩邦相鄰無百里，誰謂同時異憂樂。", "尚能怨嗟念窮苦，喜君於物心不薄。", "百里饑寒仰長官，勉充此心救民瘼。"]'),
('68683fcd-b6ad-4c0e-a5ea-9c42f6645db7','冬懷二首  其一','張耒','宋','宋诗','song-poetry','','[]','窗南積雪高三尺，二更月出連窗白。',64,'全唐诗/poet.song.64000.json','["窗南積雪高三尺，二更月出連窗白。", "爐裏石瓶鳴細泉，燈前病叟搘書策。", "家人歲晚貯梨栗，倒榼寒醪有殘滴。", "三杯取醉萬事平，兼味重裘定何益。"]'),
('f30e6c1c-6e4f-4c16-9c51-cb20e27d8534','冬懷二首  其二','張耒','宋','宋诗','song-poetry','','[]','山陽賢者有徐子，親沒十年哀不已。',80,'全唐诗/poet.song.64000.json','["山陽賢者有徐子，親沒十年哀不已。", "精誠感天天爲悲，甘露常沾墳樹枝。", "徐子行年過五十，衣不披體常苦饑。", "天公盍使少富足，甘露萬斛真何爲。", "虛恩浮惠天猶爾，安得世人無巧僞。"]'),
('57458f14-11c7-45df-a4e7-d56366d78914','和應之簷雀','張耒','宋','宋诗','song-poetry','','[]','羣兒探雀雛，雀母悲且鳴。',56,'全唐诗/poet.song.64000.json','["羣兒探雀雛，雀母悲且鳴。", "萬物雖異性，愛子均一情。", "母心於子誰不憐，爾胡棄子當道邊。", "諒非人情不如鳥，使之至此必有原。"]'),
('08e17e63-52a5-46b1-8360-f2cc271ea708','自廬山回過富池隔江遙禱甘公祠求便風至黄瀝酒而風轉日行二百里明日風猶未已又風勢徐緩不奔駛可畏甘公蓋吳將甘寧云','張耒','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江邊古祠吳甘公，往來祭禱嚴且恭。',128,'全唐诗/poet.song.64000.json','["江邊古祠吳甘公，往來祭禱嚴且恭。", "我離匡山已經宿，舟挽不進篙工慵。", "沙邊朝服遙致禱，澆酒未竟天回風。", "一帆百里至還作，不徐不疾來雍容。", "我生久已甘困滯，神亦何事特哀窮。", "但疑神理與人異，意誠詞直無不通。", "林皇夜泊若平地，疑有鬼物驅蛟龍。", "天明旗脚向北指，舟子笑語開船蓬。"]'),
('fb6d35ca-4fde-4fe5-8284-87fda83a7b6f','風駛浪湧仲達喜其快因作一篇','張耒','宋','宋诗','song-poetry','','[]','人生不欲甚快意，遲速到家還一致。',64,'全唐诗/poet.song.64000.json','["人生不欲甚快意，遲速到家還一致。", "向來白浪涌如山，舟中呀呷幾喪氣。", "我師禪祖學不動，頗覺蒼茫忘定慧。", "憑河不悔聖所非，君勿爲笑而爲戒。"]'),
('12ae1c7b-b990-4770-a578-c417e5c8a9ec','美哉','張耒','宋','宋诗','song-poetry','','[]','美哉洋洋清潁尾，西通天邑無千里。',128,'全唐诗/poet.song.64000.json','["美哉洋洋清潁尾，西通天邑無千里。", "舸𦩆大艑起危檣，淮潁耕田歲收米。", "茫茫陂澤带平原，古時溝澗還相連。", "昔人屯田戍兵處，今人阡陌連丘墓。", "今年雨足種麥多，北風吹葉鳴空柯。", "高城回望鬰嵯峨，豐年閭井聞笙歌。", "河邊古堤多老柳，去馬來船一回首。", "百年去住不由人，歲暮天寒聊飲酒。"]'),
('cbef15e2-bf4d-4456-bb91-d055663a429b','西風','張耒','宋','宋诗','song-poetry','','[]','西風吹屋絡緯鳴，星河錯落已三更。',64,'全唐诗/poet.song.64000.json','["西風吹屋絡緯鳴，星河錯落已三更。", "軍城傳警萬家靜，山堂含風遙夜清。", "雲收纖月映山盡，天轉北斗向江傾。", "舍南高林栖鶴鶂，危枝高巢雛夜驚。"]'),
('11387e0f-52a6-496f-964c-00a1f3e18405','觀梅','張耒','宋','宋诗','song-poetry','','[]','北風號夜天雨霜，屋東梅花晨洗妝。',128,'全唐诗/poet.song.64000.json','["北風號夜天雨霜，屋東梅花晨洗妝。", "老人旦起萬境寂，一笑向我吹微香。", "風月精神珠玉骨，冰雪簪珥瓊瑶璫。", "天姝星艷下人世，靈真高秀無比方。", "老人年年被香惱，學道無力時清狂。", "吟詩覓句苦無味，剪枝插頭羞鬢蒼。", "眼窺手採心愛惜，倘可取餌充朝糧。", "不如痛飲卧其下，醉魂爲蝶棲其房。"]'),
('92a5ae01-34e7-4444-975e-40a9d1690b8f','魯直惠洮河綠石研冰壺次韵','張耒','宋','宋诗','song-poetry','','[]','洮河之石利劍矛，磨刀日解十二牛。',176,'全唐诗/poet.song.64000.json','["洮河之石利劍矛，磨刀日解十二牛。", "千年虜地困沙礫，一日見寶來中州。", "黄子文章妙天下，獨有八馬森幢旒。", "平生筆墨萬金值，奇煤利翰盈篋收。", "誰持此研參案几，風瀾近手寒生秋。", "抱持投我棄不惜，副以清詩帛加璧。", "明窗試墨吐秀潤，端溪歙州無此色。", "野人齋房無玩好，慚愧衣冠陳裸國。", "晁侯碧海爲文詞，盤薄萬頃澄清漪。", "新篇來如徹札箭，勁筆更似劃沙錐。", "知君自足報蒼璧，愧我空賦瓊瑰詩。"]'),
('6422360b-6a05-4983-aa74-d24a7a67d022','福昌秋日效張文昌二首  其一','張耒','宋','宋诗','song-poetry','','[]','秋野無人秋日白，禾黍登場風索索。',64,'全唐诗/poet.song.64000.json','["秋野無人秋日白，禾黍登場風索索。", "豆田黄時霜已多，桑蟲食葉留空柯。", "小蝶翩翩晚花紫，野鶉啄粟驚人起。", "洛陽西原君莫行，秋光處處繫人情。"]'),
('5e2717af-79df-47de-9c0b-7214b6fa7329','福昌秋日效張文昌二首  其二','張耒','宋','宋诗','song-poetry','','[]','黄葉蕭蕭秋水清，田中日午村雞鳴。',64,'全唐诗/poet.song.64000.json','["黄葉蕭蕭秋水清，田中日午村雞鳴。", "場邊九月禾黍熟，空原雉飛飽新穀。", "棗籬蟲鳴村路曲，道邊古墳生野菊。", "人稀田闊草茫茫，洛陽秋聲能斷腸。"]'),
('d8b7acb1-9258-4205-849f-05a110bc5035','贈張嘉甫','張耒','宋','宋诗','song-poetry','','[]','浮舟大江里三千，歸掃先隴清淮壖。',224,'全唐诗/poet.song.64000.json','["浮舟大江里三千，歸掃先隴清淮壖。", "杜門古寺厭岑寂，夢寐清潁如家山。", "汝陰昔謬稱刺史，自愧何術甦恫瘝。", "平生爲吏甘賤拙，敢作蟊賊傷民田。", "未憂懷磚擊之去，乃欲築室買一廛。", "簞瓢三畝易辦耳，寄聲父老不汝干。", "長淮清冬龍蜃蟄，放舟出郭天宇寬。", "浮梁橫前嫋可纜，金塔却立儼莫攀。", "髯張幼好此奇服，白璧刻佩鳴玦環。", "抱持微學不忍棄，清明竹林遭削刪。", "三年江湖友魑魅，一日寶府觀璵璠。", "漸消鄙吝心自喜，追計存沒涕亦潸。", "尋山把酒豈易得，客路霰雪衣裘單。", "塵埃可洗憂可豁，待君一酌玻璃泉。"]'),
('3330ce31-8858-4694-b244-9f5b5b09cbe0','題江州琵琶亭','張耒','宋','宋诗','song-poetry','','[]','危亭古榜名琵琶，尚有楓葉連荻花。',96,'全唐诗/poet.song.64000.json','["危亭古榜名琵琶，尚有楓葉連荻花。", "嗚呼司馬則已矣，行人往來皆歎嗟。", "司馬風流映千古，當日琵琶傳樂府。", "江山寂寞三百年，潯陽風月知誰主。", "我今單舸犯江潭，往來略已遍東南。", "可憐千里傷心目，不待琵琶淚滿衫。"]'),
('e2115644-81bb-4d39-9766-55b28aa77db6','予官竟陵時李文舉嘗以事至郡同遊西禪剎陸子泉烹茶酌酒甚歡也今歲予移官齊安文舉自武昌渡江過我與之飲酒念西禪舊事相與慨然','張耒','宋','宋诗','song-poetry','','[]','此生放蕩隨羣動，一覺竟陵瀟洒夢。',128,'全唐诗/poet.song.64000.json','["此生放蕩隨羣動，一覺竟陵瀟洒夢。", "江山喚我此中來，却愁風月無人共。", "李侯年少能思我，朅來兩槳歸潮送。", "不辭薄酒與君飲，坐覺西山夕烟重。", "西禪舊遊已陳迹，壁間陸子塵生供。", "石欄古井誰知味，只有松風自成弄。", "愛君爲吏無俗韵，快誦離騷飲仍痛。", "不嫌寂寞過我來，古縣年豐少爭訟。"]'),
('e6e9108f-c65a-4c11-a4c6-b74403c21296','乞錢穆公給事丈新賜龍團','張耒','宋','宋诗','song-poetry','','[]','閩侯貢璧琢蒼玉，中有掉尾寒潭龍。',64,'全唐诗/poet.song.64000.json','["閩侯貢璧琢蒼玉，中有掉尾寒潭龍。", "驚山作春山不覺，走馬獻入明光宮。", "瑶池侍臣最先賜，惠山乳泉新破封。", "可得作詩酬孟簡，不須載酒過揚雄。"]'),
('3d98bc03-19c4-4ec2-81bb-61e6a72daca8','將至都下','張耒','宋','宋诗','song-poetry','','[]','竟陵南望稻新熟，夢澤悠悠傷遠目。',96,'全唐诗/poet.song.64000.json','["竟陵南望稻新熟，夢澤悠悠傷遠目。", "春風嶺上望齊安，太昊城邊攬秋菊。", "那知歲暮東州客，大山蒼寒曉霜白。", "雲收霧捲日月明，却上天衢瞻玉色。", "敝裘疲馬古道長，九旬刺史歸空囊。", "歸去故人應笑我，滿衫清淚說潯陽。"]'),
('6c5e212e-969f-4b16-83e6-6f9ecc724cd4','題韓幹馬圖','張耒','宋','宋诗','song-poetry','','[]','頭如翔鸞月頰光，背如安輿鳬臆方。',98,'全唐诗/poet.song.64000.json','["頭如翔鸞月頰光，背如安輿鳬臆方。", "心知不載田舍郎，猶带開元天子紅袍香。", "韓幹寫時國無事，綠樹陰低春晝長。", "兩髯執轡儼在傍，如瞻馳道黄屋張。", "北風揚塵燕賊狂，廄中萬馬歸范陽。", "天子乘騾蜀山路，滿川苜蓿爲誰芳。"]'),
('41cc0edd-d313-4abe-8445-95e1a34ed6d2','罔沙阻風','張耒','宋','宋诗','song-poetry','','[]','大江春風浪如屋，客舟迎風罔沙宿。',96,'全唐诗/poet.song.64000.json','["大江春風浪如屋，客舟迎風罔沙宿。", "連檣接舵古岸傍，岸頭無人春草綠。", "船頭日出炊烟起，買魚携菜來就市。", "漁人水惡不出門，蕭條野市無雞豚。", "堤邊紙錢灰若雨，沽酒賽神巫降語。", "南人艇子不避風，橫江五兩翩翩去。"]'),
('4357761a-0254-45c5-b7ff-c8a89aa01241','寄曼叔求酒','張耒','宋','宋诗','song-poetry','','[]','青衫畿丞頑不羞，三十持板拜督郵。',192,'全唐诗/poet.song.64000.json','["青衫畿丞頑不羞，三十持板拜督郵。", "歸來無物與消愁，典衣沽酒寒無裘。", "囊空酒貴不可得，縮手愁坐凝雙眸。", "秋風破屋冷颼颼，夜長不眠吟掉頭。", "豈無鄰家酒可偷，簡書縛汝如窮囚。", "淮陽冬醪滑勝油，唇焦不飲已經秋。", "汲公直聲聞九州，小子昔也從公遊。", "憫憐憔悴賜顔色，時丐餘酌濡其喉。", "軍厨嵯峨糟作丘，萬甕沸響玉蟻浮。", "轍魚所願斗水遊，不敢多取煩陽侯。", "玉瓶未至涎已流，想見瀲灧浮金甌。", "歌成緘書還自咻，一醉猶須越境謀。"]'),
('71a86eb2-d21f-4920-89e3-c97b6fcc03ad','題吳熙老風雲圖','張耒','宋','宋诗','song-poetry','','[]','雨脚橫空萬牛弩，烈風吹山山欲仆。',96,'全唐诗/poet.song.64000.json','["雨脚橫空萬牛弩，烈風吹山山欲仆。", "草披木拔何足道，大江翻瀾失洲渚。", "路旁失轡者誰子，道阻且長泥沒屨。", "鞭馿挽車亦何急，目眩心摇行不顧。", "我生飄蓬慣羈旅，顧爾艱難逢亦屢。", "衲被蒙頭不下堂，且與身謀安穩處。"]'),
('d03d7e8b-9e0d-4c6d-80f1-08b44f051174','京師阻雨二首  其一','張耒','宋','宋诗','song-poetry','','[]','深泥漫漫污后土，長安閉門三日雨。',64,'全唐诗/poet.song.64000.json','["深泥漫漫污后土，長安閉門三日雨。", "頑雲不動風伯愁，飛電更相雷師怒。", "陽烏力弱不自持，天漏已寬無石補。", "麥蛾禾耳不足憂，當念爲魚救無禹。"]'),
('5f8c4b5e-5296-476e-9f56-7f8943180406','京師阻雨二首  其二','張耒','宋','宋诗','song-poetry','','[]','大雨三日泥三尺，駿馬高車行不得。',64,'全唐诗/poet.song.64000.json','["大雨三日泥三尺，駿馬高車行不得。", "我有蹇馿安敢騎，閉戶高眠朝至夕。", "誰家高堂半夜秋，軟綺輕紈換絺綌。", "朱門樂事無時無，爾自賤貧空太息。"]'),
('53f939be-93be-4a54-88a3-97b7c99636bb','應龍','張耒','宋','宋诗','song-poetry','','[]','應龍未遇風雲起，仰活泥沙數尺水。',64,'全唐诗/poet.song.64000.json','["應龍未遇風雲起，仰活泥沙數尺水。", "彼能坐致千里澤，可憐一掬何難致。", "時哉未遇可奈何，一掬雖微安敢易。", "誰能寄語潭中魚，相聚須臾莫相忌。"]'),
('3834771e-2d3d-42f3-8392-d7a7cc996fbf','田家三首  其一','張耒','宋','宋诗','song-poetry','','[]','野塘積水綠可染，舍南新柳齊如剪。',64,'全唐诗/poet.song.64000.json','["野塘積水綠可染，舍南新柳齊如剪。", "去冬雪好麥穗長，今日雨晴初擇繭。", "東家饋黍西舍迎，連臂踏歌村市晚。", "婦騎夫荷兒扶翁，月出橋南歸路遠。"]'),
('2d1875a9-8349-467f-9e65-81892c37863c','田家三首  其二','張耒','宋','宋诗','song-poetry','','[]','社南村酒白如餳，鄰翁宰牛鄰媼烹。',64,'全唐诗/poet.song.64000.json','["社南村酒白如餳，鄰翁宰牛鄰媼烹。", "插花野婦抱兒至，曳杖老翁扶背行。", "淋漓醉飽不知夜，裸股掣肘時歡爭。", "去年百金易斗粟，豐歲一飲君無輕。"]'),
('3d6c2748-e891-4e1f-83c5-72e991a1dec9','田家三首  其三','張耒','宋','宋诗','song-poetry','','[]','新見鵲銜庭樹枝，黄口出巢今已飛。',64,'全唐诗/poet.song.64000.json','["新見鵲銜庭樹枝，黄口出巢今已飛。", "栗留啄椹桑葉老，科斗出畦新稻齊。", "田家苦作候時節，汲汲未免寒與饑。", "去來暴取獨何者，請視七月豳人詩。"]'),
('4d5f46dd-76c4-4008-beaa-35c5727d112c','海州道中二首  其一','張耒','宋','宋诗','song-poetry','','[]','孤舟夜行秋水廣，秋風滿帆不摇槳。',64,'全唐诗/poet.song.64000.json','["孤舟夜行秋水廣，秋風滿帆不摇槳。", "荒田寂寂無人聲，水邊跳魚翻水響。", "河邊守罾茅作屋，罾頭月明人夜宿。", "船中客覺天未明，誰家鞭牛登隴聲。"]'),
('ceafcff0-0cdb-46f6-b5d1-a50094a00fa4','海州道中二首  其二','張耒','宋','宋诗','song-poetry','','[]','秋野蒼蒼秋日黄，黄蒿滿田蒼耳長。',64,'全唐诗/poet.song.64000.json','["秋野蒼蒼秋日黄，黄蒿滿田蒼耳長。", "草蟲咿咿鳴復咽，一秋雨多水滿轍。", "渡頭鳴舂村逕斜，悠悠小蝶飛豆花。", "逃屋無人草滿家，纍纍秋蔓懸寒瓜。"]'),
('9e44fb48-2a90-41ea-a9ff-28594590f53e','女几祠下','張耒','宋','宋诗','song-poetry','','[]','山邊白雲閒不掃，廟前土馬荒春草。',64,'全唐诗/poet.song.64000.json','["山邊白雲閒不掃，廟前土馬荒春草。", "山下松花龍甲光，東風古柏吹煖香。", "朝霞爲裳水爲佩，守廟千年老龍在。", "清風掃堂神暮還，山頭月出溪潺潺。"]'),
('b64cc0bc-8e54-4c45-b91b-b273b9283d7b','女几祠下','張耒','宋','宋诗','song-poetry','','[]','山邊白雲閒不掃，山下松花龍甲老。',64,'全唐诗/poet.song.64000.json','["山邊白雲閒不掃，山下松花龍甲老。", "東風古栢吹暖香，廟前土馬荒春草。", "朝霞爲裳水爲珮，守廟千年老龍在。", "淸風掃堂神暮還，山頭月出溪潺潺。"]'),
('56badd01-dffd-4b7e-a180-9b05844a1ba7','馬周','張耒','宋','宋诗','song-poetry','','[]','馬周未遇虯鬚公，布衣落魄來新豐。',64,'全唐诗/poet.song.64000.json','["馬周未遇虯鬚公，布衣落魄來新豐。", "一樽獨酌豈無意，俗子不解知英雄。", "賢豪相逢自相得，一語君王見胸臆。", "當時豈不爲人言，聾耳安能爲君側。"]'),
('d277a85a-11e9-4cc3-9332-a580b98f5777','南山','張耒','宋','宋诗','song-poetry','','[]','南山鳳凰雙翅垂，口不妄食腹苦饑。',64,'全唐诗/poet.song.64000.json','["南山鳳凰雙翅垂，口不妄食腹苦饑。", "山前老鳶飽腐鼠，憑恃風日羣遊嬉。", "俯身視鳳有驕色，鳳不汝較空嗟咨。", "九韶一奏爲君舉，坐看百鳥相隨飛。"]'),
('2c3841e2-621e-4532-8599-e6fc54fefbbf','歲暮歎三首  其一','張耒','宋','宋诗','song-poetry','','[]','秋日苦短秋雲多，北風蕭蕭洛水波。',64,'全唐诗/poet.song.64000.json','["秋日苦短秋雲多，北風蕭蕭洛水波。", "□□□□□□□，長林撐空葉餘柯。", "鳴雁高飛去不息，晚花悠悠能幾何。", "洛陽經年客未去，歲暮搔首空悲歌。"]'),
('332aa0e2-61b2-4818-bfcf-7fb09b009b89','歲暮歎三首  其二','張耒','宋','宋诗','song-poetry','','[]','寥寥野空禾黍荒，北風日夜鳴空桑。',64,'全唐诗/poet.song.64000.json','["寥寥野空禾黍荒，北風日夜鳴空桑。", "南山碧天青不極，渺渺洛水東流長。", "山空水寒行客少，鴻雁飛急天初霜。", "蕭蕭窮谷歲已晚，嗟我再補冬衣裳。"]'),
('9e113aae-7bc0-4f26-abff-0475d715d921','歲暮歎三首  其三','張耒','宋','宋诗','song-poetry','','[]','南山蒼蒼秋季月，北風如刀青石裂。',64,'全唐诗/poet.song.64000.json','["南山蒼蒼秋季月，北風如刀青石裂。", "山陰半夜寒欲冰，晚望高峰看新雪。", "白衫少年臂鷹去，暮歸飲酒烹狐兔。", "强弓一斛尚可彎，更欲射獵窮吾年。"]'),
('c0a151ca-0ec0-4b9f-9c1b-1eeef83dcf95','一畝','張耒','宋','宋诗','song-poetry','','[]','一畝秋蔬半成實，竈突無烟已三日。',64,'全唐诗/poet.song.64000.json','["一畝秋蔬半成實，竈突無烟已三日。", "良人傭車斃車下，老婦抱子啼空室。", "秋風九月天已寒，饑腸不飽衣苦單。", "我身爲吏救無術，坐視啼泣空汍瀾。"]'),
('0c3e9f91-e068-42e3-ba84-64910f4cf439','洛水','張耒','宋','宋诗','song-poetry','','[]','洛水秋深碧如黛，亂石縱橫瀉鳴瀨。',64,'全唐诗/poet.song.64000.json','["洛水秋深碧如黛，亂石縱橫瀉鳴瀨。", "清明見底不留塵，日射澄沙動璣貝。", "南山秋風已蕭瑟，倒影上下迷空翠。", "何當載酒縱扁舟，一尺鯉魚寒可鱠。"]'),
('9db9dcd7-fc4e-4e64-9b67-878b5a4d3213','秋風三首  其一','張耒','宋','宋诗','song-poetry','','[]','秋風蕭蕭洛川渡，水碧沙寒飛白鷺。',64,'全唐诗/poet.song.64000.json','["秋風蕭蕭洛川渡，水碧沙寒飛白鷺。", "波頭伐木欲成梁，落日樵蘇下山去。", "山頭九月雪一尺，山民燃薪當襦袴。", "石田收薄婦子饑，歲晚苦寒安可度。"]'),
('305e6d3e-13e2-4297-824a-7ad28d16f186','秋風三首  其二','張耒','宋','宋诗','song-poetry','','[]','秋風蕭蕭吹野桑，田家黍稷初登場。',64,'全唐诗/poet.song.64000.json','["秋風蕭蕭吹野桑，田家黍稷初登場。", "雉肥兔飽鷹隼健，水落沙冷魚龍藏。", "長淮烟波渺千里，悵望搔首山川長。", "二年薇蕨苦不飽，長安裘馬多輝光。"]'),
('86173c1b-731c-4d46-b089-742cba82223d','秋風三首  其三','張耒','宋','宋诗','song-poetry','','[]','昏鴉歸栖暮天迥，新月娟娟水中影。',64,'全唐诗/poet.song.64000.json','["昏鴉歸栖暮天迥，新月娟娟水中影。", "秋聲索索起桑麻，古道人歸烟火靜。", "公庭吏稀霜樹老，藥檻雨多幽菊盛。", "山家生事飽諳知，野果村醪遣朝暝。"]'),
('f00dd0d0-0cb2-4031-a657-84520ede9e68','感春三首  其一','張耒','宋','宋诗','song-poetry','','[]','我昨西來到昌谷，主人致酒留我宿。',64,'全唐诗/poet.song.64000.json','["我昨西來到昌谷，主人致酒留我宿。", "坐中少年美如玉，高歌清歡春夜促。", "還家病酒對殘春，東風落花吹滿屋。", "出無與語歸閉門，安得萬里馳吾足。"]'),
('7bd08ed4-fa48-49f4-a16d-d9c189dc3967','感春三首  其二','張耒','宋','宋诗','song-poetry','','[]','我昔東行花始開，我自東歸花半摧。',64,'全唐诗/poet.song.64000.json','["我昔東行花始開，我自東歸花半摧。", "萬紅辭林捲風去，坐見錦繡蒙蒼苔。", "南山朝雲鳩逐婦，日暮微雨蕭蕭來。", "一春晴明苦難得，掩蔽風日知誰哉。"]'),
('ad1b3a19-5401-4159-ba43-4e194868f237','感春三首  其三','張耒','宋','宋诗','song-poetry','','[]','悠悠朝興暮還息，官閒事少門無客。',64,'全唐诗/poet.song.64000.json','["悠悠朝興暮還息，官閒事少門無客。", "空山多陰春雨足，饑馬蕭蕭空伏櫪。", "文章工巧謀愈疏，顔鬢衰遲進無策。", "繫身五斗爾自爲，何用中宵空嘆息。"]'),
('d75d4c2b-dbba-4ba2-bd03-bdfefb3a3cbe','又三首  其一','張耒','宋','宋诗','song-poetry','','[]','亦知春歸不可留，有情未忘寧免愁。',64,'全唐诗/poet.song.64000.json','["亦知春歸不可留，有情未忘寧免愁。", "平田茫茫芳草合，清洛不斷波悠悠。", "傷心千里寄雙淚，催老此身初白頭。", "問舍求田未成計，青衫手板對人羞。"]'),
('1e8bca58-8f7f-400a-b6cb-d827ab4ad3dc','又三首  其二','張耒','宋','宋诗','song-poetry','','[]','山民爲生最易足，一身生計資山木。',64,'全唐诗/poet.song.64000.json','["山民爲生最易足，一身生計資山木。", "負薪入市得百錢，歸守妻兒烹斗粟。", "山林未盡終不憂，衣食自足他無欲。", "人生誰使愛功名，萬慮千思撓心腹。"]'),
('be1b991b-c393-43c2-a903-923e28da530b','又三首  其三','張耒','宋','宋诗','song-poetry','','[]','騎馬出門暮復歸，出無所詣歸對誰。',64,'全唐诗/poet.song.64000.json','["騎馬出門暮復歸，出無所詣歸對誰。", "妻兒具酒勸我飲，兒稚笑語傍嬉嬉。", "人生如此亦可樂，安用軒冕生光輝。", "九原可作欲誰與，鹿門龐叟真吾師。"]'),
('8397313e-2f03-4f0a-bed5-115bbf857616','去年','張耒','宋','宋诗','song-poetry','','[]','去年四月多風雨，麥秀不實農夫苦。',64,'全唐诗/poet.song.64000.json','["去年四月多風雨，麥秀不實農夫苦。", "今年麥好風雨調，萬口嗷嗷饑待哺。", "何事今晨還衣裌，朝日無光寒慘切。", "天工與物無怨尤，安用日與人爲仇。"]'),
('329bf09c-31a1-4a58-8d10-60c109512ee7','謝李剛中','張耒','宋','宋诗','song-poetry','','[]','齊郎好詩風調清，語中有骨自老成。',64,'全唐诗/poet.song.64000.json','["齊郎好詩風調清，語中有骨自老成。", "愈鑱愈出當有名，朅來宣城蓋爲傾。", "文章不如金滿籝，我昔曾力今乃懲。", "少年平步取公卿，安用學此誤平生。"]'),
('c94f6331-86b7-4038-ba8f-7cc7ec3e6ccc','局中負暄讀書三首  其一','張耒','宋','宋诗','song-poetry','','[]','輝輝短景留寒光，重裘不暖貪負陽。',80,'全唐诗/poet.song.64000.json','["輝輝短景留寒光，重裘不暖貪負陽。", "老人背溫一體康，我欲持之獻天王。", "天王九重居明光，玉几翠被女侍傍。", "人不我知謂我狂，此心耿耿不敢忘。", "歲云暮矣天雨霜，且復持此飲一觴。"]'),
('928e62d1-5c93-40fc-a96d-b15c664f12fa','局中負暄讀書三首  其二','張耒','宋','宋诗','song-poetry','','[]','輝輝短景留寒光，瓦簷霜濕梧桐黄。',64,'全唐诗/poet.song.64000.json','["輝輝短景留寒光，瓦簷霜濕梧桐黄。", "老蛩不知秋已去，白晝嘖嘖空啼牆。", "歲云暮矣羈旅傷，塊獨守此天一方。", "床頭書史談虞唐，我言匪耄聽者狂。"]'),
('4d9a18f8-e621-4f5b-9950-f34b29971ba4','局中負暄讀書三首  其三','張耒','宋','宋诗','song-poetry','','[]','輝輝短景不能春，照我貧屋亦復仁。',67,'全唐诗/poet.song.64000.json','["輝輝短景不能春，照我貧屋亦復仁。", "虞淵道遠寒雲屯，羲和愁思隕厥輪。", "君不見志士憔悴甘賤貧，塊處屋漏含悲辛。", "重堂溫室顛醉昏，悠悠蒼天彼何人。"]'),
('a6aa00fd-0097-49d8-a65f-3122b9c43d79','歲後三日','張耒','宋','宋诗','song-poetry','','[]','春風攪空如怒濤，春日寂寂在蓬蒿。',64,'全唐诗/poet.song.64000.json','["春風攪空如怒濤，春日寂寂在蓬蒿。", "衡門鳥雀舞不下，西園桃李氣已嬌。", "天邊碧雲空漠漠，門外荒草還迢迢。", "人生幾何春復夏，可但白首隨漁樵。"]'),
('143430ed-28b8-4159-b5e1-20ebfd8acc9a','和陽念三自武昌至京師','張耒','宋','宋诗','song-poetry','','[]','三年別我客荆州，一日長安從我遊。',64,'全唐诗/poet.song.64000.json','["三年別我客荆州，一日長安從我遊。", "愛君詩有春草句，使我神遊黄鶴樓。", "江山望爾欲穿眼，見我驚嗟秋鬢短。", "扁舟可辦吾欲東，年年五湖魂夢中。"]'),
('09868d2e-7629-49f2-a74e-89ada2455c1c','二十三日晨欲飲求酒無所得戲作','張耒','宋','宋诗','song-poetry','','[]','張君所欲一壺酒，百計經營卒無有。',64,'全唐诗/poet.song.64000.json','["張君所欲一壺酒，百計經營卒無有。", "夜來客至瓶已空，晨起欲飲還戒口。", "努力忍窮甘寂淡，人間萬事如反手。", "百壺一醉有底難，造物戲謔君須受。"]'),
('b42c66ec-feb5-41d1-afd4-a61075105a16','贈翟公巽','張耒','宋','宋诗','song-poetry','','[]','我昔出守來丹陽，江流五月如探湯。',288,'全唐诗/poet.song.64000.json','["我昔出守來丹陽，江流五月如探湯。", "使君之居在山腹，繞舍樹石何青蒼。", "千年藥根蟠井底，靈液浸灌通寒漿。", "人言枸杞精變狗，夜吠往往聞空廊。", "金山蕩潏浪花裏，一舸遙去隨魚郎。", "最奇巖齋人跡少，乳水時滴白石床。", "翠黿坡陀負日色，白蹢掀舞占風祥。", "我泊金山凡十日，窮探力取無遺忘。", "南風吹我渡江去，已厭淮南塵土黄。", "二十年間多少事，身如疲馬起復僵。", "淮南窮栖衆人後，朝食不充藜莧腸。", "公來衰顔得一笑，側聽高論驚尋常。", "窮閻過我坐至暮，滿懷珠玉無粃糠。", "乃知世間有清議，未可盡以己意量。", "精金白璧天所寶，理無破碎委道旁。", "半年耳冷不聞此，過公矍然神激昂。", "論文自顧已老醜，從事理絕隨飛翔。", "斯文有屬不但爾，因公作詩我涕滂。"]'),
('530cd6de-dd8f-4f89-956a-8f0ec12c8809','讀中興頌碑','張耒','宋','宋诗','song-poetry','','["\u8d5e\u9882", "\u548f\u53f2\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143", "\u51ed\u540a"]','玉環妖血無人掃，漁陽馬厭長安草。',163,'全唐诗/poet.song.64000.json','["玉環妖血無人掃，漁陽馬厭長安草。", "潼關戰骨高於山，萬里君王蜀中老。", "金戈鐵馬從西來，郭公凜凜英雄才。", "舉旗爲風偃爲雨，洒掃九廟無塵埃。", "元功高名誰與紀，風雅不繼騷人死。", "水部胸中星斗文，太師筆下蛟龍字。", "天遣二子傳將來，高山十丈磨蒼崖。", "誰持此碑入我室，使我一見昏眸開。", "百年廢興增歎慨，當時數子今安在。", "君不見荒凉浯水棄不收，時有遊人打碑賣。"]'),
('1c10f4c5-748e-4504-9dee-ee1df474dc4a','塞獵','張耒','宋','宋诗','song-poetry','','[]','十月北風燕草黄，燕人馬飽弓力强。',64,'全唐诗/poet.song.64000.json','["十月北風燕草黄，燕人馬飽弓力强。", "虎皮裁鞍雕羽箭，射殺陰山雙白狼。", "青氈帳高雪不濕，擊鼓傳觴打令急。", "單于半醉解貂裘，昭君獨抱琵琶泣。"]'),
('7daeef14-3ed3-4abb-a6a1-ffaffa2ccdab','耒病臂比已平獨挽弓無力客言君爲史官何事挽弓戲作此詩','張耒','宋','宋诗','song-poetry','','[]','君不見吾鄉少年曹子桓，文章七步相後先。',163,'全唐诗/poet.song.64000.json','["君不見吾鄉少年曹子桓，文章七步相後先。", "有時擲筆事弋獵，邀輕截駿馳平原。", "濊貊名弓燕代馬，射雉歸來燕清夜。", "一聞驚倒荀令君，何物書生乃知射。", "我雖把筆笑腐儒，束腰待懸玉鹿盧。", "自從病臂憂親友，百嗜爲之心一枯。", "降癘無名天悔禍，奪之而與復完軀。", "但慚未使杯安肘，猶負當年門掛弧。", "便使凄凉身未伏，略聞弓馬氣猶粗。", "莫謂早衰須袖手，將軍臂折尚平吳。"]'),
('b2560c7f-34fa-4aa8-8303-c296f354374c','踵息齋','張耒','宋','宋诗','song-poetry','','[]','物之有知者恃息，物之有息知爲賊。',176,'全唐诗/poet.song.64000.json','["物之有知者恃息，物之有息知爲賊。", "天長地久載元氣，天地無心故無極。", "君知一身誰主持，六塵緣影工伎兒。", "發生變幻不暫止，令汝鼻息無停時。", "喘呼呀呷生至死，去今已遠何由歸。", "真人嗒然吾喪我，能使炎火爲寒灰。", "中空無宰氣不使，內自升降如靈龜。", "深之又深乃至踵，根深蒂固凝不動。", "超然內外無死地，梨棗華實龍虎用。", "真人示我尺素書，萬卷丹經不勞誦。", "他年綠髮對銅狄，却視吾齋真作夢。"]'),
('e26df6db-48fd-4e99-8dbf-b28566656431','喜晴','張耒','宋','宋诗','song-poetry','','[]','朝看東南雲物好，便有清風收濁潦。',80,'全唐诗/poet.song.64000.json','["朝看東南雲物好，便有清風收濁潦。", "吾知天意將悔禍，約束蛟龍便粳稻。", "山川轉眼異明晦，冠屨宜人亦輕燥。", "微凉入堂酒味好，一杯徑醉愁如掃。", "清幽枕簟東窗下，曉睡老雞呼不覺。"]'),
('45cb091c-68b1-4d09-9995-dc06009cdd5f','大風與楊念三飲次作此','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','北風黄雲卷飛沙，吹暗長安百萬家。',64,'全唐诗/poet.song.64000.json','["北風黄雲卷飛沙，吹暗長安百萬家。", "溫爐對酒慎勿出，且看酒面生浮花。", "我爲吟詩說雲夢，荆江洞庭方洶湧。", "吟成飲君三百盃，莫學雪中馿酸哀。"]'),
('0db2398e-2844-42ca-9c60-2be16ba4bae8','寄道公','張耒','宋','宋诗','song-poetry','','[]','知公鼻祖冬之日，謫向江山冷無匹。',96,'全唐诗/poet.song.64000.json','["知公鼻祖冬之日，謫向江山冷無匹。", "粹然真氣滿輕軀，自言位次神仙秩。", "同輩幾人始謝老，惟公躚躚居第一。", "鸞腰不舞自欲飛，神屨瞥波原不濕。", "永巷春深簾幕幽，西都有人名莫愁。", "我老摧頹乖舊約，空能時作夢中遊。"]'),
('95e62c0c-ca9a-42db-ab4b-22c0c21df87e','東海有大松土人相傳三代時物其狀偉異詩不能盡因讀徐仲車五花柳枝之作作此詩以激之','張耒','宋','宋诗','song-poetry','','[]','詩翁愛花復愛柳，長歌高吟半酣酒。',306,'全唐诗/poet.song.64000.json','["詩翁愛花復愛柳，長歌高吟半酣酒。", "自言二物天下奇，愛之不厭形於詩。", "嗟予所愛翁未見，我昔東遊窮海甸。", "波濤四絕大島中，上有太古不死之長松。", "千人袢延坐其下，仰見翠葉迷蒼穹。", "巨鰲竭力負不起，鵬栖僅借卑枝容。", "人言海若此其圉，鱗甲百萬屯蛟龍。", "又云海怪久不死，守護山麓蟠其躬。", "天空海闊風力壯，敲戛簸蕩聲無窮。", "軒轅張樂奏未已，筍𥲤百萬喧笙鏞。", "鬼神不欲人屢見，護以萬疊青山峰。", "愛之未免困寂寞，坐見雨露霑蒿蓬。", "東皋吟翁天下才，海岳秀氣天所鍾。", "豈惟文章繼騷雅，胸中術業窺夔龍。", "如何坎軻滯茅屋，失所因與茲松同。", "詩翁勿愛花與柳，軟弱但解爭纖穠。", "春英零落化爲土，夏葉狼藉工巢蟲。", "嬌兒姹婦最入眼，丈夫所志當英雄。", "何當與君涉海去，結茅松下甘長終。"]'),
('60eb3022-2a34-4749-aedb-62042fd9148d','讀蘇子瞻韓幹馬圖詩','張耒','宋','宋诗','song-poetry','','[]','我雖不見韓幹馬，一讀公詩如見者。',147,'全唐诗/poet.song.64000.json','["我雖不見韓幹馬，一讀公詩如見者。", "韓生畫馬常苦肥，肉中藏骨以爲奇。", "開元有臣善司牧，四十萬匹屯山谷。", "養之罕用食之豐，力不曾施空長肉。", "韓生圖像無乃然，我謂韓生巧未全。", "君不見昔時騏驥人未得，饑守鹽車惟有骨。", "昂藏不受塵土侵，伯樂未來空佇立。", "騏驥乏食肉常臞，韓生不寫瘦馬駒。", "誰能爲驥傳之圖，不如凡馬飽青芻。"]'),
('675fd4fb-ba93-46eb-8ae0-bdc4d8559368','再和馬圖','張耒','宋','宋诗','song-poetry','','[]','我年十五遊關西，當時惟揀惡馬騎。',256,'全唐诗/poet.song.64000.json','["我年十五遊關西，當時惟揀惡馬騎。", "華州城西鐵驄馬，勇士十人不可羈。", "牽來當庭立不定，兩足人立迎風嘶。", "我心壯此寧復畏，撫鞍躡鐙乘以馳。", "長衢大呼人四走，腰穩如植身如飛。", "橋邊爭道挽不止，側身逼墜壕中泥。", "懸空十丈纔一擲，我手失轡猶攢蹄。", "回頭一躍已在岸，但見滿道人嗟咨。", "關中地平草木短，盡日散漫遊忘歸。", "驅馳寧復受鞭策，進止自與人心齊。", "爾來十年我南走，此馬嗟嗟入誰手。", "楚鄉水國地卑污，人盡乘船馬如狗。", "我心未老身已衰，夢寐時時猶見之。", "想圖思畫忽有感，况復慷慨吟公詩。", "達人遇境貴不惑，世有尤物常難得。", "寧能使我即無情，搔首長歌還歎息。"]'),
('9fa5898a-f53f-430c-8961-e4835981b124','宿龜山寺下贈旻師','張耒','宋','宋诗','song-poetry','','[]','淮流赴海何時窮，我生飄泊西復東。',128,'全唐诗/poet.song.64000.json','["淮流赴海何時窮，我生飄泊西復東。", "山中老僧舊相識，驚我非復當時容。", "三年歷遍百憂患，遷就汲汲如飛鴻。", "人生易老古所歎，如我安得顔長紅。", "塵埃漫滅舊題壁，枝葉已拱當時松。", "我方奔走師已老，更念別此何時逢。", "眼看故舊懷抱好，宴坐不覺聽山鐘。", "長淮月高人語絕，惟有塔鈴鳴夜風。"]'),
('9cbddbbc-a654-4959-9d26-0903e615e84d','寄子由先生','張耒','宋','宋诗','song-poetry','','[]','先生四十猶不遇，獨坐南都誰與語。',160,'全唐诗/poet.song.64000.json','["先生四十猶不遇，獨坐南都誰與語。", "青衫弟子天下窮，饑走京城困羈旅。", "高門得飯暫見肉，敝筐無實惟巢鼠。", "樓頭酒貴不敢沽，三百青銅輸杜甫。", "强顔講學昧時宜，漫自吟詩愁肺腑。", "平生不解謁貴人，况乃令嚴門者拒。", "此生自料應常爾，但願流年醉中度。", "又思人世樂乃已，此外紛紛何足數。", "豫期歸日在凉秋，想見西風蕩煩暑。", "區區懷抱冀披豁，一尊願駐東歸櫓。"]'),
('34b13dc0-35bf-49ec-9e83-2ad98575c30b','再寄','張耒','宋','宋诗','song-poetry','','[]','宛丘之別今五年，汴上留連纔一日。',320,'全唐诗/poet.song.64000.json','["宛丘之別今五年，汴上留連纔一日。", "殘生飄泊客東南，憂患侵陵心若失。", "先生神貌獨宛然，但覺巖巖瘦而實。", "有如霜露入秋山，掃除繁蔚峰巒出。", "自言近讀養生書，頗學仙人餌芝朮。", "披尋圖訣得茯苓，云是松間千歲物。", "屑而爲食可不饑，功成在久非倉卒。", "上侔金石免毒裂，下比草木爲强崛。", "涓涓潄納白玉津，鍊以真元納之骨。", "神仙自是人不知，豈爲難求廢其術。", "我聞公說心獨嗟，欲問太虛窮恍惚。", "奈何不使被金朱，乃俾枯槁思巖窟。", "又觀世事不可常，倚伏誰能定於一。", "終身軒冕亦何頼，况有朝升而暮黜。", "何如端坐養形骸，壽考康寧無夭屈。", "乃知豈即非良圖，却笑兒曹嗜糠籺。", "青衫弟子昔受經，賦分羈窮少倫匹。", "自知無命作公卿，頗亦有心窮老佛。", "但思飽暖願即已，妄意功名心實不。", "終期策杖從公遊，更乞靈丸救衰疾。"]'),
('15cb218c-972d-4d20-ad91-ab0df091991f','寄楊應之','張耒','宋','宋诗','song-poetry','','[]','應之蹉跎三十九，猶著青衫困塵垢。',256,'全唐诗/poet.song.64000.json','["應之蹉跎三十九，猶著青衫困塵垢。", "高才逸氣老益奇，我每事之安敢友。", "逢時則駕子何患，有才未用誰之醜。", "暴得從來失常速，徐驅未用鞭其後。", "掃除萬事付之命，收拾至樂歸之酒。", "聞公頗以飲自名，我亦抗衡能至斗。", "京師常恨酒不足，貧旅僅得餬其口。", "乃知一飲尚間關，功垂萬古知難偶。", "百年痛飲乃良圖，安用金朱裹枯朽。", "我生自斷計已决，君亦我徒能爾否。", "揚眉鼠子事輕肥，眨眼小兒夸謹厚。", "須防仰嚇忌鵷雛，更慮致魘逢芻狗。", "獨醒不若餔其糟，羣犬猶須避而走。", "遭刑每笑嵇叔夜，得計須師彭澤叟。", "我官古邑洛之陽，間有山川亦奇秀。", "行當釀秫從子遊，更以新詩相獻侑。"]'),
('af65a0d0-da1d-4c36-938e-4aa7c2c36465','招潘郎飲','張耒','宋','宋诗','song-poetry','','[]','老人夜短睡不足，㪍公窗外强知時。',96,'全唐诗/poet.song.64000.json','["老人夜短睡不足，㪍公窗外强知時。", "五更未明語千萬，更憎林間鵯鵊兒。", "吹紅洗白雨三日，吾園花在已離披。", "一年春事坐如此，白首窮謫歸無期。", "念此徑須沽酒飲，買魚烹肉勤妻兒。", "更呼東鄰好酒伴，爲我醉倒階前泥。"]'),
('0a615c85-e6d0-4693-86b3-2dad838efd41','郭圃送蕪菁感成長句','張耒','宋','宋诗','song-poetry','','[]','蕪菁至南皆變菘，菘美在上根不食。',128,'全唐诗/poet.song.64000.json','["蕪菁至南皆變菘，菘美在上根不食。", "瑶簪玉筍不可見，使我每食思故國。", "西鄰老翁知我意，盈筐走送如雪白。", "蒸烹氣味元不改，今晨一日如還北。", "孔明用蜀最艱窘，百計掇拾無遺策。", "當時此物助軍行，渭上褒中有遺植。", "英雄臨事究瑣屑，終服奇才屈强敵。", "想見躬耕自灌畦，當時有意誰能測。"]'),
('982a1245-41e6-4f99-9036-74931feffc73','讀守道詩','張耒','宋','宋诗','song-poetry','','[]','仁宗之初公有聲，一世懦者聞之驚。',192,'全唐诗/poet.song.64000.json','["仁宗之初公有聲，一世懦者聞之驚。", "日行古義不顧俗，師事孫子傳其經。", "掃堂捧杖供賤役，侍師之坐隨師行。", "質疑問道無敢變，當世始知師與生。", "作爲文章不徒發，譏切時事排公卿。", "俗儒毀譽無所出，乃取過行爲譏評。", "過於仁義罪固小，矯弊自合違中行。", "人皆不及子獨過，過者之罪誰爲輕。", "開編偶誦子詩句，辭氣磊落嚴以清。", "吟哦令我不能舍，想見眉宇寒崢嶸。", "高風一泯不可見，安得壯士能經營。", "惜哉朽骨不可作，徂徠廢土知誰耕。"]'),
('be85608c-d446-40d0-b9cc-39e651037904','對雪呈仲車','張耒','宋','宋诗','song-poetry','','[]','學堂歲暮無來客，殘雪漫漫風獵獵。',160,'全唐诗/poet.song.64000.json','["學堂歲暮無來客，殘雪漫漫風獵獵。", "當庭古柳三四枝，老翁携帚收殘葉。", "二年閒散百事慵，饑寒不自勤鋤鍤。", "囊空甑倒誰復救，典衣買酒將空篋。", "人間萬事苦難齊，以醉驅愁最奇捷。", "丈夫未死誰能測，幽憂何自同兒妾。", "飲酣耳熱詩興豪，直上虛空恣凌躡。", "饑喉凍噤誰與解，正藉醺酣得嚅囁。", "少年舉白未嘗辭，漸老深杯見還怯。", "何當共有種秫田，免向官壚走書帖。"]'),
('b65b8cba-40e4-46c0-a47d-85634eb5035e','昨者','張耒','宋','宋诗','song-poetry','','[]','昨者飛雹幾破屋，頗說四郊妨麥熟。',96,'全唐诗/poet.song.64000.json','["昨者飛雹幾破屋，頗說四郊妨麥熟。", "十日霖雨一日晴，泥潦漫漫不容足。", "凄風寒凉肅肌骨，五月更衣初秋服。", "草木傷摧亦可憐，造物憑陵竟何欲。", "陰陽錯行成疫癘，君子慎疾防寒燠。", "荒凉窮巷幸無他，更勸高眠飽饘粥。"]'),
('16b57498-2a16-4f25-9265-1125a8ec091c','己未四月二十二日大雨雹','張耒','宋','宋诗','song-poetry','','[]','夜來飛雹驚我眠，大者磊落幾如拳。',128,'全唐诗/poet.song.64000.json','["夜來飛雹驚我眠，大者磊落幾如拳。", "起聽但覺屋欲動，簷瓦破墜無復全。", "是日晚晴星斗出，鏡靜萬里無雲烟。", "乾坤變化竟誰使，造作詭怪須臾間。", "鄰家老翁髮已白，云昔見此今十年。", "木衰火濫氣浮洩，激此陰沴成冰堅。", "儒生臆度知是否，天事誰得窮其源。", "屋頭雛鴉失其母，足傷翅折亦可憐。"]'),
('c6088b23-8589-4235-9781-7fb344f80b70','遊楚州天慶觀觀高道士琴棋','張耒','宋','宋诗','song-poetry','','[]','頹垣蒼蒼鎖喬木，草滿荒庭不容足。',160,'全唐诗/poet.song.64000.json','["頹垣蒼蒼鎖喬木，草滿荒庭不容足。", "壞簷破壁秋雨餘，蛛網蕭蕭風滿屋。", "黄衣道人出迎客，野態生疏脫拘束。", "圍棋盡掃一堂空，烹茶旋煮新泉熟。", "彈琴對客客卧聽，悅耳泠泠三四曲。", "離騷幽怨松風悲，流水潺湲履霜哭。", "日斜携手步空廊，鳴鳩相呼竹間宿。", "黄昏門閉人語絕，空殿幽幽掩微燭。", "我生資身最淡薄，每厭煩歊幸幽獨。", "何當不踏朝市塵，長伴高人種松菊。"]'),
('b14bc7bf-ea82-4c22-828d-99609887155a','惜別贈子中昆仲二首  其一','張耒','宋','宋诗','song-poetry','','[]','寒雲崩騰不成雪，北風吹窗燈半滅。',192,'全唐诗/poet.song.64000.json','["寒雲崩騰不成雪，北風吹窗燈半滅。", "病來廢飲卧無眠，一夜吟詩聲不絕。", "南城三俊生契闊，想對寒爐掉吟舌。", "留行一日誰有情，慰我與君千里別。", "道長塵土疲馬愁，歲晚風霜敝裘裂。", "人生何用讀書史，文字未補囊中闕。", "驅馳所幸一飽耳，士而謀食愧前哲。", "何能天獨嗇吾曹，自應所學爲之孽。", "雖然此事予不悔，昔學固知今日拙。", "欲持琬琰易羊皮，玩之已久安能輟。", "萬端畢竟有天命，計較何須論瑣屑。", "勞歌無和坐達明，曉鼓鼕鼕墮殘月。"]'),
('53dce9bf-236f-4b4f-b0b3-342532d1fc2a','惜別贈子中昆仲二首  其二','張耒','宋','宋诗','song-poetry','','[]','我年十八從先生，今也相逢得三子。',224,'全唐诗/poet.song.64000.json','["我年十八從先生，今也相逢得三子。", "坐思前事且十年，嗟我不才老將俟。", "子中兄弟氣清拔，粲若瑶環與瓊珥。", "逸足駿馬不受羈，凌躒奔馳動千里。", "先生聲名二十載，乃得姻婭皆文士。", "我今賀子得所遭，非我先生誰辦此。", "定交自恨相知晚，漫浪一官非我志。", "論文終日坐忘歸，欲別出門還頓轡。", "我如轅駒幸芻豆，豈不自厭安敢避。", "人生謀食亦可悲，世上舍閒皆失計。", "西來有人話吾邑，頗說山川慰人意。", "寄詩莫憚憑驛傳，對酒惜哉無子醉。", "到官便掃琴書室，有客過我行當至。", "疏泉養筍待子吟，更采山芻秣君驥。"]'),
('79941816-8eb8-4a6b-be71-a56b1ebfb8d0','早作','張耒','宋','宋诗','song-poetry','','[]','鸕鷀夜寒不得眠，永夜相語高樹顛。',80,'全唐诗/poet.song.64000.json','["鸕鷀夜寒不得眠，永夜相語高樹顛。", "鴉鳴最早尤喧闐，啼呼相應動百千。", "老雞睡起足攣拳，側頭端如聞九天。", "引吭一唱鳴宮懸，時哉不後亦不先。", "朦朧初日見山川，吾廬晨起有炊烟。"]'),
('1c401889-c6e2-4fb4-ad8a-60865c226e52','自南京之陳宿柘城','張耒','宋','宋诗','song-poetry','','[]','荒城人稀荆棘老，野兔驚跳出寒草。',192,'全唐诗/poet.song.64000.json','["荒城人稀荆棘老，野兔驚跳出寒草。", "蒼蒼落日黄雲西，驅馬城邊尋古道。", "入門四顧皆桑田，居民三五依道邊。", "暮投佛寺下馬立，衝眼滿屋燃萁烟。", "老僧自言八十餘，老矣不能營所居。", "村僮依竈展敗席，上有空梁懸木魚。", "旋汲新泉濯雙手，青燈照客黄昏後。", "羣兒爛漫眠我前，新月欲傾光入牖。", "夜敲僧室借酒壺，不惜青錢取次沽。", "酒香入戶推枕起，剔燈吹火燃銅盂。", "大杯一沃不留滴，滿眼棼然睡來集。", "明朝上馬倒殘壺，不怕新霜敗裘濕。"]'),
('229d7865-b8a8-4559-bcbd-20d1d34190de','送劉季孫守隰州','張耒','宋','宋诗','song-poetry','','[]','君家將軍本縫掖，叱咤西摧賀蘭石。',128,'全唐诗/poet.song.64000.json','["君家將軍本縫掖，叱咤西摧賀蘭石。", "一時成敗何足論，要使英名垂竹帛。", "到君奇骨尚虎頭，白鬚千騎守邊州。", "插架萬籤供記覽，探囊五字擅風流。", "大河之東士精勇，日飲不妨飛獵鞚。", "五更吹角建牙旗，萬馬合圍行酒甕。", "朝裘風勁黑貂暖，夜帷雪滿青氈重。", "樂哉閉口莫言兵，雖有頗牧誰能用。"]'),
('95376cb0-20dc-4bd1-8d28-53ddd7098f44','北原','張耒','宋','宋诗','song-poetry','','[]','秋風日夜吹北原，秋蕪經霜不復繁。',160,'全唐诗/poet.song.64000.json','["秋風日夜吹北原，秋蕪經霜不復繁。", "縈紆一逕漸可躡，步踏落葉披榛菅。", "蕭蕭九月草木變，獨有修竹猶禁寒。", "青紅野實不可辨，晚日照射霜榴殷。", "巉巉女几更清瘦，崖壁刻削無雲烟。", "潦收石出洛水好，靜夜側耳聲潺潺。", "原西古城有微路，禾黍離離荒野田。", "人家歲熟婦子樂，村巷日暖牛羊閒。", "登臨嗟我幸無事，况有美酒供開顔。", "射麋獵兔可卒歲，棄擲萬累休嗟歎。"]'),
('1837e722-7a5a-46e2-aed0-8795935266a8','感春','張耒','宋','宋诗','song-poetry','','[]','若若堂北桃，昨日花猶小。',188,'全唐诗/poet.song.64000.json','["若若堂北桃，昨日花猶小。", "暖風遲景一日功，萬萼千葩爛相照。", "東風漾漾吹朝雨，朝日滿簷春鳥語。", "櫻桃得暖花意忙，接萼連枝間先吐。", "蘭芽出地長可握，小筍如簪堪薦箸。", "欣欣萬木誰使然，時來不肯居塵土。", "盛衰相感但如此，鏡中安得朱顔駐。", "古來百計無可奈，惟有飲者謀猶庶。", "乃知甚急莫如酒，有衣可典猶爲富。", "我今不樂欲何待，薄俸自給供朝暮。", "功名有命不可求，白髮無私誰得拒。", "從今酩酊勿復辭，棄置人間千萬慮。"]'),
('32f8f634-49a0-4bed-8427-d9d1b11f50fd','寄陳器之','張耒','宋','宋诗','song-poetry','','[]','昨者見君纔頃刻，滿馬塵埃面黧黑。',288,'全唐诗/poet.song.64000.json','["昨者見君纔頃刻，滿馬塵埃面黧黑。", "自言別家春欲闌，歸意如飛留不得。", "玉鞭揮折手成胝，一日到家馳四驛。", "今朝得書一何喜，酌酒烹雞稅征軛。", "自言山城無與樂，坐看飛花良可惜。", "手携婦子口吟詩，文字揮毫便千百。", "醉歌昌谷和我吟，錦囊舊句無顔色。", "憐君潦倒誰復省，場屋十年名烜赫。", "嗟我春來亦何事，飽食高眠度朝夕。", "簾前相對但有山，坐上清談更無客。", "逼眼花光羅綺眩，照人酒色瓊瑶白。", "風光似此寧可忍，酩酊高歌卧花側。", "平生結友事遨遊，未省流年守山僻。", "强歡獨飲豈所樂，舍此無謀慰愁寂。", "思君一笑何可得，王事有程身有役。", "堂南柳條爭著葉，繁李夭桃落如積。", "請看春物能有畿，坐見清和變炎赫。", "須期載酒對東風，及此殘花尚堪摘。"]'),
('4153e97d-4468-4214-95da-03544e39971b','讀李憕碑','張耒','宋','宋诗','song-poetry','','[]','自唐中微北方沸，胡馬長鳴飲清渭。',160,'全唐诗/poet.song.64000.json','["自唐中微北方沸，胡馬長鳴飲清渭。", "李公守節陷賊庭，身死髑髏行萬里。", "百年事往誰復省，一丘榛莽無人祭。", "荒碑半折就磨滅，後人空解傳其字。", "殺身不畏真丈夫，自古時危知烈士。", "俗書小技何足道，嗟我但欲揚其事。", "寥寥獲麟數千載，末學褒貶多非是。", "高文大筆誰復作，黜臣餓夫須有待。", "紛紛後世競著述，紙墨徒爲史官費。", "却嗟何獨此事然，搔首碑前空歎慨。"]'),
('a3424f90-eb12-402c-9d30-d293949bd4f9','和陳器之詩四首 朝應天','張耒','宋','宋诗','song-poetry','','[]','唐衰五季更披猖，社稷反手看興亡。',192,'全唐诗/poet.song.64000.json','["唐衰五季更披猖，社稷反手看興亡。", "山河分裂流戰血，積骨被野號豺狼。", "中原正朔不出境，九州豪傑爭侯王。", "生民禍難冤痛極，腥穢上達干穹蒼。", "真人龍飛萬物睹，天命自至誰能當。", "靈旗指揮四海一，氛祲殄滅和風翔。", "降王賜第奉朝謁，九服效職爭梯航。", "百年積累到今日，運祚方與乾坤長。", "佛宮原廟廣孝敬，嚴致守衛勤烝嘗。", "陰陰祕寢鎖遺像，矗矗畫戟羅蕭牆。", "衣冠具列虛仗儼，龍駕不反遺弓藏。", "子孫億載千萬世，永與清洛流湯湯。"]'),
('51f387d3-740d-4f5b-8ac7-e744ca83b43c','和陳器之詩四首 過韓城','張耒','宋','宋诗','song-poetry','','[]','周京無人弔禾黍，七雄按劍分周土。',160,'全唐诗/poet.song.64000.json','["周京無人弔禾黍，七雄按劍分周土。", "秦人匹馬出函關，六王割地愁爲虜。", "宜陽古堞故韓都，地接强秦爭戰苦。", "謀窮運去竟亡國，從長蘇秦亦何補。", "諸侯已盡秦巍巍，嬴氏已亡秦不知。", "始皇自是呂家子，宗廟薦享真何爲。", "山河百戰移陵谷，宮殿成塵埋寶玉。", "秋風壞塚長荆榛，落日空城散樵牧。", "今古悠悠共一丘，爭强蝸角欲何求。", "誰似令威仙骨健，千年重向故鄉遊。"]'),
('6d8ca5e6-b3d0-4a60-abc5-42d4613a4558','和陳器之詩四首 弔連昌','張耒','宋','宋诗','song-poetry','','[]','唐日西頹半明滅，長彗掃天流戰血。',128,'全唐诗/poet.song.64000.json','["唐日西頹半明滅，長彗掃天流戰血。", "六龍不復入東都，連昌已有狐狸穴。", "宮前茫茫洛陽路，漢甲胡兵幾回度。", "火焚馬蹴百戰場，盡是舊時歌舞處。", "遊魂不歸宮樹老，茂陵金玉人間寶。", "春耕迤邐上空山，夜燐青熒照秋草。", "女几巉巉青插天，東流洛水自潺湲。", "興亡一覺繁華夢，只有山川似舊年。"]'),
('5072530c-cfb3-49b7-9713-4a062493e625','和陳器之詩四首 鹿仙山','張耒','宋','宋诗','song-poetry','','[]','真人朝天去不還，千年鹿跡留空山。',131,'全唐诗/poet.song.64000.json','["真人朝天去不還，千年鹿跡留空山。", "空山寂寞何所有，野殿荒凉松檜寒。", "桑田海水移今古，興亡萬變誰能數。", "五雲深處駕飛龍，應笑人間換朝暮。", "神仙不與世人期，騎鹿安知不復歸。", "朝嵐夕靄山秀潤，應有靈丹相護持。", "長生可求仙可致，浮世腥膻何足嗜。", "君不見漢時九江梅子真，一日辭家隠吳市。"]'),
('9e4bcf25-eff8-4c33-82de-92130f5f0a6a','長安仲春二首  其一','張耒','宋','宋诗','song-poetry','','[]','長安仲春七日風，蒼茫頓撼天地同。',96,'全唐诗/poet.song.64000.json','["長安仲春七日風，蒼茫頓撼天地同。", "應門縹闕岌欲動，况我窮巷連蒿蓬。", "暮寒卷雪連芳草，平門萬屋青城縞。", "無言桃李終默默，得勢泥塗常浩浩。", "夕暉入屋人氣活，勞苦羲和間何闊。", "斗杓東指令未行，要使燭龍聊潑剌。"]'),
('41ca19a7-a547-4d2b-b2af-9b2d08fddf0a','長安仲春二首  其二','張耒','宋','宋诗','song-poetry','','[]','長安花繁仲春月，北風倒山雨成雪。',64,'全唐诗/poet.song.64000.json','["長安花繁仲春月，北風倒山雨成雪。", "窮巷下里袴襦盡，老翁稚兒骨欲折。", "吾人諳事不復驚，以手扣額願天晴。", "夕陽纔升已復晦，積雲如山那肯退。"]'),
('b431cf0b-37ab-467a-ba82-f3fa116b8d7b','贈吳孟求承議二首  其一','張耒','宋','宋诗','song-poetry','','[]','我生仕宦求餬口，敢憚水浮兼陸走。',96,'全唐诗/poet.song.64000.json','["我生仕宦求餬口，敢憚水浮兼陸走。", "朅來京口見花落，歸去西風未吹柳。", "山尋北固初知路，水飲中泠未盈缶。", "徒勞結束解書劍，未覺塵埃生戶牖。", "瓜洲澄江曉如鏡，照水自覺秋容瘦。", "因公忽致舊酒壺，恍如夢覺南柯守。"]'),
('120aa330-90ec-4c48-ba00-72cecc590cbd','贈吳孟求承議二首  其二','張耒','宋','宋诗','song-poetry','','[]','我非初平叱羊口，江中浪作羣羊走。',96,'全唐诗/poet.song.64000.json','["我非初平叱羊口，江中浪作羣羊走。", "金山五日厭僧粥，揮榜瓜洲纜古柳。", "晨興但怪妻孥喜，故人致饋羅盤缶。", "起傾殘榼得餘瀝，洗盞再酌開蓬牖。", "風雲慘淡秋已嚴，桑榆摇落山初瘦。", "軍厨醇味尚煩公，應記疏慵窮太守。"]'),
('2e57db0d-21bd-436f-a425-92d02e32fabd','秋蔬','張耒','宋','宋诗','song-poetry','','[]','荒園秋露瘦韮葉，色茂春菘甘勝蕨。',128,'全唐诗/poet.song.64000.json','["荒園秋露瘦韮葉，色茂春菘甘勝蕨。", "人言佛見爲下箸，芼炙烹羹更滋滑。", "其餘瑣屑皆可口，蕪菁脆肥薹葅辣。", "藏鞭雛筍纖玉露，映葉乳茄濃黛抹。", "已殘枸杞只留枿，晚種萵苣初生甲。", "南來食魚忘肉味，久思吾土牛羊茁。", "軟炊一飽老有味，痛飲百壺今不說。", "蒲團齋罷欠伸時，自覺少年心解脫。"]'),
('0b1779f4-6a01-4d27-b918-e4fd2deb4513','瓜洲謝李德載寄蜂兒木瓜筆','張耒','宋','宋诗','song-poetry','','[]','瓜洲蕭索秋江渚，西風江岸殘紅舞。',128,'全唐诗/poet.song.64000.json','["瓜洲蕭索秋江渚，西風江岸殘紅舞。", "津亭永夜守青燈，客睡朦朧聽江雨。", "青罇曉酌遣懷抱，但恨鬰鬰將誰語。", "敲門忽得故人書，洗手開緘見眉宇。", "蜂兒肥膩愈風痹，木瓜甘酸輕病股。", "銛鋒皓管見還愧，老去筆硯生塵土。", "北歸飄泊亦何事，篙工已束橫江櫓。", "天寒應客太昊墟，當遣何人具雞黍。"]'),
('e8bda187-e22e-47e5-a5c2-d376ea741763','贈晁二','張耒','宋','宋诗','song-poetry','','[]','昔者與兄城南鄰，未省一日不相親。',160,'全唐诗/poet.song.64000.json','["昔者與兄城南鄰，未省一日不相親。", "誰令僦舍得契闊，此事我每懷古人。", "逾旬寒熱不可說，遍體戢戢生赤鱗。", "是身非有病亦幻，調御未伏猶酸辛。", "布衾蒙頭但欲睡，瞥見簷雪如飛塵。", "豈無杯杓與酬酢，口舌未肯親芳醇。", "平生相逢百不問，斗酒倒盡纔逡巡。", "崎嶇行世得皆妄，嵬峨就醉事最真。", "殘年崢嶸欲無日，晴雲浩蕩已有春。", "柳黄梅破最佳絕，京兆羔酒仍慇懃。"]'),
('fb1d5dc0-a3ae-4a5f-999c-795ab7a52c1d','和定州端明雪浪齋','張耒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','中山士馬如雲屯，號令惟覺將軍尊。',160,'全唐诗/poet.song.64000.json','["中山士馬如雲屯，號令惟覺將軍尊。", "熊旂犀甲羅左右，金鉦鳴鼓喧朝昏。", "少年畎畝老爲將，誰能復記躬耕村。", "東坡先生事業異，道岐不得安修門。", "眼前富貴念不起，惟有山林勞夢魂。", "榛中奇石安至此，坐蒙湔洗見本根。", "奔流驟浪勢萬里，至畫乃掃筆墨痕。", "黄牛三峽固細事，赤壁長江何足論。", "能令萬古蛟蜃怪，么麽入此玻璃盆。", "扁舟獨往則不可，平生致君言具存。"]'),
('388d4f79-90e3-422b-8acc-800febe7585a','某寒熱伏枕已數日忽聞車騎明當接頓睡中得韵語數句上呈四丈龍圖兼記至日之飲','張耒','宋','宋诗','song-poetry','','[]','山羊卷酥如切玉，翦毛胡羊花作肉。',112,'全唐诗/poet.song.64000.json','["山羊卷酥如切玉，翦毛胡羊花作肉。", "燭前醉客淋漓時，山泉更煮如珠粟。", "深泥三尺歸不記，日到床前初睡足。", "爾來七日戰寒熱，朝飯齋糜不盈掬。", "客來但辦君且去，卧聽涓涓雪消屋。", "因山事嚴京兆出，十驛人人如在目。", "駝裘便面行野時，晴郊已動陳根綠。"]'),
('8dc95e62-078f-40ee-adc3-5d94bb3c5622','贈晁十七','張耒','宋','宋诗','song-poetry','','[]','應之風骨世絕倫，濯濯芳柳當青春。',128,'全唐诗/poet.song.64000.json','["應之風骨世絕倫，濯濯芳柳當青春。", "瓊瑶冰雪照一坐，我恐子是神仙人。", "十年聲名望不見，一日邂逅情相親。", "安仁白璧絕瑕玷，宗之玉樹無埃塵。", "襟清胸明遇事敏，西河舊政傳諸民。", "縣門高開吏束手，訟至立决如有神。", "別君還家恍如失，咫尺莫見徒爲鄰。", "會期殘春再携手，滿引大釂無辭頻。"]'),
('d90d362c-e398-4ba4-8d7f-f6b49029ae87','聽客話澶淵事','張耒','宋','宋诗','song-poetry','','[]','憶昔胡來動河朔，渡河飲馬吹胡角。',96,'全唐诗/poet.song.64000.json','["憶昔胡來動河朔，渡河飲馬吹胡角。", "澶淵城下冰載車，邊風蕭蕭千里餘。", "城上黄旂坐真主，夜遣六丁張猛弩。", "雷驚電發一矢飛，橫射胡酋貫車柱。", "犬羊無蹤大漠空，歸來封禪告成功。", "自是乾坤扶聖主，可能功業盡萊公。"]'),
('23a54698-aeef-488e-8fc4-3e2660325e5f','和晁應之憫農','張耒','宋','宋诗','song-poetry','','[]','南風吹麥麥穗好，饑兒道上扶其老。',160,'全唐诗/poet.song.64000.json','["南風吹麥麥穗好，饑兒道上扶其老。", "皇天雨露自有時，爾恨秋成常不早。", "南山壯兒市兵弩，百金裝劍黄金縷。", "夜爲盜賊朝受刑，甘心不悔知何數。", "爲盜操戈足衣食，力田竟歲猶無穫。", "饑寒刑戮死則同，攘奪猶能緩朝夕。", "老農悲嗟淚沾臆，幾見良田有荆棘。", "壯夫爲盜羸老耕，市人珠玉田家得。", "吏兵操戈恐不銳，由來殺人傷正氣。", "人間萬事莽悠悠，我歌此詩聞者愁。"]'),
('0cd46f36-08d9-4799-a607-b949ee935384','止酒贈郡守楊瓌寶','張耒','宋','宋诗','song-poetry','','[]','止酒正似塞决河，厚積薪芻傅砂礫。',192,'全唐诗/poet.song.64000.json','["止酒正似塞决河，厚積薪芻傅砂礫。", "堅牢不使見蟻漏，一線纔通便奔激。", "莫輕弱箭不穿縞，轉眼已驚牛弩射。", "我今止酒用此法，目前逾月無涓滴。", "情鍾我輩獨痛制，慧通則流那可測。", "懲羹端是合吹虀，用玉無疑初諫漆。", "脾乾胃燥生未省，黄姥無聊怨岑寂。", "不憂羣飲惱姬翁，但畏獨醒嘲楚客。", "茫然自惻還自笑，一身心口相仇敵。", "何妨二豎即奔忙，不廢三嬰更滋澤。", "平生杯杓不掛眼，一飲便須論斗石。", "低心伏老慎勿癡，此身何啻千金值。"]'),
('9aa5753c-32fa-4828-8560-15d57fd469a8','送畢公叔奉詔赴陝西','張耒','宋','宋诗','song-poetry','','[]','畢子談鋒不可摧，捷若急電飛霆雷。',224,'全唐诗/poet.song.64000.json','["畢子談鋒不可摧，捷若急電飛霆雷。", "老儒宿學不敢較，左右戈戟縱橫排。", "文如翻河注浩渺，學有要會窮根荄。", "眼看青雲不著脚，决去得邑窮山隈。", "漢家封疆際四海，琛賮萬里連翩來。", "西河故地獨何事，禮樂舊俗遭狼豺。", "包藏隠忍非一日，獸子未可仁心懷。", "英雄天子命世主，撫劍震怒風雷迴。", "馬如屯雲士如虎，萬車載甲如崔嵬。", "豈惟俘斬復境土，誓剖巢穴窮卵胎。", "除書命子參漕府，國有大事須羣才。", "男兒功業在勤苦，莫惜沙塞衝塵埃。", "禦戎舊策子所習，胸臆請爲將軍開。", "封侯報國在今日，贈行滿舉黄金杯。"]'),
('5e175b5b-14d1-47d1-99e4-c641c8955380','九月十二日入南山憩一民舍冒雨炙衣久之','張耒','宋','宋诗','song-poetry','','[]','石棱如刀不容步，上挽垂藤下無路。',160,'全唐诗/poet.song.64000.json','["石棱如刀不容步，上挽垂藤下無路。", "風寒雨滑徒旅愁，捨馬杖藜泥沒屨。", "躋攀顛墜不容髮，目眩心寒驚反顧。", "亦知垂堂有遺戒，身仰微官欲誰愬。", "蕭蕭茅屋映絕壁，門外汩汩清泉注。", "解衣就火不能暖，旋拾山薪伐溪樹。", "山翁生未食醯醢，脫粟寒蔬度朝暮。", "人間平地固不少，何用崎嶇守磨兔。", "秋聲四起山靄夕，壞屋疏籬睡無處。", "披裘結束相勸歸，過盡重雲下山去。"]'),
('a79f94d7-557f-4821-a39c-70f31c3f91c7','八盜','張耒','宋','宋诗','song-poetry','','[]','挾弓持矛八人者，暮出永寧循白馬。',384,'全唐诗/poet.song.64000.json','["挾弓持矛八人者，暮出永寧循白馬。", "袁村飲酒呼主翁，主翁倉皇問以弓。", "朝飯南山民獻彘，主人贈刀其姓李。", "道逢兩夫捕鷹隼，脅之以威使從己。", "晚投民居迫之饋，坐有三夫願從事。", "其徒新故十有三，驅使兩夫前探伺。", "諜知小水無徼巡，彎弓長呼蒼市門。", "傳聲市人恣誘脅，擾擾坐致幾千人。", "一盜登床坐而視，四盜執兵環以衛。", "八夫露刃入民居，斂聚金珠致之帥。", "搜羅抉剔凡八戶，淫污婦女纍其主。", "烹羊致酒來紛紛，錢幣滿前隨賜與。", "一盜揚聲集市人，我憐市人常苦貧。", "居民積財尚餘羨，恣爾攫取舍無嗔。", "市人聽令喜且舞，肩負囊擔誰復數。", "須臾散去閭里空，犬逝雞逃無敢語。", "八盜連謀詔其五，爲我鳴金南取路。", "人聞金聲謂盜南，八盜西馳下山去。", "長吏飛書呵有司，坐欲捕獲如吾期。", "洛陽大牓如匹帛，一百萬錢賞能獲。", "一朝兩卒扣吾門，自言有密人不聞。", "我知小鼠羣偷地，二盜今居洛之涘。", "立呼吏兵給戈弩，期以朝擒夜馳去。", "可憐鼠子不知逃，猶復持矛起相拒。"]'),
('408c6060-fcea-49bf-95f4-3b06859214d4','淮陰阻雨','張耒','宋','宋诗','song-poetry','','[]','檣竿日日春風轉，渺渺孤舟數家縣。',128,'全唐诗/poet.song.64000.json','["檣竿日日春風轉，渺渺孤舟數家縣。", "朝來雨暗隔淮村，白浪卷沙吹斷岸。", "渡頭楊柳濕青青，橋下涓涓野水生。", "滿尺白魚初受釣，斷行歸雁故能鳴。", "平生行止任遲速，篷底欠伸朝睡足。", "從來江海有前約，老去塵埃無可欲。", "曉天暖日生波光，桃杏家家半出牆。", "春日春波好相待，短帆輕櫓可須忙。"]'),
('2d007b99-6f5f-441e-8e58-04280f7d8c7f','蕭朝散惠石本韓幹馬圖馬亡後足','張耒','宋','宋诗','song-poetry','','[]','世人怪韓生，畫馬身苦肥。',287,'全唐诗/poet.song.64000.json','["世人怪韓生，畫馬身苦肥。", "幹寧忍不畫驥骨，當時廄馬君未知。", "開元太平國無事，戰馬卷甲飽不騎。", "玉關橐駝通萬里，長安第宅連諸姨。", "笙歌錦繡遍一國，六龍長閒空食粟。", "霜甜秋草沙苑遊，日暖春波渭川浴。", "脽圓腰穩目生光，細尾豐膺毛帖肉。", "珠鞍玉鐙驕不行，豈有塵埃侵四足。", "韓生丹青寫天廄，磊落萬龍無一瘦。", "豈知車下骨如牆，饑食草根刺傷口。", "君家古圖纔半身，千里騰驤已有神。", "迴身側顧不無意，剪騣絡頭嗟失真。", "君不見太宗戰馬拳腹毛，身騎此馬縛羣豪。", "龍虎精神金鼓氣，豈有閑地供脂膏。", "至今畫圖快胸臆，想見虬鬚親破賊。", "那知但愛廄中肥，漁陽筋脚蹄如石。", "神駒入水隨烟雲，蜀山石路無行人。", "六驥悲鳴足流血，騎騾遺事一酸辛。"]'),
('e0488b75-3eb8-4d93-891e-4d3bd3c15a2e','次韵君復七兄見贈','張耒','宋','宋诗','song-poetry','','[]','老知山林等朝市，扁舟誰能問行止。',192,'全唐诗/poet.song.64000.json','["老知山林等朝市，扁舟誰能問行止。", "長淮十日浪吹沙，春風正攪驪龍睡。", "幽人軟語破永日，衝泥携手林間寺。", "坐中知兄病當已，眉宇氤氳有佳氣。", "華池神酒不用醒，人生和暢自忘形。", "扶持陰德鬼神在，洗除世緣煩惱輕。", "東來自慚雙鬢改，相逢獨覺兩眼明。", "論詩尚愛淡生活，學道久歎閒名聲。", "嗟我塵埃費昏旦，補刖自憐聞道晚。", "還丹欲問僕僕仙，一菴更伴騰騰睡。", "春陰夜薄月朦朧，劇談燭盡樽亦空。", "他日重逢龐處士，可能猶與世人同。"]'),
('3ce8e0d7-e728-4932-b9c0-813a6059e23e','離泗州有作','張耒','宋','宋诗','song-poetry','','[]','舸𦩆大艑來何州，翩翩五兩在船頭。',112,'全唐诗/poet.song.64000.json','["舸𦩆大艑來何州，翩翩五兩在船頭。", "淮邊落帆汴口宿，橋下連檣南與北。", "南來北去何時停，春水春風相送迎。", "沙岸飛鷗舊相見，短亭楊柳不無情。", "清歌一曲主人酒，主人壽客客舉手。", "明日酒醒船鼓鳴，沙邊破堠不知名。", "行人十里一回首，雲邊猶有塔亭亭。"]'),
('112e7053-e920-4ff2-a774-97106b4add4e','汴上觀迎送有感','張耒','宋','宋诗','song-poetry','','[]','居人憐客千里來，掃堂爲客致酒杯。',96,'全唐诗/poet.song.64000.json','["居人憐客千里來，掃堂爲客致酒杯。", "夜闌再拜客辭去，尊前美人不成舞。", "陽關八疊倒玉船，銷魂此地自年年。", "船頭旂竿船尾柂，南遊江海北長安。", "長亭出城十餘里，柳邊人家飯遊子。", "少年此地幾經過，白頭相逢可奈何。"]'),
('0ed50c10-c9ba-4eca-af49-1b69450459fc','奉先寺','張耒','宋','宋诗','song-poetry','','[]','荒凉城南奉先寺，後宮美人棺葬此。',128,'全唐诗/poet.song.64000.json','["荒凉城南奉先寺，後宮美人棺葬此。", "角樓相望高起墳，草間栢下多石人。", "秩卑焚骨不作塚，青石浮屠當丘壠。", "家家墳上作享亭，朱門相向無人聲。", "樹頭土梟作人語，月黑風悲鬼摇樹。", "宮中養女作子孫，年年犢車來作主。", "廢后陵園官道側，家破無人掃陵域。", "官家歲給半千錢，街頭買餠作寒食。"]'),
('e447a45b-9a8d-407b-8a5d-ef3d01fef969','送程德孺赴江西','張耒','宋','宋诗','song-poetry','','[]','程侯治楚我獨知，去時民作嬰兒啼。',160,'全唐诗/poet.song.64000.json','["程侯治楚我獨知，去時民作嬰兒啼。", "歸來明光見天子，還把一節來江西。", "年來屢下寬大詔，赤子未免寒與饑。", "恩如憂病政如藥，知病無藥何由治。", "朝廷法度寄吏手，付授得所乃合宜。", "事如黑白初易睹，敢以容悅相蒙欺。", "此行委寄意不淺，列城數十受指揮。", "任官輕外最弊法，省閣無補真何爲。", "遙知敏手多暇日，不廢樽俎環蛾眉。", "從君多乞歙州紙，歲晏天祿供吟詩。"]'),
('52e5b380-517d-4fc3-bd5a-71dd769fd241','送杜君章守齊州','張耒','宋','宋诗','song-poetry','','[]','平生杜公賢弟兄，北州人物家法稱。',160,'全唐诗/poet.song.64000.json','["平生杜公賢弟兄，北州人物家法稱。", "兒童服膺今見面，溫潤圭璧清霜冰。", "胸中詩書不見試，鬢髮欲白論邦刑。", "用違所長衆不可，公猶談笑氣甚平。", "人才之難萬冀一，一士其重九鼎輕。", "典籤不廢吟擁鼻，所歎虛席何人登。", "臨蕃千騎亦不惡，聊以餘力蘇疲氓。", "霜清水落魚潑剌，萬甕沸響新醪傾。", "東秦山河太守貴，長安歌舞新曲成。", "正須晝夜快作樂，舍人促公歸治行。"]'),
('61a2ba61-4a9b-49d1-8449-47558c3cf77d','送劉季孫赴浙東','張耒','宋','宋诗','song-poetry','','["\u592a\u6e56"]','將軍好書如郤縠，文史隨船三萬軸。',128,'全唐诗/poet.song.64000.json','["將軍好書如郤縠，文史隨船三萬軸。", "吟詩坐嘯士賈勇，不學虎頭飛食肉。", "念昔先君得佳句，歸見兒童詫珠玉。", "乖離存沒偶不死，十年遇公拜還哭。", "堂堂山西忠勇後，凜凜典刑在眉目。", "總戎南下聊復爾，健虜黠羌要頗牧。", "戈船水犀士扼虎，三江太湖浪翻屋。", "丈夫爲將亦不惡，寂寞揚雄老天祿。"]'),
('c154e68d-f77d-466a-83cb-0dc29fb30029','寒夜擁爐有懷淮上','張耒','宋','宋诗','song-poetry','','[]','長安暮冬雪如山，堅冰錯落於其間。',144,'全唐诗/poet.song.64000.json','["長安暮冬雪如山，堅冰錯落於其間。", "八荒一雲同慘淡，北海怒迴江海翻。", "老人此時不復出，閉戶燃薪守蓬蓽。", "忽憶去年淮上舟，有客致酒頗豪逸。", "三更堂下霜折木，坐上美人鳴寶瑟。", "人生有情亦可憐，明眸皓齒如眼前。", "主人金章作塵土，烟飛星散江南天。", "知非蘧公時一歎，讀書梅叟並蕭然。", "百年萬事費排遣，軟語須問東家禪。"]'),
('a64e8fea-18c3-44e7-90ee-9e721959c38e','同魯直无咎遊啟聖','張耒','宋','宋诗','song-poetry','','[]','西方金仙千歲身，天上伐木役天人。',160,'全唐诗/poet.song.64000.json','["西方金仙千歲身，天上伐木役天人。", "閻浮檀光照世界，作此無量勝妙因。", "九龍寶地赤精宅，湧出宮殿壓風輪。", "化人南來爲守護，震動六種走鬼神。", "錦幪老人常住世，燕坐說法無冬春。", "故人蕭公作塵土，白蓮花葉光如新。", "妙道無邊世眼窄，真心遍通人智貧。", "可憐端居弊宇宙，幾見疑惑談僞真。", "簷牙森森鐵鳳啄，殿顔眈眈金獸蹲。", "官冷何妨近香火，時容絕勝洗埃塵。"]'),
('6b9256a7-4072-4b71-8aad-4428617d1715','送邵郎中守同州','張耒','宋','宋诗','song-poetry','','[]','君不見漢家左輔百萬戶，里胥夜驚厭桴鼓。',99,'全唐诗/poet.song.64000.json','["君不見漢家左輔百萬戶，里胥夜驚厭桴鼓。", "爾來荆棘露沾衣，只有山河閱今古。", "邵侯風流華省郎，三十憑熊兩開府。", "不須閉閣决田訟，多屑石餠羞魚俎。", "東南文章舊人物，莫愧蓴羹便酪乳。", "仍煩細閱白沙龍，驌驦一骨今何所。"]'),
('dd2ae9b3-45e3-46dc-8a88-fc76ec682638','王都尉惠詩求和逾年不報王屢來索而王許酒未送因次其韵以督之','張耒','宋','宋诗','song-poetry','','[]','酸寒杜陵老，痛飲遺身世。',158,'全唐诗/poet.song.64000.json','["酸寒杜陵老，痛飲遺身世。", "雲安小縣麴米春，遙知美味無多子。", "猶令此老氣如虎，傲兀幾以醉爲異。", "爭知侯家美酒如江湖，金鐺犀杓與之俱。", "玉壺曉傾春水决，銀槽夜滴秋雨疏。", "主人文章足賓客，許致麴生來坐側。", "三杯脫帽我家風，渴如旱田占雨虹。", "冷官如瓶君未見，腹惟貯水冰生面。", "鳴鞭走送煩騶轡，坐對朝寒北風起。", "未欲煩公大作醼，老夫自斟看深淺。"]'),
('72abff30-15c7-4bd9-8946-945f5221e92d','架蒲萄','張耒','宋','宋诗','song-poetry','','[]','蒲萄盤屈如修蛇，春來蟄起紓橫斜。',112,'全唐诗/poet.song.64000.json','["蒲萄盤屈如修蛇，春來蟄起紓橫斜。", "延之升架鱗甲動，舊枿粲粲生光華。", "盤堆馬乳未敢望，殷勤灌溉意非他。", "要聽暑雨鳴大葉，窗間致榻圍青紗。", "年來幽淡亦有趣，自值花草占萌芽。", "奔波玄德老不遂，正爾種菜豈不佳。", "猶嫌尚遣兒輩覺，方食失匕徒驚嗟。"]'),
('d0d9b763-7034-4647-8033-70ffc65ad343','敘十五日事','張耒','宋','宋诗','song-poetry','','[]','五更聞鐘自驚起，坐守殘燈具冠履。',160,'全唐诗/poet.song.64000.json','["五更聞鐘自驚起，坐守殘燈具冠履。", "昏昏睡眼正團花，獨愛當庭月如水。", "强驅睡味誰不仁，漠漠黑甜留兩眥。", "忽驚左掖漲風埃，已起上閣鏘環佩。", "平明原廟煥金碧，饑投散幕走寒餌。", "紛紛僕僕酸兩脛，肉食當然賤何事。", "走馬回家百不問，掃榻伸腰真有味。", "起來炊熟日亭午，槐葉新成庭覆翠。", "翻書弄翰老自笑，飽食安眠計難遂。", "古來高士不入城，肯聽鷄鳴踏朝市。"]'),
('8a7f31b2-bba4-44f7-bc87-a0a20e610a6b','淮陰太寧山主崇岳逮與予諸父遊今年七十餘耳目聰明筋力强壯奉戒精苦禪誦不輟聞予自黄歸欣然空所居而相延日與之語或寂然相對終日使人之意消也因賦此詩','張耒','宋','宋诗','song-poetry','','[]','我來之初季春月，門外李花如積雪。',304,'全唐诗/poet.song.64000.json','["我來之初季春月，門外李花如積雪。", "杜門燕坐度長夏，庭樹秋風忽騷屑。", "西馳大火不復燎，急雨凄風爭應節。", "紫貂暴日知有待，畫扇依牆將怨別。", "蒸雲積潦漸收拾，惡木煩蕪稍摧折。", "不知此事誰主張，躍馬奔車忽回轍。", "嗟予行世蹈坎埳，僅免豺狼膏齒舌。", "三年閉戶餓江島，脫粟無餘衣百結。", "近者皇天忽悔禍，雨施雲行咸澡雪。", "復官還職遍海內，爭脫囚冠鳴佩玦。", "老夫龍鍾衆人後，一舸循江信沿涉。", "風波歷盡見故鄉，親友相逢驚白髮。", "道人已老見我喜，靜掃高堂容憩歇。", "佛龕日近得香火，僧飯時容供粗糲。", "讀書小技漫勤苦，安禪大觀無分別。", "久便閑放輕祿利，已脫憂危傲縲紲。", "天時進退古不忒，人事興衰今屢閱。", "酒濃村店足斟酌，魚美長淮恣哺啜。", "從今萬事付天工，致安民庶看夔契。"]'),
('4ea751cb-e98f-420c-8ca0-8c07ba35d2f7','聞子瞻嶺外歸贈邠老','張耒','宋','宋诗','song-poetry','','[]','今晨風日何佳哉，南極老人度嶺來。',64,'全唐诗/poet.song.64000.json','["今晨風日何佳哉，南極老人度嶺來。", "此翁身如白玉樹，已過千百大火聚。", "望天留之付真主，世間毒烈計已誤。", "柯山潘子應鼓舞，與子異時從杖屨。"]'),
('cc61e670-6b97-4aa8-a64d-08a01c8237a5','次韵蘇公武昌西山','張耒','宋','宋诗','song-poetry','','[]','靈均不醉楚人醅，秋蘭蘼蕪堂下栽。',224,'全唐诗/poet.song.64000.json','["靈均不醉楚人醅，秋蘭蘼蕪堂下栽。", "九江仙人棄家去，吳市不知身姓梅。", "東坡先生送二子，一丘便欲藏崔嵬。", "脫遺簪笏玩杖屨，招揖魚鳥營池臺。", "西山寂寥舊風月，百年石樽埋古埃。", "洗樽致酒招浪士，荒墳空餘黄土堆。", "但傳言語古味在，一勺玄酒藏山罍。", "鄧公歎息爲摩撫，重刻文字蒼崖隈。", "五年見盡江上客，兩屐踏遍空山苔。", "謝公富貴知不免，醉眼來爲蒼生開。", "長虹一吐誰得掩，六翮故在何人摧。", "橫翔相與顧鴻雁，寶劍再合張與雷。", "山猿澗鳥汝勿怨，天遣兩公聊一來。", "豈如屈賈終不遇，詩賦長遣後人哀。"]'),
('334e15c9-c2ea-41fb-9333-3ad286e3cd6d','宿譙東逆旅夜聞歌白公琵琶行','張耒','宋','宋诗','song-poetry','','[]','元和才子悲流落，一聽琵琶謂天樂。',128,'全唐诗/poet.song.64000.json','["元和才子悲流落，一聽琵琶謂天樂。", "青衫裛淚作長歌，誰取篇章和宮角。", "譙東夜久行人稀，卧聞此歌歌者誰。", "歌侶舊時人不見，舉頭欲聽淚雙垂。", "畫堂青瑣春無事，幾聽此歌還幾醉。", "東風桃李作黄埃，寶篋塵昏譜閒字。", "一聲一聽一情傷，未老應知幾斷腸。", "展轉曲終燈燼落，荒城寒月夜飛霜。"]'),
('887807ed-5764-4b46-8bd2-1ea0254381ed','趙德麟有詩言過萬壽縣得玉芝乃以供一醉之味按道書凡芝皆神仙上藥無乃輕用之乎','張耒','宋','宋诗','song-poetry','','[]','王孫憔悴食無肉，天遣枯腸出雙玉。',96,'全唐诗/poet.song.64000.json','["王孫憔悴食無肉，天遣枯腸出雙玉。", "荒園夜飲供一醉，仙物無乃遭輕辱。", "王孫高名滿天下，剸膾龍蛟刀几熟。", "眼高不爲小物變，采掇僅同葵薤屬。", "憐君十年清潁客，年少未甘窺藥錄。", "再逢靈藥慎勿輕，不死問君安可獨。"]'),
('fc4bd2f3-dc8d-4989-a66c-d77790613161','東園','張耒','宋','宋诗','song-poetry','','[]','堂中宴坐不妄出，堂外青春去如失。',144,'全唐诗/poet.song.64000.json','["堂中宴坐不妄出，堂外青春去如失。", "小園十步綠如雲，一時桃李事已畢。", "猶有荼蘼數朵在，未覺塵沙污玉質。", "金沙格俗終可憐，膩白嬌紅如欲滴。", "老夫睡起聽山禽，竹間林外紛嘲嘖。", "筍生漸愜子猷願，梅熟未邀朱老喫。", "翻書只作隨睡具，傾壺屢進忘憂物。", "今春風雨稍依節，上田麥穗過數尺。", "但知洗眼看世塗，莫厭終身守蓬蓽。"]'),
('fb5350e5-b119-4ccd-9009-321d75074def','送翟公巽赴中書舍人','張耒','宋','宋诗','song-poetry','','[]','韓筋柳骨世不聞，翟公筆力回千鈞。',192,'全唐诗/poet.song.64000.json','["韓筋柳骨世不聞，翟公筆力回千鈞。", "十年聲名滿四海，淮陽邂逅雙朱輪。", "老翁空疏亦何有，察公於我意甚真。", "高談亹亹雲漢上，一掃闒茸如灰塵。", "夜光明月不計數，坐使衰弊生精神。", "恨無金玉相報答，還家三歎嗟我貧。", "青燈論文夜未分，曉聞門外送使君。", "問君舍此去安往，紫皇詔歸侍玉宸。", "鋒鋩發硎斷犀象，好爲明主裁絲綸。", "論思獻納乃其職，况公之意常在民。", "追還三代舊風采，主以事實致此文。", "聖君賢相有美意，筆端與物爲陽春。"]'),
('4d57bf81-fa54-44a3-870d-8cef82a51549','波稜乃自波陵國來蓋西域蔬也甚能解麵毒予頗嗜之因考本草爲作此篇','張耒','宋','宋诗','song-poetry','','[]','誰從西域移佳蔬，遍植中原葵莧俱。',128,'全唐诗/poet.song.64000.json','["誰從西域移佳蔬，遍植中原葵莧俱。", "清霜嚴雪凍不死，寒氣愈盛方芳敷。", "貫金銳箭脫秋竹，剪羅巧带飄華裾。", "中含金氣抱勁利，穿滌炎熱清煩紆。", "老人食貧貪易得，大釜日煮和甘腴。", "飯炊香白煮餠滑，一飽盡缽無贏餘。", "空厨蕭條烟火冷，可但食客歌無魚。", "男兒五鼎食固美，當念就鑊還愁吁。"]'),
('c1ca3fe9-0252-4990-b842-1805a668086e','北鄰賣餠兒每五鼓未旦即遶街呼賣雖大寒烈風不廢而時略不少差也因爲作詩且有所警示秬秸','張耒','宋','宋诗','song-poetry','','[]','城頭月落霜如雪，樓頭五更聲欲絕。',64,'全唐诗/poet.song.64000.json','["城頭月落霜如雪，樓頭五更聲欲絕。", "捧盤出戶歌一聲，市樓東西人未行。", "北風吹衣射我餠，不憂衣單憂餠冷。", "業無高卑志當堅，男兒有求安得閒。"]'),
('a5498220-5ffa-4daa-a6d6-24a5d77b7378','寄余五十五','張耒','宋','宋诗','song-poetry','','[]','憶昨戊午寄東都，人事紛紛相見疏。',352,'全唐诗/poet.song.64000.json','["憶昨戊午寄東都，人事紛紛相見疏。", "補官洛陽我西走，君理舟楫歸江湖。", "往來相失頃刻爾，坐使一別三年餘。", "他鄉滿眼非故舊，南北耿耿無音書。", "福昌古邦廢已久，莽莽榛棘藏麕鼯。", "空宮蕭條唐舊路，古堞斷續韓遺墟。", "商頑餘民俗未泯，習尚凶獷羞爲儒。", "高堂塵埃坐無客，雖復强接非歡愉。", "嗟君尚復記憶我，兩得書札何勤劬。", "最後新詩意不淺，知君過我山陽居。", "人間翩翩輕薄子，交友暫爾久則渝。", "歡欣憂患心不易，我視一世無君如。", "念昔登科各年少，君中第一名傳呼。", "春風朝遊踏廣陌，夜雨縱飲傾金壺。", "當時意氣今在否，十年我困官庭趨。", "君宜騰達上寥廓，何乃失足遭崎嶇。", "人生難必但如此，付委造物隨所驅。", "得之幾何失未損，七尺可貴惟吾軀。", "洛川春風來已久，桃李次第爭芬敷。", "登臨想君不可見，夢逐流水遊東吳。", "東吳舊遊我所樂，飲有美酒烹有魚。", "何當相逢兩披豁，擺落萬累無嗟吁。"]'),
('35aa7c6b-9e7d-4783-94e0-f1f2f96f77d4','從黄仲閔求友于泉','張耒','宋','宋诗','song-poetry','','[]','炎暑戰已定，清秋當抗衡。',48,'全唐诗/poet.song.64000.json','["炎暑戰已定，清秋當抗衡。", "碧雲生雁思，幽草見蛩情。", "曬麥村墟靜，觀書枕簟清。", "誰能酌玄酒，來破屈原醒。"]'),
('fba91dc0-9788-428d-86b6-25e05d1d1d5e','清洛','張耒','宋','宋诗','song-poetry','','[]','清洛西風急，遙知故國秋。',48,'全唐诗/poet.song.64000.json','["清洛西風急，遙知故國秋。", "羈游成歲月，疏放合淹留。", "地迥驚身老，山高更旅愁。", "登臨有詞賦，不減在荆州。"]'),
('1625194e-2887-42ac-8be2-68e834613f4e','落日','張耒','宋','宋诗','song-poetry','','[]','落日西風急，空山客獨驚。',48,'全唐诗/poet.song.64000.json','["落日西風急，空山客獨驚。", "夕雲寒不動，秋水暮多聲。", "粟厭周人飯，蓴思故國羹。", "南飛有征雁，羨爾羽毛輕。"]'),
('28181dda-fd4b-49e1-9d25-eb36315dadc8','贈陳履常','張耒','宋','宋诗','song-poetry','','[]','勞苦陳夫子，欣聞病肺蘇。',48,'全唐诗/poet.song.64000.json','["勞苦陳夫子，欣聞病肺蘇。", "席門遷次數，僧米乞時無。", "旨蓄親庖急，青錢藥裹須。", "我場方不給，何以縶君駒。"]'),
('7b6132f1-3880-437e-b265-e8a2adddc23f','至安化驛先寄淮陽故人','張耒','宋','宋诗','song-poetry','','[]','蕭條安化驛，倦客思悠哉。',48,'全唐诗/poet.song.64000.json','["蕭條安化驛，倦客思悠哉。", "積水連天闊，青山送客來。", "疏籬風捲葉，敗屋雨生苔。", "寄語淮陽舊，人今放逐回。"]'),
('70526e8b-fa0b-4a0e-8257-965cad6ff757','發金陵折柳亭二首  其一','張耒','宋','宋诗','song-poetry','','[]','綠衮溶溶日，紅飛寂寂春。',48,'全唐诗/poet.song.64000.json','["綠衮溶溶日，紅飛寂寂春。", "青山今古事，芳草去來人。", "歌吹酒家市，帆檣賈客津。", "誰云絕勝地，登眺更傷神。"]'),
('faca78f8-a0bb-46d0-9573-2b182db0c616','發金陵折柳亭二首  其二','張耒','宋','宋诗','song-poetry','','[]','桃李蕃晴日，江山秀晚春。',48,'全唐诗/poet.song.64000.json','["桃李蕃晴日，江山秀晚春。", "孤舟多病客，長道未歸人。", "豪俗競行樂，倦遊慵問津。", "南山還暮雨，疑有楚臺神。"]'),
('efde6b2e-dd04-4a75-8d69-0f3409b58c3e','秋日','張耒','宋','宋诗','song-poetry','','[]','隕葉鳥不顧，枯莖蟲莫吟。',48,'全唐诗/poet.song.64000.json','["隕葉鳥不顧，枯莖蟲莫吟。", "野荒田已穫，江暗夕多陰。", "夜語聞山雨，無眠聽楚砧。", "敝裘還補綻，披拂動歸心。"]'),
('282b080b-a6c7-42b5-806e-e30bae907d49','次韵斯舉送巖桂新釀','張耒','宋','宋诗','song-poetry','','[]','叢桂仙君子，小山幽處芳。',48,'全唐诗/poet.song.64000.json','["叢桂仙君子，小山幽處芳。", "□□□鄙素，漢殿略塗黄。", "有客憐衰病，新醅許撇嘗。", "併將塵外物，助我北窗凉。"]'),
('cb2d51fa-8a98-49e0-abf2-4a5200ac1254','發安州作','張耒','宋','宋诗','song-poetry','','[]','積雨陂塘秀，南風蒿艾肥。',48,'全唐诗/poet.song.64000.json','["積雨陂塘秀，南風蒿艾肥。", "烏犍立橫隴，白鳥下深畦。", "雲木叫杜宇，曉林啼竹雞。", "平生倦遊興，頼有濁醪携。"]'),
('b312999b-d52c-4f93-8afd-00dc001b8b3c','賦得瀑布','張耒','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u534e\u5c71"]','浩浩自太古，洋洋灌百川。',48,'全唐诗/poet.song.64000.json','["浩浩自太古，洋洋灌百川。", "深將一源潤，首出萬峰巔。", "晴浴岱宗日，香通華嶽蓮。", "應有真仙子，揮榜上青天。"]'),
('7ad2bc28-1156-4848-a297-2cd87d90cb37','江城','張耒','宋','宋诗','song-poetry','','[]','江城寒食近，風雨作輕寒。',48,'全唐诗/poet.song.64000.json','["江城寒食近，風雨作輕寒。", "花落已可惜，春衣猶怯單。", "畏人成不出，已老自無歡。", "沽酒金明道，回頭十五年。"]'),
('9c1e551e-d9c6-47ea-b4ea-4fa0838a2ced','都梁亭下','張耒','宋','宋诗','song-poetry','','[]','金塔青冥上，孤城蒼莽中。',48,'全唐诗/poet.song.64000.json','["金塔青冥上，孤城蒼莽中。", "淺山寒带水，旱日白吹風。", "人事劇翻手，生涯真轉蓬。", "高眠待春漲，鮭菜伴南公。"]'),
('31476a40-aa61-4eb2-9623-1d44f7982d79','過孝感縣十里所望一土山下有漁舟呼之不來委舟負魚徑去不顧俄有一舟不待呼自拏舟直前取舟中美魚致之求價甚賤予倍與之值卒辭倍值而去予語之曰爾不待招而赴人之求仁也售不求厚價廉也子豈有道者乎茲楚境也昔有勸屈大夫以餔糟啜醨者豈非子耶爲作一篇','張耒','宋','宋诗','song-poetry','','[]','有道隠屠釣，仁廉非偶然。',48,'全唐诗/poet.song.64000.json','["有道隠屠釣，仁廉非偶然。", "傾筐出紫鱖，揮手謝青錢。", "昔有離騷客，名高楚國賢。", "獨醒遭爾笑，吾幸醉終年。"]'),
('a9f34526-5857-426d-97db-b46415d4c357','二月三日艤舟徐城戲呈戚郎','張耒','宋','宋诗','song-poetry','','[]','自嗟爲客久，羈旅過淮時。',48,'全唐诗/poet.song.64000.json','["自嗟爲客久，羈旅過淮時。", "雪野挑蔬瘦，霜天暖酒遲。", "流年下坡轂，萬事一枰棋。", "異日懷陳迹，孤舟近古祠。"]'),
('9439ddf3-7b8b-4a85-ab1b-b603f55a61e4','重到臨淮壽聖院','張耒','宋','宋诗','song-poetry','','[]','陳迹不可訪，舊游三十年。',48,'全唐诗/poet.song.64000.json','["陳迹不可訪，舊游三十年。", "相逢非故物，大半已沈泉。", "世界揚塵海，浮生不繫船。", "老人無固必，醉即掩篷眠。"]'),
('fbfcdf8d-f071-458a-81a6-f6db0222a4a0','舟中曉思','張耒','宋','宋诗','song-poetry','','[]','樹色未啼鳥，槳聲初度航。',48,'全唐诗/poet.song.64000.json','["樹色未啼鳥，槳聲初度航。", "客燈青映壁，城角冷吹霜。", "飄泊年來甚，羈游情易傷。", "年豐清潁尾，吾計亦差良。"]'),
('eeaf97f0-05a9-4286-a2bf-2142d4c6bae2','將至漢川夜泊','張耒','宋','宋诗','song-poetry','','[]','水翼飛栖定，連檣宿暝烟。',48,'全唐诗/poet.song.64000.json','["水翼飛栖定，連檣宿暝烟。", "葦風驚客夢，江月伴人眠。", "多病閒偏樂，苦吟愁易牽。", "漁郎爾何恨，終夕獨鳴舷。"]'),
('d6699dfc-2a92-406e-99a1-e4e5493d7e32','酬同年徐正夫司戶時欲卜築嵩洛間','張耒','宋','宋诗','song-poetry','','[]','少別老相見，無言空惘然。',48,'全唐诗/poet.song.64000.json','["少別老相見，無言空惘然。", "功名屬多病，詩酒樂衰年。", "釜厭顔公粥，囊須趙壹錢。", "歸裝何日辦，嵩少好林泉。"]'),
('e1039642-3b48-42af-a3d3-a8c506dfef79','何處春深好二首  其一','張耒','宋','宋诗','song-poetry','','[]','何處春深好，春深禪宿家。',48,'全唐诗/poet.song.64000.json','["何處春深好，春深禪宿家。", "茶爐寒夙火，佛案曉添花。", "壞宅無妖火，通途有寶車。", "院深人不到，幡影逐風斜。"]'),
('5f53b8e4-aa7d-44ad-8015-9a1e7fc7890e','何處春深好二首  其二','張耒','宋','宋诗','song-poetry','','[]','何處春深好，春深居士家。',48,'全唐诗/poet.song.64000.json','["何處春深好，春深居士家。", "荒園幾畦菜，環堵數株花。", "自蠟登山屐，仍驅下澤車。", "時時客問字，醉帽任傾斜。"]'),
('1096e29a-8412-4160-bd76-62574a8bfc79','次韵寄趙伯堅二首  其一','張耒','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖望中潬，能有幾多程。',48,'全唐诗/poet.song.64000.json','["西湖望中潬，能有幾多程。", "問訊懶不講，篇章來愈清。", "爲邦循舊政，把酒憶交情。", "祝子過新歲，春風入帝城。"]'),
('94465b6a-41c4-46aa-b03f-db2ecf10dc5f','次韵寄趙伯堅二首  其二','張耒','宋','宋诗','song-poetry','','[]','相思何處望，月閣對南堂。',48,'全唐诗/poet.song.64000.json','["相思何處望，月閣對南堂。", "念子猶記我，懷君時舉觴。", "可能思潁好，端是種花忙。", "閒說河陽政，佳哉副所望。"]'),
('f03143b8-02b6-4ad1-8a38-ff8404d1dae3','陋屋','張耒','宋','宋诗','song-poetry','','[]','陋屋秋霖後，荒城落葉中。',48,'全唐诗/poet.song.64000.json','["陋屋秋霖後，荒城落葉中。", "壞牆朝插菌，幽草晝聞蛩。", "豈是不浪出，直緣無奈慵。", "何勞求季主，吾自了窮通。"]'),
('b6915267-d86a-457a-aa8c-c8de871ec0bd','道旁花','張耒','宋','宋诗','song-poetry','','[]','長夏百草秀，道旁多野花。',48,'全唐诗/poet.song.64000.json','["長夏百草秀，道旁多野花。", "無名自紅紫，有意占年華。", "灼灼照流水，斑斑上古槎。", "中原何日掃，將爾付泥沙。"]'),
('b0a4699b-e6be-4a39-9e1f-086c3eec71c2','寺西閒步','張耒','宋','宋诗','song-poetry','','[]','閭里靜無事，野塘春水生。',48,'全唐诗/poet.song.64000.json','["閭里靜無事，野塘春水生。", "好風時獨立，芳草共閑行。", "閏月遲春候，輕陰弄晚晴。", "鄰炊烟火動，下舍晚鷄鳴。"]'),
('fef9c05f-fc26-4125-8d82-ffa13328aa78','已醒','張耒','宋','宋诗','song-poetry','','[]','已醒厭厭醉，將開灼灼紅。',48,'全唐诗/poet.song.64000.json','["已醒厭厭醉，將開灼灼紅。", "年年到春日，忽忽遇東風。", "暇日如年永，閒愁似酒濃。", "時能將醉眼，天際送飛鴻。"]'),
('3a5dba16-4ad1-4d54-91cb-8b6c9f1967a7','題廬阜官廳壁','張耒','宋','宋诗','song-poetry','','[]','平生山水興，今夜宿東林。',48,'全唐诗/poet.song.64000.json','["平生山水興，今夜宿東林。", "落日樓殿影，西風鐘梵音。", "雲橫山閣迥，雨過虎溪深。", "脚力猶堪在，他年當重尋。"]'),
('0cc0f373-6a27-4528-825a-2963bfbdd162','今早將飲酒聞鶯有感','張耒','宋','宋诗','song-poetry','','[]','蕭條古蘭若，春日等閒斜。',48,'全唐诗/poet.song.64000.json','["蕭條古蘭若，春日等閒斜。", "唧唧初聞燕，怱怱又過花。", "舊遊都似夢，到處即爲家。", "把酒聽鶯處，羈懷感歲華。"]'),
('0f2ae90e-3f1c-4dc4-b45f-60ec02d6b035','破幌','張耒','宋','宋诗','song-poetry','','[]','破幌一點白，卧知千里明。',48,'全唐诗/poet.song.64000.json','["破幌一點白，卧知千里明。", "低窗通雪氣，喬木尚風聲。", "傳警軍城靜，鳴鐘梵剎清。", "高眠尋斷夢，鄰樹已烏驚。"]'),
('27a6e4df-1c88-45a3-903e-a17569907f47','食筍','張耒','宋','宋诗','song-poetry','','[]','荒林春足雨，新筍迸龍雛。',48,'全唐诗/poet.song.64000.json','["荒林春足雨，新筍迸龍雛。", "鄰叟勤致饋，老人欣付厨。", "朝餐甘飽美，放浄爲嗟吁。", "惜取葛陂杖，猶堪代我駒。"]'),
('fe4cf954-4648-450a-a92f-d3075a247f6b','夜意','張耒','宋','宋诗','song-poetry','','[]','每見青桐落，常虞白髮侵。',48,'全唐诗/poet.song.64000.json','["每見青桐落，常虞白髮侵。", "傷心惟片月，不睡更清砧。", "蟋蟀秋聲早，銀河夜色深。", "崎嶇無限意，蕭索一長吟。"]'),
('8835b752-3b91-4cf8-b8d7-32b3f0f84a6f','秋雨','張耒','宋','宋诗','song-poetry','','[]','階下梧桐樹，芳菲亦已休。',48,'全唐诗/poet.song.64000.json','["階下梧桐樹，芳菲亦已休。", "歲時驚病客，風雨送清秋。", "栖鳥歸何晚，鳴蟲響漸收。", "蕭蕭寒色暮，吹作夜深愁。"]'),
('50c8b0d4-ff7c-44ed-b10b-2aca730c8a47','秦兵部書堂','張耒','宋','宋诗','song-poetry','','[]','丈人憐我厚，許與過常情。',48,'全唐诗/poet.song.64000.json','["丈人憐我厚，許與過常情。", "身世已迂闊，功名何敢爭。", "笑談忘晚輩，樽俎罄生平。", "欲斸臨淮地，從公老此生。"]'),
('cdf03666-7690-4ccd-b0d5-9721adb78919','日落','張耒','宋','宋诗','song-poetry','','[]','日落長雲暗，風悲古岸秋。',48,'全唐诗/poet.song.64000.json','["日落長雲暗，風悲古岸秋。", "渚鷗遙避客，野蝶戲隨舟。", "疏拙資微祿，飄零厭遠遊。", "若無尊裏酒，何物與消愁。"]'),
('a3f1c6e5-53a7-4615-86a9-fe92c6ecc56d','晚卧','張耒','宋','宋诗','song-poetry','','[]','日落煩暑退，秋晴河漢明。',48,'全唐诗/poet.song.64000.json','["日落煩暑退，秋晴河漢明。", "微雲映天白，纖月過林清。", "獨卧誰晤語，幽懷殊未平。", "蕭蕭夜深冷，皓露滿前楹。"]'),
('f9f2095f-7114-4867-a9cf-17e4855dc2fb','捲簾','張耒','宋','宋诗','song-poetry','','[]','捲簾新月上，林影散微茫。',48,'全唐诗/poet.song.64000.json','["捲簾新月上，林影散微茫。", "庭草鳴蟲近，風燈秋幌凉。", "長年惟有病，晚歲苦多傷。", "身世竟何就，吾將問蜀莊。"]'),
('096a92b5-3e80-411d-8eae-787054f70d78','秋懷次韵晁應之三首  其一','張耒','宋','宋诗','song-poetry','','[]','木落晚風急，宵凉侵暑衣。',48,'全唐诗/poet.song.64000.json','["木落晚風急，宵凉侵暑衣。", "有期惟向老，無計未成歸。", "只益顛毛脫，還從髀骨肥。", "感時仍弔古，回首意多違。"]'),
('a41a3ccc-33e5-475d-9e0d-d58d2f24e0e4','秋懷次韵晁應之三首  其二','張耒','宋','宋诗','song-poetry','','[]','衰鬢不堪洗，病軀先覺陰。',48,'全唐诗/poet.song.64000.json','["衰鬢不堪洗，病軀先覺陰。", "天寒白日短，歲暮亂山深。", "薄酒醒無力，危弦奏不禁。", "謀身老逾拙，三聽洛陽砧。"]'),
('e56aa5b3-51c7-4d09-b200-e32ac2e6737b','秋懷次韵晁應之三首  其三','張耒','宋','宋诗','song-poetry','','[]','清秋萬里興，力疾上層臺。',48,'全唐诗/poet.song.64000.json','["清秋萬里興，力疾上層臺。", "歲熟雉兔飽，風高榆柳摧。", "晚篁元自綠，幽菊爲誰開。", "寂寞無人問，鄉書久不來。"]'),
('8d134e60-f687-4533-a865-73c34852f2aa','冬至三首  其一','張耒','宋','宋诗','song-poetry','','[]','昨夜新霜落，淮南十月初。',48,'全唐诗/poet.song.64000.json','["昨夜新霜落，淮南十月初。", "寒雲風後白，高木雨來疏。", "功業嗟謀拙，星霜逼歲餘。", "子雲真拙者，寂寞爲玄書。"]'),
('74dfec56-2b1c-46e0-9130-56b6ecf3f891','冬至三首  其二','張耒','宋','宋诗','song-poetry','','[]','汴水日夜淺，天寒霜野寬。',48,'全唐诗/poet.song.64000.json','["汴水日夜淺，天寒霜野寬。", "拂衣秋葉亂，衝面北風寒。", "不作歸山計，空悲走馬鞍。", "濟時吾力薄，俯仰一悲歎。"]'),
('3b3286b0-926f-44f1-8494-e0813c938f9e','冬至三首  其三','張耒','宋','宋诗','song-poetry','','[]','孤衾不成寐，起坐聽雞號。',48,'全唐诗/poet.song.64000.json','["孤衾不成寐，起坐聽雞號。", "樓閉更籌靜，天寒星斗高。", "蕭條陶令酒，清怨楚臣騷。", "凜凜悲秋意，何須待二毛。"]'),
('5766aae8-a6eb-429b-8b3d-ca9ed58c36d2','青陽驛會劉伯聲夜話','張耒','宋','宋诗','song-poetry','','[]','奔走倦塵埃，相逢顔暫開。',48,'全唐诗/poet.song.64000.json','["奔走倦塵埃，相逢顔暫開。", "語闌燈燼改，飲散月華來。", "行役風霜苦，流年歲月催。", "我愚甘自分，惆悵子多才。"]'),
('8386f66e-ee34-4aa9-8336-c43069321997','十二月二十六日旦聞東堂啄木聲忽記作福昌尉時在山間環舍多老木臘後春初此鳥尤多聲態不一今琵琶箏中所效既不類又百不得一二云','張耒','宋','宋诗','song-poetry','','[]','睡餘聞啄木，忽憶福昌春。',48,'全唐诗/poet.song.64000.json','["睡餘聞啄木，忽憶福昌春。", "官舍題詩壁，如今經幾人。", "猶能老耽酒，依舊拙謀身。", "尚想蘭宮路，東風清洛濱。"]'),
('2cd12a29-01ea-4440-91b3-65e75652dfe7','次韵和王彥昭九日湖園會飲','張耒','宋','宋诗','song-poetry','','[]','故人憐寂寞，九日共登臨。',48,'全唐诗/poet.song.64000.json','["故人憐寂寞，九日共登臨。", "天地客行遠，山河秋已深。", "狂來能醉舞，興罷獨悲吟。", "莫怪凄凉甚，多憂損壯心。"]'),
('e3f0c66e-8a98-440b-98a5-e207195c7272','暮春三首  其一','張耒','宋','宋诗','song-poetry','','[]','還將多病眼，冉冉對殘春。',48,'全唐诗/poet.song.64000.json','["還將多病眼，冉冉對殘春。", "啼鳥日求侶，晚花如向人。", "物情懶著意，杯酒最關身。", "亦有功名志，吾生付大鈞。"]'),
('f8d29670-8d52-4a5b-b207-4d75bb593330','暮春三首  其二','張耒','宋','宋诗','song-poetry','','[]','應接非吾事，深幽興有餘。',48,'全唐诗/poet.song.64000.json','["應接非吾事，深幽興有餘。", "筍深鳴鳥下，花薄午風疏。", "草淺見飛雉，溪清生細魚。", "端居亦多趣，不用席門車。"]'),
('a8ea41be-710d-41a1-af93-4d7e5eda526a','暮春三首  其三','張耒','宋','宋诗','song-poetry','','[]','紅點薔薇架，綠深桃李蹊。',48,'全唐诗/poet.song.64000.json','["紅點薔薇架，綠深桃李蹊。", "語鶯知果熟，忙燕聚新泥。", "節物有常態，羈遊無定栖。", "寧須說鵬鷃，物理固應齊。"]'),
('630f5fc8-9548-4203-8756-75a02e64f09a','之天長會宿僧院','張耒','宋','宋诗','song-poetry','','[]','蕭條林下寺，客至解塵鞍。',48,'全唐诗/poet.song.64000.json','["蕭條林下寺，客至解塵鞍。", "雨過月逾白，夜深秋向寒。", "老僧無俗累，愛客故盤桓。", "之子靜相對，松風清石欄。"]'),
('01f2f204-5fea-47bf-8582-e5d357e4693d','宿銅陵','張耒','宋','宋诗','song-poetry','','[]','山色日已遠，問人歸路長。',48,'全唐诗/poet.song.64000.json','["山色日已遠，問人歸路長。", "碧天凉夜闊，秋物雨餘荒。", "人靜路傍寺，鳥啼林下房。", "銅陵竟何就，空死漢吳王。"]'),
('cb91db3b-fd20-46b0-9950-d91c8e8f1a0f','漣水','張耒','宋','宋诗','song-poetry','','[]','孤舟逆水上，野靜聞水聲。',48,'全唐诗/poet.song.64000.json','["孤舟逆水上，野靜聞水聲。", "鷗飛不遠水，寒浪濺霜翎。", "夜氣岸兼木，夕光潭照星。", "長吟弄雙槳，知有睡龍驚。"]'),
('3873f2f4-161d-4b5a-89ec-79f37cdce694','一日復一日','張耒','宋','宋诗','song-poetry','','[]','一日復一日，炎凉行一周。',48,'全唐诗/poet.song.64000.json','["一日復一日，炎凉行一周。", "異鄉猶在望，白髮久生頭。", "且看尋橦技，休懷失馬憂。", "天公有至信，萬古一春秋。"]'),
('62d18d03-fe93-4c90-95bf-bb9a15818543','索莫','張耒','宋','宋诗','song-poetry','','[]','索莫歸未得，閒雲還滿空。',48,'全唐诗/poet.song.64000.json','["索莫歸未得，閒雲還滿空。", "愁吟對寒月，不睡到晨鐘。", "衣喜初冬寄，書憐手自封。", "何當聽夜雪，暖酒夜爐紅。"]'),
('c80cab8f-bf58-4240-9f21-4348dc02d29f','上方僧','張耒','宋','宋诗','song-poetry','','[]','不下上方地，夜禪心慮冥。',36,'全唐诗/poet.song.64000.json','["不下上方地，夜禪心慮冥。", "三更風雪暗，一點佛龕燈。", "持鉢呪潭水，鬼神拳跪聽。"]'),
('05ef2cd2-c6c6-4c21-b37b-8035edbe9e2b','冬夜','張耒','宋','宋诗','song-poetry','','[]','山靜寒雲薄，天空孤月明。',48,'全唐诗/poet.song.64000.json','["山靜寒雲薄，天空孤月明。", "霜桐占階影，風葉繞廊聲。", "經濟心難就，蹉跎歲屢更。", "冥鴻本清遠，何事亦宵征。"]'),
('ce354d89-3077-47c5-a4df-24af14bdd632','和得故人書','張耒','宋','宋诗','song-poetry','','[]','來書纔一紙，離別意何長。',48,'全唐诗/poet.song.65000.json','["來書纔一紙，離別意何長。", "應爲相思苦，還能細作行。", "水浮新恨闊，花想舊容芳。", "欲問人何處，青樓在帝鄉。"]'),
('d5883cd7-6ab5-409d-ae5c-2be5c004001a','和西齋','張耒','宋','宋诗','song-poetry','','[]','山色供開鏡，溪光照掩扉。',48,'全唐诗/poet.song.65000.json','["山色供開鏡，溪光照掩扉。", "暗蟲先夜響，萎葉近秋飛。", "灌壠晴蔬出，開籠暮鶴歸。", "鳴琴坐朗月，輕露點秋衣。"]'),
('6a4f5bec-a96a-40a0-b20b-390ac4145edc','和北寺','張耒','宋','宋诗','song-poetry','','[]','寺倚蒼崖古，僧閒晝掩扉。',48,'全唐诗/poet.song.65000.json','["寺倚蒼崖古，僧閒晝掩扉。", "曉雲辭嶺去，夕鳥占林歸。", "悟理觀旛動，臨風想錫飛。", "寄懷玄觀外，更覺此生微。"]'),
('57eec915-223d-446b-ae62-53e98e868d20','食薇','張耒','宋','宋诗','song-poetry','','[]','歲窮陰不解，短日過牆微。',48,'全唐诗/poet.song.65000.json','["歲窮陰不解，短日過牆微。", "幽鳥穿林小，寒烏啄樹饑。", "冰霜崖嶺壯，烟火井閭稀。", "老拙安閒僻，無心厭食薇。"]'),
('7988d414-6a53-495e-9f04-cac6b3d8f389','春寒','張耒','宋','宋诗','song-poetry','','[]','客舍逢桃李，清樽聊自歡。',48,'全唐诗/poet.song.65000.json','["客舍逢桃李，清樽聊自歡。", "夢中經夜雨，醉裏度春寒。", "草色遠還綠，鳥聲晴更繁。", "預期多病眼，花發更辭看。"]'),
('fc9917a3-4d95-45ba-9de1-2988e4a8f09d','遣悶','張耒','宋','宋诗','song-poetry','','[]','爲問庭前鵲，歸期何太遲。',48,'全唐诗/poet.song.65000.json','["爲問庭前鵲，歸期何太遲。", "舊傳能報喜，東去是何時。", "黄葉西風急，幽花白露滋。", "朝朝清洛水，坎坎只東馳。"]'),
('29d9045f-cc79-49a0-abad-75e910fee8cb','歲暮書事十二首  其一','張耒','宋','宋诗','song-poetry','','[]','歲晏北風疾，山空萬谷號。',48,'全唐诗/poet.song.65000.json','["歲晏北風疾，山空萬谷號。", "木枯隨意折，鴻斷不成高。", "深屋支蓬戶，溫爐煖縕袍。", "老夫原不寐，鳴竹鼓蕭騷。"]'),
('961f5dc1-4cf3-422a-b63e-26a0264bc0d1','歲暮書事十二首  其二','張耒','宋','宋诗','song-poetry','','[]','清洛魚梁淺，霜鱗素鯽肥。',48,'全唐诗/poet.song.65000.json','["清洛魚梁淺，霜鱗素鯽肥。", "供厨調鼎快，充腹此羹稀。", "老去只便飽，年來甘息機。", "寒江鱸鱠美，悵望未成歸。"]'),
('d226284f-8c15-4616-b9f0-d0b00b572050','歲暮書事十二首  其三','張耒','宋','宋诗','song-poetry','','[]','風捲塵沙白，雲垂雪意凝。',48,'全唐诗/poet.song.65000.json','["風捲塵沙白，雲垂雪意凝。", "夜山時叫虎，晚市早收燈。", "園栗炮還美，村醪醉不能。", "三年官况味，真是冷於冰。"]'),
('a8d662c7-e6a0-4f50-ae21-135498e5dfbb','歲暮書事十二首  其四','張耒','宋','宋诗','song-poetry','','[]','牛羊已歸去，殘照滿山陂。',48,'全唐诗/poet.song.65000.json','["牛羊已歸去，殘照滿山陂。", "霜雁田中靜，風鳶木杪悲。", "川原今自若，龍虎昔交馳。", "丘隴耕桑盡，千年不復知。"]'),
('16188023-1d40-4139-8964-bef473073e7c','歲暮書事十二首  其五','張耒','宋','宋诗','song-poetry','','[]','原廟依岡起，傳聞世祖營。',48,'全唐诗/poet.song.65000.json','["原廟依岡起，傳聞世祖營。", "南陽無雊雉，熊耳合投兵。", "霜日蓬原路，天風栢殿聲。", "山川英氣在，不負昔聞名。"]'),
('54100765-256f-4ba3-8183-6dbb4790f7b1','歲暮書事十二首  其六','張耒','宋','宋诗','song-poetry','','[]','北風吹馬疾，石徑上危基。',48,'全唐诗/poet.song.65000.json','["北風吹馬疾，石徑上危基。", "野俎飽貆脯，山爐煮橡糜。", "寒耕敲凍石，獵火上風枝。", "留滯親麋鹿，多慚髮欲絲。"]'),
('bf78fa2a-cefd-4f40-9123-24da40e5cab5','歲暮書事十二首  其七','張耒','宋','宋诗','song-poetry','','[]','壯心常許國，平日討論兵。',48,'全唐诗/poet.song.65000.json','["壯心常許國，平日討論兵。", "天地身將老，山河意欲驚。", "病多緣痛飲，吟苦更傷情。", "斗酒新豐市，何人問馬生。"]'),
('51004890-0f6d-453b-921a-19304aca0f74','歲暮書事十二首  其八','張耒','宋','宋诗','song-poetry','','[]','自昔周人俗，貪庸巧治生。',48,'全唐诗/poet.song.65000.json','["自昔周人俗，貪庸巧治生。", "千金不冠带，一飲起紛爭。", "佩犢攻攘敚，通書爲姓名。", "二南分陝化，寂寞久無聲。"]'),
('602bc0e9-6fcf-4ff7-94ec-da7533cb72db','歲暮書事十二首  其九','張耒','宋','宋诗','song-poetry','','[]','千載傷頑俗，遺風耿未忘。',48,'全唐诗/poet.song.65000.json','["千載傷頑俗，遺風耿未忘。", "陳荒丘擊鼓，魏褊女縫裳。", "遠客防猜嫉，官居備寇攘。", "妻兒怪多喜，清洛有歸艎。"]'),
('bc8c210b-2b92-4b63-b807-60b1d3ef08f4','歲暮書事十二首  其一○','張耒','宋','宋诗','song-poetry','','[]','陳葉不肯墮，凍醪凝未融。',48,'全唐诗/poet.song.65000.json','["陳葉不肯墮，凍醪凝未融。", "寒林晴有影，霜日冷無風。", "許國片心壯，勞生雙鬢蓬。", "功名任愚智，萬事古今同。"]'),
('5f984b5c-bceb-461b-89d6-04311d855979','歲暮書事十二首  其一一','張耒','宋','宋诗','song-poetry','','[]','日落擎明燭，一杯千里心。',48,'全唐诗/poet.song.65000.json','["日落擎明燭，一杯千里心。", "驕兒驚醉舞，山僕怪悲吟。", "谷冷水流急，天昏雲起陰。", "三更何處雁，急急尚哀音。"]'),
('1508baa4-11f2-47db-a2ac-66100a9d4776','歲暮書事十二首  其一二','張耒','宋','宋诗','song-poetry','','[]','雲去暮天迥，雁飛寒夜長。',48,'全唐诗/poet.song.65000.json','["雲去暮天迥，雁飛寒夜長。", "姮娥守孤月，青女恨連霜。", "不寐看銀燭，長吟送羽觴。", "山爐與石鼎，伴我老他鄉。"]'),
('db3c5c8f-15ac-4df2-a51c-4bceae50e33f','宿東魯父居二首  其一','張耒','宋','宋诗','song-poetry','','[]','夕陽低欲盡，春淺色蕭蕭。',48,'全唐诗/poet.song.65000.json','["夕陽低欲盡，春淺色蕭蕭。", "暝色催歸牧，炊烟向晚樵。", "疏星臨水際，遠火隔村橋。", "黯黯柴門夜，栖鴉對寂寥。"]'),
('59455f14-4e22-478d-bb9e-7ed269c47597','宿東魯父居二首  其二','張耒','宋','宋诗','song-poetry','','[]','郡國何時極，羈愁觸處生。',48,'全唐诗/poet.song.65000.json','["郡國何時極，羈愁觸處生。", "望隨天不盡，春共野兼平。", "烟樹淮南闊，漁鹽楚俗輕。", "飄零五年別，歎息鬢毛更。"]'),
('dd30bb22-0094-4c4c-8e06-ac429802869b','淮上夜風','張耒','宋','宋诗','song-poetry','','[]','縣郭初傳柝，船窗已閉篷。',48,'全唐诗/poet.song.65000.json','["縣郭初傳柝，船窗已閉篷。", "星低春野路，月淡夜淮風。", "烟水東南闊，漁鹽吳楚同。", "久遊諳里社，賒酒問鄰翁。"]'),
('4212557e-c2a0-43e1-98e9-e01c4e216fa8','春望','張耒','宋','宋诗','song-poetry','','[]','鳥去晴雲外，帆歸芳草邊。',48,'全唐诗/poet.song.65000.json','["鳥去晴雲外，帆歸芳草邊。", "平淮分綠野，春樹接低天。", "殘枿寒餘燒，新青雨後田。", "年來千里目，容易淚雙懸。"]'),
('9d1211d9-2214-4287-8e47-0b7a1b862f38','村晚','張耒','宋','宋诗','song-poetry','','[]','深塢繁花麗，晴田細逕分。',48,'全唐诗/poet.song.65000.json','["深塢繁花麗，晴田細逕分。", "孤舟春水路，芳草夕陽村。", "暗雀投簷靜，昏鴉集樹喧。", "牛羊自歸晚，燈火掩衡門。"]'),
('9536f6cc-acb1-49c1-919f-18a43ebacf54','夜意','張耒','宋','宋诗','song-poetry','','[]','荒城轉五更，北斗向誰傾。',48,'全唐诗/poet.song.65000.json','["荒城轉五更，北斗向誰傾。", "穴鬭時爭齧，林棲或自驚。", "老來神慮淡，睡足骨毛輕。", "石磬催僧粥，低窗枕畔鳴。"]'),
('4f8fb98f-12b6-47f3-9108-40f838c39ee0','春望','張耒','宋','宋诗','song-poetry','','[]','暖日晴薰草，清淮闊浸天。',48,'全唐诗/poet.song.65000.json','["暖日晴薰草，清淮闊浸天。", "地卑連遠水，城廢入春田。", "目極風燈外，愁懸淚臉邊。", "人生苦多感，花柳自年年。"]'),
('500c0f23-3f1a-4493-98fb-3783618e4a6b','同七兄及崧上人自墳莊還寺','張耒','宋','宋诗','song-poetry','','[]','和風快人意，岸幘晚襟凉。',48,'全唐诗/poet.song.65000.json','["和風快人意，岸幘晚襟凉。", "日落野痕碧，月生淮際光。", "論詩得靈運，靜語屬支郎。", "不是耽閒散，從來懶性長。"]'),
('6f55ecf4-ad67-40c8-bdc5-67c91fccd799','蔡河漲二首  其一','張耒','宋','宋诗','song-poetry','','[]','長河秋雨漲，極目漫難分。',48,'全唐诗/poet.song.65000.json','["長河秋雨漲，極目漫難分。", "潢潦雖無自，龜魚恐有神。", "天寬垂鑒影，風細起龍鱗。", "老去扁舟興，臨流欲問津。"]'),
('1e09a9f9-0022-445f-a7bb-2aa2a01f8989','蔡河漲二首  其二','張耒','宋','宋诗','song-poetry','','[]','渾渾雖未已，浩浩竟東歸。',48,'全唐诗/poet.song.65000.json','["渾渾雖未已，浩浩竟東歸。", "闊處長天近，澄邊一鳥飛。", "西風疏葦亂，斜日遠村微。", "淹泊從吾道，扁舟伴釣磯。"]'),
('3e6e400f-3164-4ef6-a25c-76cc6e1fe256','初秋對雨','張耒','宋','宋诗','song-poetry','','[]','閉戶理殘編，疏慵得自便。',48,'全唐诗/poet.song.65000.json','["閉戶理殘編，疏慵得自便。", "朝凉清病思，秋雨對高眠。", "屋冷深藏燕，槐疏混抱蟬。", "所欣堂下菊，芳意已鮮鮮。"]'),
('111a0dc3-32eb-4c83-bf79-40ce72e5fb16','泊長平晚望','張耒','宋','宋诗','song-poetry','','[]','川隠夷猶棹，春歸杳靄天。',48,'全唐诗/poet.song.65000.json','["川隠夷猶棹，春歸杳靄天。", "翠深交岸樹，綠野望川田。", "漁酒數家市，船檣何處船。", "登臨一回首，無限意茫然。"]'),
('29a9e188-3f3a-4ad3-95d1-f7daa6e41505','發長平','張耒','宋','宋诗','song-poetry','','[]','歸牛川上渡，去翼望中迷。',48,'全唐诗/poet.song.65000.json','["歸牛川上渡，去翼望中迷。", "野水侵官道，春蕪沒斷堤。", "川平雙槳上，天闊一帆西。", "無酒消羈恨，詩成獨自題。"]'),
('d30d47b6-8991-475d-96f9-803a783bce2f','離建雄塗中','張耒','宋','宋诗','song-poetry','','[]','遠水悠悠靜，孤檣裊裊遲。',48,'全唐诗/poet.song.65000.json','["遠水悠悠靜，孤檣裊裊遲。", "草深春已後，麥秀日長時。", "聚語條桑婦，行歌拾穗兒。", "年豐隨處樂，飄泊我何爲。"]'),
('d5d2d7b5-8f57-4f97-be4f-7082322b6ab6','夏日十二首  其一','張耒','宋','宋诗','song-poetry','','[]','過雨芰荷亂，繁陰竹樹多。',48,'全唐诗/poet.song.65000.json','["過雨芰荷亂，繁陰竹樹多。", "雛聲知鳥哺，萍動見魚過。", "細逕饒苔蘚，陰牆引薜蘿。", "角巾從倒側，疏懶欲如何。"]'),
('bab029e5-8310-4482-b5ed-932bd84a0e13','夏日十二首  其二','張耒','宋','宋诗','song-poetry','','[]','蚓壤排晴圃，蝸涎印雨階。',48,'全唐诗/poet.song.65000.json','["蚓壤排晴圃，蝸涎印雨階。", "花鬚嬌带粉，樹角老封苔。", "問字病多忘，過鄰慵却回。", "晚凉還盥櫛，對竹引清杯。"]'),
('bf742175-ad63-4866-9557-b4808e041e10','夏日十二首  其三','張耒','宋','宋诗','song-poetry','','[]','山雨晴來暑，溪雲暗復興。',48,'全唐诗/poet.song.65000.json','["山雨晴來暑，溪雲暗復興。", "林塘陰不解，巾幘潤還蒸。", "書帙慵披蠹，盤餐厭撲蠅。", "老來疲薾甚，多病日侵陵。"]'),
('033445ea-09f3-4f20-9b70-78d213069c4a','夏日十二首  其四','張耒','宋','宋诗','song-poetry','','[]','朝雨來還密，村墟一望間。',48,'全唐诗/poet.song.65000.json','["朝雨來還密，村墟一望間。", "遠聲惟野竹，潤色但青山。", "書史供高卧，莓苔只閉關。", "蕭蕭覺秋興，飄颯近衰顔。"]'),
('f231da69-d7e6-4f7f-b21e-cd07145c3395','夏日十二首  其五','張耒','宋','宋诗','song-poetry','','[]','細逕依原僻，蓬蒿四五家。',48,'全唐诗/poet.song.65000.json','["細逕依原僻，蓬蒿四五家。", "山田來雉兔，溪雨熟桑麻。", "竹籠晨收果，茅庵夜守瓜。", "頗知農事樂，彼此問生涯。"]'),
('59deebba-4762-4df4-ab82-ce69888b6230','夏日十二首  其六','張耒','宋','宋诗','song-poetry','','[]','養拙貧無事，深幽樂更真。',48,'全唐诗/poet.song.65000.json','["養拙貧無事，深幽樂更真。", "簷巢偷哺子，樹啄巧藏身。", "竊果鶯知主，移居蟻過鄰。", "老夫朝食美，薦俎有溪鱗。"]'),
('334084ed-6c21-403a-a50a-a69066f74ec2','夏日十二首  其七','張耒','宋','宋诗','song-poetry','','[]','謝守常搜句，陶潜亦效官。',48,'全唐诗/poet.song.65000.json','["謝守常搜句，陶潜亦效官。", "傍溪分水細，過巘得天寬。", "布種隨蔬隴，尋香到藥欄。", "野裝兒稚笑，繩屨鹿衣冠。"]'),
('9001a2fa-448f-4e55-89ad-8e8a058be9b4','夏日十二首  其八','張耒','宋','宋诗','song-poetry','','[]','久與山川約，那無風月情。',48,'全唐诗/poet.song.65000.json','["久與山川約，那無風月情。", "經營原闊略，疏放自平生。", "山友招相見，鄉書向遠征。", "殷勤語歸計，貧苦病難成。"]'),
('94fd57b0-cf13-4e04-b1fe-d04c36026441','夏日十二首  其九','張耒','宋','宋诗','song-poetry','','[]','種藥幽人事，還披本草經。',48,'全唐诗/poet.song.65000.json','["種藥幽人事，還披本草經。", "出山拋舊翠，過雨有新青。", "術受壺中秘，方傳肘後靈。", "不辭勤服餌，爲變髮星星。"]'),
('cb5f4d3a-3b36-46c2-9d95-1f9a999f62b7','夏日十二首  其一○','張耒','宋','宋诗','song-poetry','','[]','陶令拋官易，龐公去隠深。',48,'全唐诗/poet.song.65000.json','["陶令拋官易，龐公去隠深。", "由來浮世事，可見昔人心。", "卜築閒多思，奔馳病不禁。", "簷楹來燕雀，鸞鶴自山林。"]'),
('4ed32bba-4c17-4c2e-822f-c82a013aa7fd','夏日十二首  其一一','張耒','宋','宋诗','song-poetry','','[]','蛩怨青莎老，螢飛秋水深。',48,'全唐诗/poet.song.65000.json','["蛩怨青莎老，螢飛秋水深。", "庭除延夜色，砧杵發秋心。", "雄劍鳴初匣，寒衣補硬針。", "老來詞賦懶，從使二毛侵。"]'),
('4b5f206b-4f46-429d-83f9-339ee768e69b','夏日十二首  其一二','張耒','宋','宋诗','song-poetry','','[]','夜色川原合，秋聲草木催。',48,'全唐诗/poet.song.65000.json','["夜色川原合，秋聲草木催。", "星辰隨地闊，河漢寫山來。", "栖鶴凉先警，饑烏夕未回。", "高樓對斜月，鳴笛正清哀。"]'),
('96cdb3ee-e0b1-405b-bbdf-c8878c839b38','宿故濟陽城','張耒','宋','宋诗','song-poetry','','[]','夜色蕭條寺，天寒老病身。',48,'全唐诗/poet.song.65000.json','["夜色蕭條寺，天寒老病身。", "空村惟有雪，遠道更無人。", "不寐依爐暖，多愁頼酒醇。", "遙思雙鳳闕，雨露已先春。"]'),
('116bc0d9-0308-4a08-9837-eed93db0b496','早秋感懷','張耒','宋','宋诗','song-poetry','','[]','永日付悠悠，年華逝不留。',48,'全唐诗/poet.song.65000.json','["永日付悠悠，年華逝不留。", "風聲送殘暑，雲色淡新秋。", "吾道倘有待，窮通寧遽憂。", "朝來望清潁，一雁下汀洲。"]'),
('9bcf1315-eee7-4a2e-adb3-19c313b5ef9c','庚辰臘八日大雪二首  其一','張耒','宋','宋诗','song-poetry','','[]','平生臘八日，借鉢受齋糜。',48,'全唐诗/poet.song.65000.json','["平生臘八日，借鉢受齋糜。", "客路歲將晚，旅庖晨不炊。", "持杯從破律，遣興自吟詩。", "何日依禪宿，鐘魚自有時。"]'),
('42bdda39-9fa1-4896-bb09-abcd8e7269d3','庚辰臘八日大雪二首  其二','張耒','宋','宋诗','song-poetry','','[]','東州逢臘雪，却憶竟陵梅。',48,'全唐诗/poet.song.65000.json','["東州逢臘雪，却憶竟陵梅。", "客路人方遠，天涯雁欲回。", "遙憐簷外白，還點砌邊苔。", "久是無人過，誰知照酒杯。"]'),
('5e11e76d-4c35-4bf6-9052-9c1f79f6a1f4','蒙恩除奉常有感','張耒','宋','宋诗','song-poetry','','[]','平生秉周禮，投老奉龍旗。',48,'全唐诗/poet.song.65000.json','["平生秉周禮，投老奉龍旗。", "斥逐偶不死，歸來敢恨遲。", "門闌走賓客，行李飭妻兒。", "又踏長安道，多慚鬢有絲。"]'),
('5bb3f5b8-97a7-4c0c-961c-9e0fe69d08f4','建平途次','張耒','宋','宋诗','song-poetry','','[]','野橋田徑滑，官路柳條新。',48,'全唐诗/poet.song.65000.json','["野橋田徑滑，官路柳條新。", "流水伴麗日，野花留晚春。", "點空知去翼，衝綠有歸人。", "自笑諳岐路，無勞更問津。"]'),
('8a4d3cc9-380d-4353-a632-d7ad835dbd52','白沙阻風','張耒','宋','宋诗','song-poetry','','[]','春江風易惡，故作客行難。',48,'全唐诗/poet.song.65000.json','["春江風易惡，故作客行難。", "晴日開野色，朝寒醒醉顔。", "歸人出斷岸，去翼復前山。", "淹泊無誰語，村翁亦往還。"]'),
('309cbb4d-8a02-416d-86e7-08d0e60a441c','冬日雜興六首  其一','張耒','宋','宋诗','song-poetry','','[]','小園晴自掃，曝日坐前軒。',48,'全唐诗/poet.song.65000.json','["小園晴自掃，曝日坐前軒。", "野鼠穿山葉，寒烏啄草根。", "短籬藩隙地，別逕入孤村。", "幽趣供岑寂，淹留不復論。"]'),
('9bd2e3c7-13c4-495f-8280-54b43935a105','冬日雜興六首  其二','張耒','宋','宋诗','song-poetry','','[]','水落橋痕在，沙乾岸草枯。',48,'全唐诗/poet.song.65000.json','["水落橋痕在，沙乾岸草枯。", "霜餘槐老壯，風際竹清疏。", "啄木高逾響，鶺鴒飛且呼。", "二年親友絕，惟有對禽魚。"]'),
('9e22ee3b-cad1-47d1-adb3-3b27b3a97698','冬日雜興六首  其三','張耒','宋','宋诗','song-poetry','','[]','池館留餘雪，西山照夕曛。',48,'全唐诗/poet.song.65000.json','["池館留餘雪，西山照夕曛。", "臘催梅蕊迸，春向鳥聲新。", "愁思供多病，風光欲近人。", "年年桃李樹，相對只傷神。"]'),
('ab67ec59-489a-4333-810f-b0ebe98f7101','冬日雜興六首  其四','張耒','宋','宋诗','song-poetry','','[]','空山身欲老，徂歲臘還來。',48,'全唐诗/poet.song.65000.json','["空山身欲老，徂歲臘還來。", "愁怯年年柳，傷心處處梅。", "綠蔬挑甲短，紅蠟點花開。", "冰雪知何有，東風日夜回。"]'),
('0108af7f-1e6a-48aa-8e79-0ffee5a6c97b','冬日雜興六首  其五','張耒','宋','宋诗','song-poetry','','[]','南壁蒼崖壯，窮冬井落閒。',48,'全唐诗/poet.song.65000.json','["南壁蒼崖壯，窮冬井落閒。", "風聲先老樹，日色避諸山。", "落雁饑相向，啼烏夕自還。", "微微寒月影，蓬戶已深關。"]'),
('05eba030-677b-4229-940f-6c79872aedae','冬日雜興六首  其六','張耒','宋','宋诗','song-poetry','','[]','擊柝山城閉，疏燈野店扃。',48,'全唐诗/poet.song.65000.json','["擊柝山城閉，疏燈野店扃。", "疾風鳴夜谷，晴水動浮星。", "霜翼歸何晚，鄰機織未停。", "短歌時自和，愁絕更誰聽。"]'),
('4814f416-7936-4c08-987c-badd50745de3','哲宗皇帝挽詞四首  其一','張耒','宋','宋诗','song-poetry','','[]','端拱循堯道，無爲十六年。',48,'全唐诗/poet.song.65000.json','["端拱循堯道，無爲十六年。", "偏師擒頡利，上將勒燕然。", "夢損周王壽，丹催黄帝仙。", "凄凉舊載筆，慟哭抱殘編。"]'),
('697dafc3-d81d-41df-950b-5d4fc7b7b31e','哲宗皇帝挽詞四首  其二','張耒','宋','宋诗','song-poetry','','[]','秦地蟠螭紐，細陽玉象光。',48,'全唐诗/poet.song.65000.json','["秦地蟠螭紐，細陽玉象光。", "升歌陳備樂，信史記多祥。", "奪邑公無怨，開邊義侮亡。", "威靈對三后，常在白雲鄉。"]'),
('7189544a-a3a4-4777-b4de-30e84fd81c36','哲宗皇帝挽詞四首  其三','張耒','宋','宋诗','song-poetry','','[]','萬世興王業，千年極治辰。',48,'全唐诗/poet.song.65000.json','["萬世興王業，千年極治辰。", "澤丘還北祭，玉檢議東巡。", "汗竹人間事，因山地下春。", "雲天不可望，髯斷泣遺臣。"]'),
('90aa0c44-bfc5-457d-9413-9d4ed152cba0','哲宗皇帝挽詞四首  其四','張耒','宋','宋诗','song-poetry','','[]','七月宮車駕，西陵觀闕新。',48,'全唐诗/poet.song.65000.json','["七月宮車駕，西陵觀闕新。", "風雲悲厚夜，羽衛異時巡。", "落月低金爵，秋蕪暗石麟。", "威靈凜如在，善繼有天倫。"]'),
('4af036e8-9fe9-43af-ad38-f07ed4c20c2c','故僕射司馬文正公挽詞四首  其一','張耒','宋','宋诗','song-poetry','','[]','黼座方恭點，邦家付老臣。',48,'全唐诗/poet.song.65000.json','["黼座方恭點，邦家付老臣。", "頌歌民一口，形勢國千鈞。", "富庶新田里，忠臣舊搢紳。", "裴公恨不早，丘禱歎無神。"]'),
('45122cd9-56fb-461f-888c-3944bf0cae99','故僕射司馬文正公挽詞四首  其二','張耒','宋','宋诗','song-poetry','','[]','辭爵浮雲外，安民反手中。',48,'全唐诗/poet.song.65000.json','["辭爵浮雲外，安民反手中。", "山林獨往意，衮繡太平功。", "布被終身儉，貂冠一命崇。", "他年兩行淚，碑下泣羊公。"]'),
('2955d44d-6bf5-414a-a1d0-4da092ecc6b4','故僕射司馬文正公挽詞四首  其三','張耒','宋','宋诗','song-poetry','','[]','經濟心猶壯，清羸疾易傷。',48,'全唐诗/poet.song.65000.json','["經濟心猶壯，清羸疾易傷。", "那知兩楹奠，遽失萬夫望。", "家有詩書積，墳無金玉藏。", "誰知幅巾斂，曾佩上公章。"]'),
('8c3e8610-6f53-4cc5-b85b-73422b8d19da','故僕射司馬文正公挽詞四首  其四','張耒','宋','宋诗','song-poetry','','[]','伊洛平生興，園林獨樂居。',48,'全唐诗/poet.song.65000.json','["伊洛平生興，園林獨樂居。", "曾過鄭公里，得御李膺車。", "華屋當年客，名山異代書。", "定知傳不朽，埋玉自沾裾。"]'),
('86ea9b5f-f1b2-4335-8133-9ca61e516f4b','欽慈皇后挽詞二首  其一','張耒','宋','宋诗','song-poetry','','[]','疇昔熙寧盛，遠同麟趾時。',48,'全唐诗/poet.song.65000.json','["疇昔熙寧盛，遠同麟趾時。", "內敦勤儉德，陰輔太平基。", "餘烈光彤史，追榮備母儀。", "遺民懷永裕，簫鼓不勝悲。"]'),
('69ba6342-579a-4932-aa1f-cd6ed594ed6b','欽慈皇后挽詞二首  其二','張耒','宋','宋诗','song-poetry','','[]','淑德承明舊，徽音固有來。',48,'全唐诗/poet.song.65000.json','["淑德承明舊，徽音固有來。", "據龍符聖嗣，合劍會軒臺。", "玉冷衣銷馥，鸞昏鏡集埃。", "傷心國西道，寂寞送車回。"]'),
('2b2d0ea4-aa4a-483d-8362-7fa6d2fb7db2','挽黄幾道','張耒','宋','宋诗','song-poetry','','[]','異政潁川鳳，遺風叔度陂。',48,'全唐诗/poet.song.65000.json','["異政潁川鳳，遺風叔度陂。", "聞哀苦朋友，歸葬束書詩。", "百歲鄉人社，他年故吏碑。", "知公萬金産，故在阿戎兒。"]'),
('2c244843-d1b3-4d89-8936-15b1ea74e335','范參軍挽詞','張耒','宋','宋诗','song-poetry','','[]','力學志不就，多才宦可嗟。',48,'全唐诗/poet.song.65000.json','["力學志不就，多才宦可嗟。", "生平叔知己，身後婦成家。", "溫洛新阡茂，東吳慶系賒。", "功名付兒子，文史舊生涯。"]'),
('a28cc705-47ef-44ed-afb8-3ff91d7fd33e','任左藏挽詞','張耒','宋','宋诗','song-poetry','','[]','人也隠君子，一官聊自閒。',48,'全唐诗/poet.song.65000.json','["人也隠君子，一官聊自閒。", "誰能學管庫，竟爾死茅菅。", "良璞不易剖，大弨終不彎。", "惟應太史錄，他日出名山。"]'),
('e8d676ce-53b5-4565-9c9d-20b9fef13312','張夫人挽詞','張耒','宋','宋诗','song-poetry','','[]','世德簪纓貴，家風孝友傳。',48,'全唐诗/poet.song.65000.json','["世德簪纓貴，家風孝友傳。", "承夫知不忌，愛子故親賢。", "飄忽人間夢，生平物外緣。", "諸天清浄報，可但閟重泉。"]'),
('422c13c0-2908-4e5a-83d3-7ef21ace0be9','呂郡君挽詞','張耒','宋','宋诗','song-poetry','','[]','表海東侯長，分吳異姓王。',48,'全唐诗/poet.song.65000.json','["表海東侯長，分吳異姓王。", "世家端作合，華裔遠相望。", "龍去孤神劍，雛成九鳳凰。", "多情潘散騎，悼逝足文章。"]'),
('9094d9a9-d105-4648-b6a9-3b09151eab48','太府李萃卿挽詞','張耒','宋','宋诗','song-poetry','','[]','妙譽馳場屋，家風在搢紳。',48,'全唐诗/poet.song.65000.json','["妙譽馳場屋，家風在搢紳。", "使華推厚德，卿月上通津。", "齒德時方重，山丘迹已陳。", "長年先友淚，懷感獨沾巾。"]'),
('dfb62416-7da7-48f2-ac62-f2144a5b447e','太皇太后挽詞','張耒','宋','宋诗','song-poetry','','[]','共政艱難際，臨朝保佑初。',48,'全唐诗/poet.song.65000.json','["共政艱難際，臨朝保佑初。", "經綸付耆老，利澤到樵漁。", "禮盛謙常抑，功成委不居。", "聖君深致孝，盡守典刑餘。"]'),
('4847c777-c21e-4444-9bb4-1d2d17f6d63e','李處道都曹丈挽詞','張耒','宋','宋诗','song-poetry','','[]','凄凉正始後，尚復有斯人。',48,'全唐诗/poet.song.65000.json','["凄凉正始後，尚復有斯人。", "慟哭亦云已，傷心難重陳。", "傳家雙令器，懷德萬遺民。", "尚想典刑在，蕭然老鶴身。"]'),
('b2328e19-8fcd-4a6f-9802-56e1102f08a5','欒提舉妻石氏挽詞','張耒','宋','宋诗','song-poetry','','[]','和敬承夫順，勤劬教子賢。',48,'全唐诗/poet.song.65000.json','["和敬承夫順，勤劬教子賢。", "平生積浄業，倉卒歎無年。", "孤劍留耿介，九雛誰撫憐。", "塵埃舊脂澤，春草掩新阡。"]'),
('0bebd473-eb93-4b9f-a715-af17711128ba','鄧學士慎思挽詞','張耒','宋','宋诗','song-poetry','','[]','清苦吟詩客，癯羸嗜學身。',48,'全唐诗/poet.song.65000.json','["清苦吟詩客，癯羸嗜學身。", "詩書不得力，鬼物定欺人。", "類物傳遺學，經書植妙因。", "九原誰與友，千載葬魚臣。"]'),
('59134c6b-bbc2-4b18-b1dd-e843aced4d28','潘鯁奉議挽詞','張耒','宋','宋诗','song-poetry','','[]','廉退辭榮早，清貧卜吉遲。',48,'全唐诗/poet.song.65000.json','["廉退辭榮早，清貧卜吉遲。", "買山新兆域，從窆舊書詩。", "松菊留三徑，簞瓢遺兩兒。", "升堂舊賓客，執紼涕交頤。"]'),
('a762582c-0db5-4981-a305-ea8c33396ac6','哭蔡彥規二首  其一','張耒','宋','宋诗','song-poetry','','[]','青衫未白首，已歎掩新阡。',48,'全唐诗/poet.song.65000.json','["青衫未白首，已歎掩新阡。", "哭別自今日，書來纔去年。", "功因鐘鼎記，名頼友朋傳。", "平昔圍棋笑，臨枰更泫然。"]'),
('448f5620-e0b6-4772-9799-0b1dc36213c4','哭蔡彥規二首  其二','張耒','宋','宋诗','song-poetry','','[]','文章不用世，淪落掩山阿。',48,'全唐诗/poet.song.65000.json','["文章不用世，淪落掩山阿。", "命也人無奈，悲哉天謂何。", "至交嗟我少，雙淚爲君多。", "遙想山陽墓，秋風吹薜蘿。"]'),
('f1219e1e-8840-47b2-a6f9-9c2e7e8d5414','李少卿挽詞','張耒','宋','宋诗','song-poetry','','[]','青雲舊馳譽，白髮早辭榮。',48,'全唐诗/poet.song.65000.json','["青雲舊馳譽，白髮早辭榮。", "談笑惟詩酒，交遊盡老成。", "支離病中見，瀟洒舊時情。", "已矣不可問，九原松柏聲。"]'),
('65b1def7-b51b-4bd0-a945-109eaea28764','歲暮即事寄子由先生','張耒','宋','宋诗','song-poetry','','[]','歲暮淮陽客，貧閒兩有餘。',240,'全唐诗/poet.song.65000.json','["歲暮淮陽客，貧閒兩有餘。", "朝昏面壁坐，風雪閉門居。", "老去深依佛，年衰更嗜書。", "未能忘素業，聊用慰窮途。", "下里皆平屋，開門即古墟。", "雞豚來近舍，舂汲頼鄰夫。", "雪壓移來竹，霜萎自種蔬。", "烏皮蒙燕几，褐帽裹僧顱。", "肉似聞韶客，齋如持律徒。", "女寒愁粉黛，男窘補衣裾。", "已病藥三暴，辭貧飯一盂。", "長瓶卧牆角，短褐倒天吳。", "宵寐衾鋪鐵，晨炊米數珠。", "木鑱隨杜脛，葛製暖韓軀。", "時命今如此，功名已矣乎。", "談愁風射馬，拙待兔逢株。", "久慕香城樂，深諳夢境虛。", "誰憐九頓首，正有一長吁。", "瞻望身空老，蒼茫歲欲除。", "何當聞妙誨，黥刖待完膚。"]'),
('1b3c58cd-6ddb-40e6-b399-44a91792ec12','用歐陽文忠韵雪詩','張耒','宋','宋诗','song-poetry','','[]','密雪當殘臘，衝風到蓽門。',120,'全唐诗/poet.song.65000.json','["密雪當殘臘，衝風到蓽門。", "洒窗驚紙濕，入竹覺聲繁。", "天闊飄無界，城高積有痕。", "氣和歸麥隴，水味到茶軒。", "廣陌無遊騎，空郵有滯轅。", "炎爐聊自暖，濁酒僅能溫。", "野迥征鞍設，邊寒塞甲屯。", "振奇歌歷歷，迴袖舞蹲蹲。", "客至須駝褐，相逢頼酒樽。", "晴明占草木，春意到閒園。"]'),
('1d059884-362a-41fe-8090-7fc846876be7','題譙東魏武帝廟','張耒','宋','宋诗','song-poetry','','[]','草昧羣龍鬭，英雄接上游。',120,'全唐诗/poet.song.65000.json','["草昧羣龍鬭，英雄接上游。", "吳卑青蓋伏，蜀陋葆車留。", "挾漢臨諸夏，中原半九州。", "人驚呂布縛，誰信本初憂。", "天作西南限，時方割據秋。", "力終回赤壁，功止霸諸侯。", "歷數知歸禹，乾坤正造周。", "事商完夙志，傳子豈人謀。", "銅雀佳人恨，西陵拱木秋。", "千年故鄉廟，歌舞薦牢羞。"]'),
('dd310a41-8bf5-40c9-807a-5db937157e44','過衛真太清宮追懷章聖皇帝遊幸之盛小臣斐然成韵','張耒','宋','宋诗','song-poetry','','[]','鳳歷開三葉，中原正偃兵。',144,'全唐诗/poet.song.65000.json','["鳳歷開三葉，中原正偃兵。", "端居思道妙，順動展精神。", "函谷傳經後，渦陽舊宅新。", "龍蟠泉不竭，丹養檜長生。", "鸞鶴迎黄屋，烟霞避翠旌。", "琳瑯千佩玉，貔虎萬屯營。", "邃殿仙容儼，靈庭盛禮行。", "書留河上語，碑勒大夫名。", "歌罷秋風晚，弓遺藥鼎成。", "句陳嚴舊寢，輦道接新耕。", "日落重樓影，天寒暮鳥聲。", "異時懷往事，千古有餘情。"]'),
('3604810c-37ce-46a8-ae7d-d7a936915c17','天慶觀三色檜','張耒','宋','宋诗','song-poetry','','[]','聚處歲寒物，生爲千歲身。',72,'全唐诗/poet.song.65000.json','["聚處歲寒物，生爲千歲身。", "柯條雖自異，臭味本相親。", "商季諸公子，茅家賢弟昆。", "分驅衆彭惡，各共一清真。", "竽籟風中合，鱗鰭雨後伸。", "高枝如借便，輕舉豈無人。"]'),
('5e04d33e-dc41-47f8-a345-3d3c84f1a980','八月三日舟行自蔡河赴臨淮','張耒','宋','宋诗','song-poetry','','[]','曠野天垂地，川晴水見沙。',72,'全唐诗/poet.song.65000.json','["曠野天垂地，川晴水見沙。", "河回迷向背，岸斷忽桑麻。", "水闊時浮鷺，陂寒乍集鴉。", "年饑田濩落，歲晚客悲嗟。", "新月排雲水，西風送日斜。", "孤舟何處宿，故國已天涯。"]'),
('9c1519dc-c371-4613-9d8e-5c17a8b82951','舟行即事二首  其一','張耒','宋','宋诗','song-poetry','','[]','古岸生微靄，空林挂夕陽。',72,'全唐诗/poet.song.65000.json','["古岸生微靄，空林挂夕陽。", "霞輝明野色，天影戰波光。", "集鳥村墟暗，鳴蟲禾黍荒。", "秋高孤月靜，天末巧雲長。", "沙晚橫歸艇，川晴列去檣。", "登臨自多感，何必寄他鄉。"]'),
('f27c3953-5be7-46ff-9943-a81735bcff4e','舟行即事二首  其二','張耒','宋','宋诗','song-poetry','','[]','去去路日遠，行行歲向深。',72,'全唐诗/poet.song.65000.json','["去去路日遠，行行歲向深。", "晚田荒更闊，秋野曉多陰。", "岸蓼飛寒蝶，汀沙戲水禽。", "迎風蘆顫葉，眩日棗裝林。", "早蟹肥堪薦，村醪濁可斟。", "不勞頻悵望，處處有鳴砧。"]'),
('a8f9952d-df75-4c49-8bab-f72108dc855a','發崔橋','張耒','宋','宋诗','song-poetry','','[]','野麥平蕪隴，官榆卧古津。',72,'全唐诗/poet.song.65000.json','["野麥平蕪隴，官榆卧古津。", "眠鷗沙上曉，幽草水邊春。", "暖葉生浮綠，風漪起細鱗。", "青新桑媼筥，茜浄浣娘裙。", "有客悲芳芷，無人採白蘋。", "可憐千里目，愁殺未歸人。"]'),
('761d0cfa-7eeb-4f88-84d1-8a3024daa3b0','和柳郎中山谷寺翠光亭長韵','張耒','宋','宋诗','song-poetry','','[]','山深疑路斷，古寺忽開門。',216,'全唐诗/poet.song.65000.json','["山深疑路斷，古寺忽開門。", "喬木風霜急，荒崖雲雨痕。", "朝霞明翠靄，秋雨濯嵐昏。", "幽鳥不避客，閒雲時入軒。", "重蘿深更綠，碧澗淺無渾。", "寶地黄金布，飛泉白玉噴。", "庭閒卧馴鹿，果熟引王孫。", "禪靜石爲室，客迷桃滿園。", "每悲塵世幻，方信梵王尊。", "野實饑堪薦，陽崖冬自溫。", "便當安寂寞，何事走歊煩。", "清梵晨齋啟，高松夜枕喧。", "逢人休問道，得意已忘言。", "直指曹溪路，勞將貝葉翻。", "功名歎不偶，歲月去如奔。", "久分疏軒冕，寧辭友玃猿。", "從容巖客話，粗糲野僧飧。", "即是平生樂，心期何日論。"]'),
('977703a7-0775-4d70-899e-41c4282581bf','訪曇上人有感','張耒','宋','宋诗','song-poetry','','[]','上人稀出入，黄葉閉門深。',96,'全唐诗/poet.song.65000.json','["上人稀出入，黄葉閉門深。", "繫馬長林下，逢僧古殿陰。", "相逢成底事，乘興偶來尋。", "靜境亦何有，無言知祖心。", "生平避浮俗，與物苦差參。", "脫去猶未得，塵埃嗟滯淫。", "長廊秋日薄，古木野霜侵。", "徙倚誰晤語，獨歸還獨吟。"]'),
('b8e7358e-8041-4fa9-ab6d-52ddf36bdd98','夜吟','張耒','宋','宋诗','song-poetry','','[]','簾捲凉侵戶，窗虛月過帷。',72,'全唐诗/poet.song.65000.json','["簾捲凉侵戶，窗虛月過帷。", "高桐清露濕，深柳夜蟬嘶。", "斷績銀河轉，欹斜斗柄移。", "風來高葉報，伏近候蟲知。", "陶令尊無酒，潘生鬢有絲。", "將何慰愁寂，倚杖獨題詩。"]'),
('d64a736e-391e-4c6e-b127-fd0364f5b7b4','斜日二首  其一','張耒','宋','宋诗','song-poetry','','[]','斜日歸錢暑，秋容淡太虛。',72,'全唐诗/poet.song.65000.json','["斜日歸錢暑，秋容淡太虛。", "閒雲工變易，片月自清孤。", "淹泊年華老，凄凉歲事餘。", "時違自樸拙，興懶日蕭疏。", "阮籍慵耽酒，文園病著書。", "簪纓非草野，江海得樵漁。"]'),
('050528ae-74f8-45f9-a3c8-b2e69c39706e','斜日二首  其二','張耒','宋','宋诗','song-poetry','','[]','伏盡金纔壯，天高火欲流。',96,'全唐诗/poet.song.65000.json','["伏盡金纔壯，天高火欲流。", "病悰拋酷暑，詩興得高秋。", "晝靜塵埃少，宵凉河漢浮。", "青傷桐葉膩，爽奪蕙蘭柔。", "晚歲寒將屆，羣芳葉不收。", "幽人多感慨，啼鴂助騷愁。", "病懶非高卧，疏迂却自由。", "功名與世事，擺落醉鄉遊。"]'),
('a99faca6-f056-40ee-a74b-3d487fc792ef','歲暮獨酌書事奉懷晁永寧','張耒','宋','宋诗','song-poetry','','[]','天涯催晚歲，殘律去如奔。',168,'全唐诗/poet.song.65000.json','["天涯催晚歲，殘律去如奔。", "入夜北風惡，多陰寒日昏。", "野吹餘燒燼，溪落舊沙痕。", "霜重饑鷹疾，田空宿雁喧。", "山明千筍直，雲積萬營屯。", "足雨耕犂早，豐年柿栗繁。", "地平秦接席，土斷洛開門。", "白首三年客，黄桑數畝村。", "懶梳悲髮短，不寐守爐溫。", "折骨披殘枿，蒼龍卧老根。", "晚篁猶竚思，幽蕊助消魂。", "慷慨雙龍劍，飄零一酒樽。", "琳琅思秀色，環佩想清言。", "獨語看明燭，空庭月出軒。"]'),
('0a1bdd76-d812-412f-8724-d1d404138d4a','出都有感','張耒','宋','宋诗','song-poetry','','[]','來時雪盡花初發，歸去柳陰蟬亂鳴。',64,'全唐诗/poet.song.65000.json','["來時雪盡花初發，歸去柳陰蟬亂鳴。", "四序風光半爲客，百年飄泊一浮名。", "春來多病思高卧，老去違時畏後生。", "若有黄精換華髮，敢隨車馬到高城。"]'),
('5b2f97b2-8ce1-4960-8bda-f8a70da37ff1','贈別何道士','張耒','宋','宋诗','song-poetry','','[]','疏散多違久自知，形骸况復病先衰。',64,'全唐诗/poet.song.65000.json','["疏散多違久自知，形骸况復病先衰。", "全身幸免誅三獻，避世何勞賦五噫。", "聞說永嘉饒水石，便思輕帆向天涯。", "却嗟病翮傷摧甚，孤鶴高飛不得隨。"]'),
('ea3b61e4-95a6-471d-abec-19026ecbf898','北橋送客','張耒','宋','宋诗','song-poetry','','[]','橋上垂楊繫馬嘶，橋頭船尾插青旗。',64,'全唐诗/poet.song.65000.json','["橋上垂楊繫馬嘶，橋頭船尾插青旗。", "船來船去知多少，橋北橋南長別離。", "亭上幾傾行客酒，遊人自唱少年辭。", "百年回首皆陳迹，浮世飄零亦可悲。"]'),
('127ee28d-b8ee-48ed-919f-c912bb80e70c','九日獨遊懷故人','張耒','宋','宋诗','song-poetry','','[]','故人分散在天涯，九日登臨獨歎嗟。',64,'全唐诗/poet.song.65000.json','["故人分散在天涯，九日登臨獨歎嗟。", "人世光陰催日日，鄉閭時節自家家。", "風烟滿眼臨秋盡，鼓角荒城送日斜。", "取醉憑誰正烏帽，遣愁猶强插黄花。"]'),
('b483e2a6-720f-4d74-b0e3-01efd91632e5','夜','張耒','宋','宋诗','song-poetry','','[]','木落風高砧杵傷，孤城更漏入秋長。',64,'全唐诗/poet.song.65000.json','["木落風高砧杵傷，孤城更漏入秋長。", "寒生疏牖人無夢，月過中庭樹有霜。", "報落梧桐猶隕葉，知時蟋蟀解親床。", "年年多病渾無寐，靜對楞嚴一炷香。"]'),
('8ba45003-c0d3-4719-b886-4139c3aabfe1','早春','張耒','宋','宋诗','song-poetry','','[]','輝輝暖日弄遊絲，風軟晴雲緩緩飛。',64,'全唐诗/poet.song.65000.json','["輝輝暖日弄遊絲，風軟晴雲緩緩飛。", "殘雪暗隨冰筍滴，新春偷向柳梢歸。", "可憐鬢髮蹉跎老，每惜梅花取次稀。", "何事都城輕薄子，買歡酤酒試春衣。"]'),
('56e5b23e-b224-4269-86fc-7e288d461ad2','上元日駕回登樓二首  其一','張耒','宋','宋诗','song-poetry','','[]','紫霧氛霏閶闔開，團團明月上天來。',64,'全唐诗/poet.song.65000.json','["紫霧氛霏閶闔開，團團明月上天來。", "香車百兩天街晚，清蹕一聲仙仗回。", "燈隔畫簾時閃爍，風穿高幕故徘徊。", "太平日久多閒暇，簪笏從容侍燕杯。"]'),
('672e94b2-4c92-47a6-9da6-d10b81e51dac','上元日駕回登樓二首  其二','張耒','宋','宋诗','song-poetry','','[]','長街十二遠相通，閶闔峨峨彩霧紅。',64,'全唐诗/poet.song.65000.json','["長街十二遠相通，閶闔峨峨彩霧紅。", "天白華燈交皓月，樓寒朱幕蕩春風。", "車頭笑語歸時醉，城下傳呼夜向中。", "自古長安多樂事，周南留滯意何窮。"]'),
('c912ef99-0d02-43ad-8567-2dc2c5e34d2c','探春有感二首  其一','張耒','宋','宋诗','song-poetry','','[]','出城但怪風光老，草色蒼茫柳色深。',64,'全唐诗/poet.song.65000.json','["出城但怪風光老，草色蒼茫柳色深。", "烟樹遠浮春縹緲，風光不動日陰沉。", "芳郊未厭縈紆入，美酒何妨取次斟。", "羸馬青衫亦何事，一生空負野人心。"]'),
('cf76b81d-e839-47c5-96c0-859053da1cca','探春有感二首  其二','張耒','宋','宋诗','song-poetry','','[]','柳萼蒙茸待放綿，櫻桃新葉大如錢。',64,'全唐诗/poet.song.65000.json','["柳萼蒙茸待放綿，櫻桃新葉大如錢。", "深春冷落花殘後，寒食朦朧月淡天。", "獨坐每將詩作伴，遣愁安得酒如泉。", "傷心千里休凝望，城外東風早滿船。"]'),
('44158d92-1090-4852-915b-da38c9c0e421','暇日同孫畢二同舍遊李氏園亭','張耒','宋','宋诗','song-poetry','','[]','蕩蕩東風散客心，出門驅馬問園林。',64,'全唐诗/poet.song.65000.json','["蕩蕩東風散客心，出門驅馬問園林。", "花房待暖徐徐放，柳色隨春旋旋深。", "城郭遠來無俗客，松篁深處有幽禽。", "王公留壁題詩句，應許騷人盡日吟。"]'),
('1742e08d-5e23-4796-8d43-c014e0a3edef','暮春','張耒','宋','宋诗','song-poetry','','[]','夜雨輕寒拂曉晴，牡丹開盡過清明。',64,'全唐诗/poet.song.65000.json','["夜雨輕寒拂曉晴，牡丹開盡過清明。", "庭前落絮誰家柳，葉裏新聲是處鶯。", "白髮生來如有信，青春歸去更無情。", "便當種秫長成酒，遠學陶潜過此生。"]'),
('be35c0fb-13a3-4fb3-a805-26522a49d282','秋興','張耒','宋','宋诗','song-poetry','','[]','薄雲蔽日晚悠悠，簷雨蕭蕭急未收。',64,'全唐诗/poet.song.65000.json','["薄雲蔽日晚悠悠，簷雨蕭蕭急未收。", "佳樹已彫今歲葉，西風還是去年秋。", "蹉跎不奈時驚客，牢落惟憑酒散愁。", "多病支離欣得睡，晚來凉氣滿衾裯。"]'),
('72bb11c7-7110-43d2-8484-4683b1d15af2','秋雨二首  其一','張耒','宋','宋诗','song-poetry','','[]','急雨凄風未肯晴，牆陰先報候蟲鳴。',64,'全唐诗/poet.song.65000.json','["急雨凄風未肯晴，牆陰先報候蟲鳴。", "掃除暑氣驅三伏，催促秋聲向五更。", "美酒若能斟靖節，二毛偏解著潘生。", "醉來真有無窮意，老去何勞浪自驚。"]'),
('0a577546-fb57-45a8-b39a-1504c0239a76','秋雨二首  其二','張耒','宋','宋诗','song-poetry','','[]','陋巷柴門揜寂寥，一窗風雨晚蕭蕭。',64,'全唐诗/poet.song.65000.json','["陋巷柴門揜寂寥，一窗風雨晚蕭蕭。", "清秋漸冷尤宜懶，閒日苦長無處消。", "烏几青筇扶病弱，素琴黄卷伴逍遙。", "交朋南北音書隔，雖有芳樽誰可招。"]'),
('8bc07c47-a96b-4435-a760-6984bf03c176','壽陽樓下泊舟有感','張耒','宋','宋诗','song-poetry','','[]','壽陽樓下清淮水，帆去帆來何日休。',64,'全唐诗/poet.song.65000.json','["壽陽樓下清淮水，帆去帆來何日休。", "浮世十年多少事，風烟依舊別離愁。", "樓頭夜靜行人絕，樓下影斜淮月秋。", "不道孤吟不能寐，一聲羌笛怨誰舟。"]'),
('ec26d360-959f-478b-b1cb-410e957563e2','和柳郎中舒州潜庵二首  其一','張耒','宋','宋诗','song-poetry','','[]','浪走塵埃竟未甘，仙郎六十制潜庵。',64,'全唐诗/poet.song.65000.json','["浪走塵埃竟未甘，仙郎六十制潜庵。", "門前山色雲侵坐，峰下秋光水滿潭。", "野鶴避人巢古木，清猿乘月嘯寒巖。", "從今不作軒裳客，多買烟霞未是貪。"]'),
('c1272560-d66f-4f05-bfa3-ab3c06874ff6','和柳郎中舒州潜庵二首  其二','張耒','宋','宋诗','song-poetry','','[]','蒼顔華髮未能甘，欲覺長年先創庵。',64,'全唐诗/poet.song.65000.json','["蒼顔華髮未能甘，欲覺長年先創庵。", "坐久烟嵐開翠壁，夢回雲雨起寒潭。", "松風夜掃鳴琴榻，溪溜晴分種藥巖。", "不是仙翁有仙骨，幽奇爭許世人貪。"]'),
('f7a79700-cd9a-406e-86f1-8a352a439e08','將至壽州初見淮山二首  其一','張耒','宋','宋诗','song-poetry','','[]','浩蕩平波欲接天，天光波色遠相連。',64,'全唐诗/poet.song.65000.json','["浩蕩平波欲接天，天光波色遠相連。", "風鳴雨槳初離浦，岸轉青山忽對船。", "澤國秋高添氣象，人家南去好風烟。", "步兵何必江東走，自有鱸魚不值錢。"]'),
('79b56cf6-adb5-4cc7-aa3c-4d8e4f577673','將至壽州初見淮山二首  其二','張耒','宋','宋诗','song-poetry','','[]','晚繫孤舟古岸隈，蒹葭風定渚鷗回。',64,'全唐诗/poet.song.65000.json','["晚繫孤舟古岸隈，蒹葭風定渚鷗回。", "山兼野色蒼茫去，月向淮心晃蕩來。", "秋色解將愁並至，年華偏與客相催。", "青衫手板徒勞爾，富貴功名安在哉。"]'),
('1a5a67fa-3ec5-42f1-b31a-573aeee1aca1','晚發壽春浮橋望壽陽樓懷古','張耒','宋','宋诗','song-poetry','','[]','烟水蒼茫古岸高，危樓縹緲枕波濤。',64,'全唐诗/poet.song.65000.json','["烟水蒼茫古岸高，危樓縹緲枕波濤。", "山圍粉堞青屏合，橋跨長淮百艦牢。", "爭戰往年空故國，登臨行客歎前朝。", "青旗試問誰家酒，風雨蒹葭晚渡遙。"]'),
('130735ac-774c-4add-aea8-8b424ab2490d','夜泊','張耒','宋','宋诗','song-poetry','','[]','遠雁初歸楓葉乾，孤舟晚繫岸邊灘。',64,'全唐诗/poet.song.65000.json','["遠雁初歸楓葉乾，孤舟晚繫岸邊灘。", "淮聲夜靜凌風壯，月色秋深照客寒。", "疏拙功名甘闊略，飄零蹤跡但悲歎。", "不關酒薄難成醉，自是年來少所歡。"]'),
('fe4a0d56-1f72-46ab-a397-f69a3b00d9d6','將別普濟二首  其一','張耒','宋','宋诗','song-poetry','','[]','老槐疏竹寺門幽，九月輕寒襲客裘。',64,'全唐诗/poet.song.65000.json','["老槐疏竹寺門幽，九月輕寒襲客裘。", "漠漠淮烟天際晚，蕭蕭山雨坐中秋。", "風前紅葉知時落，籬下黄花對客愁。", "爲語老僧無我笑，此生終待老林丘。"]'),
('493a6c7b-99ac-4e12-be3c-ea21925d8441','將別普濟二首  其二','張耒','宋','宋诗','song-poetry','','[]','孤城淮北晚鐘殘，落日橋邊送客鞍。',64,'全唐诗/poet.song.65000.json','["孤城淮北晚鐘殘，落日橋邊送客鞍。", "物外樓臺秋更豁，山深松竹晚多寒。", "窗風細細侵衣冷，簷雨蕭蕭到夜闌。", "佳境欲留嗟不可，塵埃蹤跡但悲歎。"]'),
('34b4e021-e905-4ac1-8505-5cf09da72940','發泗州','張耒','宋','宋诗','song-poetry','','[]','萬艘獵獵戰風桅，我亦孤舟別岸隈。',64,'全唐诗/poet.song.65000.json','["萬艘獵獵戰風桅，我亦孤舟別岸隈。", "漠漠曉雲生木末，蕭蕭飛雨送帆開。", "消磨歲月書千卷，零落江湖酒一杯。", "因病得州真漫爾，功名於我亦悠哉。"]'),
('3e2d28c2-476f-4dc8-a591-2aea29429785','病中得晁應之秋懷詩','張耒','宋','宋诗','song-poetry','','[]','西風堂下飛黄葉，病卧空床白日高。',64,'全唐诗/poet.song.65000.json','["西風堂下飛黄葉，病卧空床白日高。", "疲薾扶行孤竹杖，蕭條隠几兩霜毛。", "散花有客談真實，燒藥無人過寂寥。", "怪得晚來頭目快，新詩秋興苦飄飄。"]'),
('88901d58-6cf8-48a4-a7b8-bb30f8c4b316','夏日雜興四首  其一','張耒','宋','宋诗','song-poetry','','[]','隔牆泉下是東溪，細溜涓涓入我池。',64,'全唐诗/poet.song.65000.json','["隔牆泉下是東溪，細溜涓涓入我池。", "一部笙簫寒竹響，百年風雨古槐姿。", "果懸幽檻朱初熟，蔓度空牆翠欲垂。", "野趣轉深身愈老，故應寂寞畏人知。"]'),
('b0e5e6c8-2a11-4124-afb0-2eda73daf633','夏日雜興四首  其二','張耒','宋','宋诗','song-poetry','','[]','無地從容解鬰陶，寄懷林野散塵勞。',64,'全唐诗/poet.song.65000.json','["無地從容解鬰陶，寄懷林野散塵勞。", "含風槐柳參天合，足雨桑麻映露高。", "五斗得官迷簿領，一廛何處斸蓬蒿。", "致身富貴須年少，顧我衰遲已二毛。"]'),
('b190f5c2-df56-49eb-8277-713cfb80c924','夏日雜興四首  其三','張耒','宋','宋诗','song-poetry','','[]','牆下溪流清且長，夾溪喬木雨蒼蒼。',64,'全唐诗/poet.song.65000.json','["牆下溪流清且長，夾溪喬木雨蒼蒼。", "裊風翠果擎枝重，照水圓荷舞葉凉。", "蝸殻已枯黏粉壁，燕泥時落污書床。", "南山野客閒相過，贈我能携藥滿筐。"]'),
('f1b7b1c0-7b8f-492e-8cbf-1c19f866d8b8','夏日雜興四首  其四','張耒','宋','宋诗','song-poetry','','[]','蔬圃茅齋三畝餘，溪光山影動浮虛。',64,'全唐诗/poet.song.65000.json','["蔬圃茅齋三畝餘，溪光山影動浮虛。", "病妻老去惟尋藥，稚子年來解愛書。", "中散無堪心放蕩，馮唐已老興蕭疏。", "全真養素安吾分，敢謂軒裳不我如。"]'),
('b91fefed-3ff4-4c65-891f-fcea36653f07','清明日卧病','張耒','宋','宋诗','song-poetry','','[]','鶯花零亂清明日，巾褐蕭條老病翁。',64,'全唐诗/poet.song.65000.json','["鶯花零亂清明日，巾褐蕭條老病翁。", "烏鼎相親勤煮藥，素屏深坐怯當風。", "愛花未免呼兒摘，畏雨還成對客慵。", "自歎年來怨青鏡，衰顔改盡少年紅。"]'),
('6bdbdac2-bdc1-4de8-9a4c-f39fda4c50df','水南春望','張耒','宋','宋诗','song-poetry','','[]','洛岸東風送馬行，橋橫落日半川明。',64,'全唐诗/poet.song.65000.json','["洛岸東風送馬行，橋橫落日半川明。", "天連觀閣雲垂地，春入山河秀滿城。", "老去飄萍甘屏跡，興來懷古未忘情。", "短歌一曲聊回首，不待悲秋白髮生。"]'),
('0f9917fb-41a2-448f-b9ee-2c86416f2e36','春日遣興','張耒','宋','宋诗','song-poetry','','[]','洛陽自古帝王都，百戰荆榛只故墟。',64,'全唐诗/poet.song.65000.json','["洛陽自古帝王都，百戰荆榛只故墟。", "零亂園林遺物在，嬉遊人物古風餘。", "草迷公子障泥錦，花近佳人油壁車。", "漂泊强隨遊客轡，不辭塵土污衣裾。"]'),
('3d5461a8-0283-465f-a5e5-2540ec6988a5','送楊補之赴鄂州支使','張耒','宋','宋诗','song-poetry','','[]','相逢顧我尚童兒，二十年來鬢有絲。',64,'全唐诗/poet.song.65000.json','["相逢顧我尚童兒，二十年來鬢有絲。", "涕淚兩家同患難，光陰一半屬分離。", "扁舟又作江湖別，千里長懸夢寐思。", "何日粗酬身世了，卜鄰耕釣老追隨。"]'),
('048cb3bd-cb43-4d3b-baf3-4747ecbf7c3c','送楊念行監簿侍行赴鄂渚','張耒','宋','宋诗','song-poetry','','[]','楚天南去水冥冥，鄂渚悠悠到幾程。',64,'全唐诗/poet.song.65000.json','["楚天南去水冥冥，鄂渚悠悠到幾程。", "京洛信稀千里隔，江湖春盡一帆輕。", "莫辭送別青春滿，會是相逢白髮生。", "飽讀詩書取卿相，不應如我老無成。"]'),
('5ef2c318-6096-45c2-9b34-dd1e6a1e06ba','送三姊之鄂州','張耒','宋','宋诗','song-poetry','','[]','兄弟分飛各一方，老來分袂苦多傷。',64,'全唐诗/poet.song.65000.json','["兄弟分飛各一方，老來分袂苦多傷。", "兩行別淚江湖遠，五月征車岐路長。", "休歎伯鸞甘寂寞，所欣楊惲好文章。", "北歸會有相逢地，只恐塵埃髮易蒼。"]'),
('8dba9b4f-6a19-43a1-ae45-901cf9655d4b','正月六日','張耒','宋','宋诗','song-poetry','','[]','楊柳梢頭臘雪消，東風猶著晚寒驕。',64,'全唐诗/poet.song.65000.json','["楊柳梢頭臘雪消，東風猶著晚寒驕。", "新年花柳傳芳信，去臘星霜變斗杓。", "來共春烟情冉冉，洒隨疏雨淚蕭蕭。", "蛾眉一閉年華改，縱有遺魂可得招。"]'),
('b73c4c39-d6ec-405e-a2a2-d748785e1a29','遊李氏園','張耒','宋','宋诗','song-poetry','','[]','堂下新年見草芽，驚心强起探年華。',64,'全唐诗/poet.song.65000.json','["堂下新年見草芽，驚心强起探年華。", "柳呈雪後青蒼幹，梅破風前一兩花。", "綽約風光新物態，栽培園沼好生涯。", "奔馳世路吾何有，一到林塘一歎嗟。"]'),
('46667e83-2e1b-42dc-92a0-25a72ec48888','寄榮子雍','張耒','宋','宋诗','song-poetry','','[]','蒼茫臘雪欲成泥，又見東風上柳枝。',64,'全唐诗/poet.song.65000.json','["蒼茫臘雪欲成泥，又見東風上柳枝。", "萬事過前渾是夢，百年投老只添悲。", "功名末路收常晚，節物驚心空自知。", "千里故人猶念我，書來辛苦話相思。"]'),
('8a7e8de2-e740-4439-9f85-2b723ede6c4a','題朱氏園','張耒','宋','宋诗','song-poetry','','[]','東風邀客入芳菲，夾徑吹香李萬枝。',64,'全唐诗/poet.song.65000.json','["東風邀客入芳菲，夾徑吹香李萬枝。", "啼鳥遠聞知晝靜，好花相續得春遲。", "連檣東去淮天闊，綠野南環楚澤卑。", "客至會須留醉墨，主人留榜待新詩。"]'),
('09cc3e2b-418a-4a6b-bd38-12ce1eaae93e','離宿州後寄兄弟','張耒','宋','宋诗','song-poetry','','[]','落日村橋涕泫然，東風匹馬去翩翩。',64,'全唐诗/poet.song.65000.json','["落日村橋涕泫然，東風匹馬去翩翩。", "兩行綠樹當隋岸，一片春雲限楚天。", "妄意致身常許國，强顔得祿廢求田。", "幅巾會作淮南叟，白髮相收一釣船。"]'),
('712c0182-ca32-4810-b98b-ce774ba67193','寄榮子雍三首  其一','張耒','宋','宋诗','song-poetry','','[]','東風三月洛陽城，傾蓋相逢氣倍增。',64,'全唐诗/poet.song.65000.json','["東風三月洛陽城，傾蓋相逢氣倍增。", "看盡園花方信馬，飲斜樓月更挑燈。", "年光飄忽雙馳轂，心事蕭條一老僧。", "酒病年來慵把筆，新文寄我苦憑陵。"]'),
('cabc9d91-275b-4484-b1fe-47cd96609ad0','寄榮子雍三首  其二','張耒','宋','宋诗','song-poetry','','[]','蒼蒼老柏古南禪，嫋嫋修篁泮水灣。',64,'全唐诗/poet.song.65000.json','["蒼蒼老柏古南禪，嫋嫋修篁泮水灣。", "此地笑談惟我共，百年交友得君難。", "已甘心向詩書老，會與身圖雲水閒。", "年少功名須力致，看君朝佩日珊珊。"]'),
('1751425f-6763-44c6-b29d-7226773724e2','寄榮子雍三首  其三','張耒','宋','宋诗','song-poetry','','[]','家家新酒滴新醅，殘歲崢嶸春欲回。',64,'全唐诗/poet.song.65000.json','["家家新酒滴新醅，殘歲崢嶸春欲回。", "霜野寂無新到雁，雪林寒有欲開梅。", "關河路永雙橫轍，天地身閒一舉杯。", "酬答風光千點淚，怯將愁眼更登臺。"]'),
('557b40f3-feed-494c-ab02-b7a29e3df72d','陳履常惠詩有曾門一老之句不肖二十五歲謁見南豐舍人于山陽始一書而褒與過宜陽有同途至亳之約耒以病不能如期後八年始遇公於京師南豐門人惟君一人而已感舊慨歎因成鄙句願勿他示','張耒','宋','宋诗','song-poetry','','[]','南豐冢木已蕭蕭，猶有門人守一瓢。',64,'全唐诗/poet.song.65000.json','["南豐冢木已蕭蕭，猶有門人守一瓢。", "文彩自應傳壺奧，典刑猶可想風標。", "紛紛但見侏儒飽，寂寂誰歌隠士招。", "十載敝冠彈未得，簪纓知復爲誰彯。"]'),
('0e4c0706-b1d8-4d53-8a97-994e24a11a34','泊舟候水','張耒','宋','宋诗','song-poetry','','[]','一水悠悠斷復連，卸帆終日小灘前。',64,'全唐诗/poet.song.65000.json','["一水悠悠斷復連，卸帆終日小灘前。", "青旗招飲篙工醉，五兩敧風賈客眠。", "樹色遠分芳草路，鳥行斜斷夕陽天。", "漁舟慣伴危檣宿，饋我霜鱗不用錢。"]'),
('c39b3df9-001e-4317-9ad7-5106f04c363c','同李十二醉飲王氏牡丹園二首  其一','張耒','宋','宋诗','song-poetry','','[]','東風窮巷只埃塵，誰見城南萬朵新。',64,'全唐诗/poet.song.65000.json','["東風窮巷只埃塵，誰見城南萬朵新。", "不問主人聊一飲，爲携佳客送餘春。", "比君意氣三年老，貸我疏狂一味真。", "醉裏尚能馳馬去，看君倒著接䍦巾。"]'),
('e4ed7e8a-3439-4811-aca4-200c8cc2c230','同李十二醉飲王氏牡丹園二首  其二','張耒','宋','宋诗','song-poetry','','[]','吹盡紛紛桃李塵，天香國艷一翻新。',64,'全唐诗/poet.song.65000.json','["吹盡紛紛桃李塵，天香國艷一翻新。", "正過穀雨初晴日，分得西都大半春。", "舊態似推新艷好，紅芳不似淡妝真。", "嗟予久得丘園意，何日相逢一幅巾。"]'),
('7b30d9a5-ec5b-4489-9937-fa6e3db00c1e','同无咎遐叔文叔同遊凝祥得遊字','張耒','宋','宋诗','song-poetry','','[]','客子長安塵滿裘，道人門館自深幽。',64,'全唐诗/poet.song.65000.json','["客子長安塵滿裘，道人門館自深幽。", "東風拂地千條柳，春水平池數點鷗。", "俯首一官真底事，倒囊三百更何求。", "讀書挾策君知否，失性還同博塞遊。"]'),
('b0fc52e4-5898-4133-9d14-911d64c00cfc','晝卧懷陳三時陳三卧疾','張耒','宋','宋诗','song-poetry','','[]','睡如飲蜜入蜂房，懶似遊絲百尺長。',64,'全唐诗/poet.song.65000.json','["睡如飲蜜入蜂房，懶似遊絲百尺長。", "陋巷誰過居士疾，春風正作國人狂。", "吟詩得瘦由無性，辟穀輕身合有方。", "欲餉子桑歸問婦，一瓢過午尚懸牆。"]'),
('a215648a-0e36-4c70-a700-d38fb321ca58','將至海州明山有作','張耒','宋','宋诗','song-poetry','','[]','望望孤城滄海邊，好雲深處是人烟。',64,'全唐诗/poet.song.65000.json','["望望孤城滄海邊，好雲深處是人烟。", "鳥飛山靜晴秋日，水闊人閒熟稻天。", "旗影遠摇沽酒市，棹歌歸去隔村船。", "功名富貴非吾事，誓斸明山數畝田。"]'),
('7d1f7188-b5c0-4e63-8f10-30635f7dfb93','秋日登海州乘槎亭','張耒','宋','宋诗','song-poetry','','[]','海上西風八月凉，乘槎亭外水茫茫。',64,'全唐诗/poet.song.65000.json','["海上西風八月凉，乘槎亭外水茫茫。", "人家日暖樵漁樂，山路秋晴松栢香。", "隔水飛來鴻陣闊，趁潮歸去櫓聲忙。", "蓬萊方丈知何處，烟浪參差在夕陽。"]'),
('81378394-b230-459b-8b98-1c46e432fe95','屋東','張耒','宋','宋诗','song-poetry','','[]','蒼鳩呼雨屋東啼，麥穗初長燕子飛。',64,'全唐诗/poet.song.65000.json','["蒼鳩呼雨屋東啼，麥穗初長燕子飛。", "竹裏人家雞犬靜，水邊官舍吏民稀。", "溪聲夜漲寒通枕，山色朝晴翠染衣。", "頼有西鄰好詩句，賡酬終日自忘機。"]'),
('e123a493-efb1-4267-b3bc-21cf7475b836','題齋壁','張耒','宋','宋诗','song-poetry','','[]','松庭日午聽啼鶯，簾外人稀睡老鈴。',64,'全唐诗/poet.song.65000.json','["松庭日午聽啼鶯，簾外人稀睡老鈴。", "已歎近秋添白髮，更因多病讀黄庭。", "江魚未上烹難致，吳酒空斟醉易醒。", "好住安心莫惆悵，此身天地一浮萍。"]'),
('ff616527-8490-451e-8a1a-8c4e643ccfc0','次韵李德載見寄','張耒','宋','宋诗','song-poetry','','[]','頭顱幸獲免姦鋒，甘分江湖老釣篷。',64,'全唐诗/poet.song.65000.json','["頭顱幸獲免姦鋒，甘分江湖老釣篷。", "老得一州聊自慰，相望千里與誰同。", "已欣臺省登羣俊，猶數湖湘卧病翁。", "詩就醉餘頻走筆，待觀雲海戲羣鴻。"]'),
('0b893224-1beb-4f85-99e2-3a781517211b','讀孫巨源經緯集','張耒','宋','宋诗','song-poetry','','[]','等閒咳唾爛成文，奏牘三千世共珍。',64,'全唐诗/poet.song.65000.json','["等閒咳唾爛成文，奏牘三千世共珍。", "不向人間調鼎鼐，却歸天上作麒麟。", "侍遊曲水歡何在，敷奏延英迹已陳。", "四輔當時曾避柱，熙寧天子屬詞臣。"]'),
('cfa08a4c-de58-4df3-9242-47a125fbf7bf','將赴上庠偶成','張耒','宋','宋诗','song-poetry','','[]','卷中課最詩成後，枕上功名睡美餘。',64,'全唐诗/poet.song.65000.json','["卷中課最詩成後，枕上功名睡美餘。", "弟子解疑常隠几，輪人能笑久觀書。", "山林沉痼時搔首，松菊耽淫自荷鋤。", "干世可能尋一飽，虀鹽未用食無魚。"]'),
('3bb4933c-9179-4f25-9d94-f897b554b366','寄楊克一','張耒','宋','宋诗','song-poetry','','[]','吾甥頗似魏家舒，新罷推囚却著書。',64,'全唐诗/poet.song.65000.json','["吾甥頗似魏家舒，新罷推囚却著書。", "顧我獨傾陶令酒，思君同鱠季鷹鱸。", "荒凉雲物秋將老，寂寞山城誰與娛。", "倏忽風光行老矣，躊躇不去欲何如。"]'),
('54f39573-5b9d-4b89-a21c-3798710ebc16','己卯十二月二十日感事二首  其一','張耒','宋','宋诗','song-poetry','','[]','高樓乘興獨登臨，搔首天涯歲暮心。',64,'全唐诗/poet.song.65000.json','["高樓乘興獨登臨，搔首天涯歲暮心。", "带雪臘風藏澤國，犯寒春色著烟林。", "山川極目風光異，歲月驚懷老境侵。", "可是斯文天未喪，楚囚何事涕沾襟。"]'),
('b88c33b8-74e6-41f3-b3b2-0bee5ce6edc0','己卯十二月二十日感事二首  其二','張耒','宋','宋诗','song-poetry','','[]','蹉跎流落已華顛，又見荆湖一歲遷。',64,'全唐诗/poet.song.65000.json','["蹉跎流落已華顛，又見荆湖一歲遷。", "人怯苦寒愁日短，天收殘臘放新年。", "園林寂歷飄梅後，里巷經過爆竹前。", "自料知非猶得在，潜心久學衛蘧先。"]'),
('ca217d64-d54f-4e71-ab87-e197499cf4dc','冬節小不佳懷正叔老兄','張耒','宋','宋诗','song-poetry','','[]','老境光陰短景催，新冬又復一年回。',64,'全唐诗/poet.song.65000.json','["老境光陰短景催，新冬又復一年回。", "焚香燕坐衣僧衲，煮藥高眠廢酒杯。", "處處庖厨鳴甕缶，年年歌笑慘風埃。", "孟公歌舞猶須雪，未放愁眉取次開。"]'),
('a50a9760-d04b-493c-9584-9fe882047603','耒將之臨淮旅泊泗上屬病作迎候上官不敢求告比歸尤劇疏拙無以自振但自憫歎耳','張耒','宋','宋诗','song-poetry','','[]','謀身不解免飄蓬，零落孤舟西復東。',64,'全唐诗/poet.song.65000.json','["謀身不解免飄蓬，零落孤舟西復東。", "雙鬢雖青應早白，病顔更醉不成紅。", "崎嶇避俗人難合，憔悴多愁疾易攻。", "蓴菜碧鱸秋正美，步兵終欲向江東。"]'),
('bba652b8-8950-4f87-aaa1-3a2e79258075','訪人汴上有感','張耒','宋','宋诗','song-poetry','','[]','萬尾鱗鱗汴岸舟，汴流日夜去悠悠。',64,'全唐诗/poet.song.65000.json','["萬尾鱗鱗汴岸舟，汴流日夜去悠悠。", "舟行水去常如舊，世事紛紛何日休。", "落日昏昏沙際晚，白雲片片碧天秋。", "□□□□□□□，□□□□□□□。"]'),
('32f057aa-8487-450d-9411-8ee6df364835','望龜山二首  其一','張耒','宋','宋诗','song-poetry','','[]','淮上風高寒日西，龜山嶺下白雲歸。',64,'全唐诗/poet.song.65000.json','["淮上風高寒日西，龜山嶺下白雲歸。", "遊人苦憾日已晚，青山自與雲爲期。", "輕舟漁子犯烟去，照水白鷗窺影飛。", "人間不作逍遙客，老去塵埃空滿衣。"]'),
('29b147b4-5e46-4642-8db6-1bc46966402a','望龜山二首  其二','張耒','宋','宋诗','song-poetry','','[]','日落龜山山更清，原頭啼鳥已春聲。',64,'全唐诗/poet.song.65000.json','["日落龜山山更清，原頭啼鳥已春聲。", "可憐山近不能到，盡日與山相對行。", "雲裏人家自來往，天邊樓閣遠分明。", "白鷗不解遊客意，驚起碧烟深處橫。"]'),
('f62e940c-3745-4f80-9733-0fba8a9fd2cc','次韵答存之','張耒','宋','宋诗','song-poetry','','[]','環堵蕭然汝水隈，孤懷炯炯向誰開。',64,'全唐诗/poet.song.65000.json','["環堵蕭然汝水隈，孤懷炯炯向誰開。", "青春不覺書邊過，白髮無端鏡上來。", "祭竈請鄰聊復爾，賣刀買犢豈難哉。", "故人休說封侯事，歸釣江天有舊臺。"]'),
('c2d9b6e4-bfc9-4e5d-be8c-d07cd398913b','離天長寄周重實','張耒','宋','宋诗','song-poetry','','[]','相逢握手便忘形，射策天門盡弟兄。',64,'全唐诗/poet.song.65000.json','["相逢握手便忘形，射策天門盡弟兄。", "浮世有誰尊道義，青衫自笑爲功名。", "高談未盡胸中意，作別猶如夢後驚。", "半夜叩門投野寺，天寒孤月更分明。"]'),
('8d6c6c3a-2607-46b1-ac4d-f1358a305aeb','秋宮','張耒','宋','宋诗','song-poetry','','[]','帳額斕斑暗舊金，玉猊香重暖沈沈。',64,'全唐诗/poet.song.65000.json','["帳額斕斑暗舊金，玉猊香重暖沈沈。", "秋風宮殿梧桐老，暮雨樓臺簾幕深。", "銀箭漏遲雞唱曉，綺窗人睡晝生陰。", "無眠慣滴班姬淚，聽盡長安夜夜砧。"]'),
('4dbcd7f7-da8d-47c3-83fc-aad06620f2d0','題堂下桐','張耒','宋','宋诗','song-poetry','','[]','零落當軒兩樹桐，秋來相伴一衰翁。',64,'全唐诗/poet.song.65000.json','["零落當軒兩樹桐，秋來相伴一衰翁。", "寒枝向月空餘影，隕葉知時不待風。", "故國山川天黯淡，美人音信雁西東。", "歲華節物俱寥落，滿眼牢愁頼酒攻。"]'),
('e3ccc468-0cad-40cd-99dc-0ebe0b9c7df2','登海州城樓','張耒','宋','宋诗','song-poetry','','[]','城外滄溟日夜流，城南山直對城樓。',64,'全唐诗/poet.song.65000.json','["城外滄溟日夜流，城南山直對城樓。", "溪田雨足禾先熟，海樹風高葉易秋。", "疏傅里閭詢故老，秦皇車甲想東遊。", "客心不待傷千里，檻外風烟盡是愁。"]'),
('94ae1723-fb98-471d-b7e7-abda855bec69','秋日憶家','張耒','宋','宋诗','song-poetry','','[]','汩汩流光長遠客，年年秋至是離家。',64,'全唐诗/poet.song.65000.json','["汩汩流光長遠客，年年秋至是離家。", "孤城入夜寒更迥，霜月滿天歸夢賒。", "摵摵老桐風後葉，娟娟疏菊雨殘花。", "茅簷布被猶無力，長走塵埃真可嗟。"]'),
('086e1498-aea9-4d86-b9c8-d0080a21a3df','七言','張耒','宋','宋诗','song-poetry','','[]','飛鴻歸盡燕將還，亭院深沉人倚欄。',64,'全唐诗/poet.song.65000.json','["飛鴻歸盡燕將還，亭院深沉人倚欄。", "斜搭鞦韆寒食雨，已黄楊柳暮春寒。", "密毬杏萼紅如糝，半落梅花香未殘。", "人世年年非舊事，感時惟有淚汍瀾。"]'),
('f4f40747-58ae-4419-8c0d-3f29716b3aef','山下','張耒','宋','宋诗','song-poetry','','[]','山下疏鐘日夜催，城頭畫角五更哀。',64,'全唐诗/poet.song.65000.json','["山下疏鐘日夜催，城頭畫角五更哀。", "流年忽忽愁中過，世事紛紛空裏來。", "沮溺漫高輕世節，管商空盡濟時才。", "古來擾擾今何有，一熟黄粱夢已回。"]'),
('5b064985-77a7-48e8-b722-3ff1bc016ff4','京師廢宅','張耒','宋','宋诗','song-poetry','','[]','當道朱門白晝扃，高堂歌吹久無聲。',64,'全唐诗/poet.song.65000.json','["當道朱門白晝扃，高堂歌吹久無聲。", "古窗積雨昏殘畫，朽樹經陰長寄生。", "門下老人時灑掃，舊時來客歎平生。", "艷姬驕馬知何處，獨有庭花春正榮。"]'),
('9baf4968-4ad1-4ea3-b5ce-13345307cdb1','送徐任','張耒','宋','宋诗','song-poetry','','[]','白髮青衫困宦遊，相逢不復話封侯。',64,'全唐诗/poet.song.65000.json','["白髮青衫困宦遊，相逢不復話封侯。", "少年壯氣青雲上，投老生涯一醉休。", "獻璞誰憐藏美玉，惡聲不至爲虛舟。", "從來滿卷新詩句，寫取淮天萬里秋。"]'),
('1e1299af-1ee1-4fd5-872b-95b9c49911ec','登城樓','張耒','宋','宋诗','song-poetry','','[]','沙雨初乾巾褐輕，獨披衰蔓步高城。',64,'全唐诗/poet.song.65000.json','["沙雨初乾巾褐輕，獨披衰蔓步高城。", "天晴海上峰巒出，野暗人家燈火明。", "歸鳥各尋芳樹去，夕陽微照遠村耕。", "登樓已恨荆州遠，况復安仁白髮生。"]'),
('b3531384-8392-45dd-88b6-03d02497e6df','寄陳鼎','張耒','宋','宋诗','song-poetry','','[]','懶著青衫沉醉眠，近來沽酒困無錢。',64,'全唐诗/poet.song.65000.json','["懶著青衫沉醉眠，近來沽酒困無錢。", "常憂送乏鄰僧米，何啻寒無坐客氈。", "直道漫憑詹尹卜，浮生已付祖師禪。", "祇應居士無醒日，知有淵明種秫田。"]'),
('d58dee19-96ac-4d69-867f-4812e295a9a8','蓬瀛臺二首  其一','張耒','宋','宋诗','song-poetry','','[]','青冥不盡海茫茫，一望蓬瀛去路長。',64,'全唐诗/poet.song.65000.json','["青冥不盡海茫茫，一望蓬瀛去路長。", "秋信解憑詩客寄，春心長爲楚魂傷。", "縈回四望山如畫，興廢千年木已蒼。", "直使臺傾荆棘滿，聞琴何用涕霑裳。"]'),
('b26ddd55-9eff-4c68-be89-e06f4d749801','蓬瀛臺二首  其二','張耒','宋','宋诗','song-poetry','','[]','蒼烟喬木古臺荒，下見蓬瀛六月凉。',64,'全唐诗/poet.song.65000.json','["蒼烟喬木古臺荒，下見蓬瀛六月凉。", "過雨誰知非峽女，好風應是爲襄王。", "歡來未放流年老，事去却尋陳迹傷。", "飄泊南遊未能返，興來回首獨凄凉。"]'),
('81c4ee22-109f-4092-a9d0-6b9441904260','和即事','張耒','宋','宋诗','song-poetry','','[]','溪如圓塹木如城，魚鳥從遊信此情。',64,'全唐诗/poet.song.65000.json','["溪如圓塹木如城，魚鳥從遊信此情。", "啅雀踏枝飛尚裊，仰荷承雨側還傾。", "彈琴廢久重尋譜，種藥求多旋記名。", "於世久判無妙策，直應歸學老農耕。"]'),
('e536431d-dbe2-4680-bae4-5f34dd64dc74','自海至楚途次寄馬全玉八首  其一','張耒','宋','宋诗','song-poetry','','[]','迂疏懷抱獨君知，杖拂親依即我師。',64,'全唐诗/poet.song.65000.json','["迂疏懷抱獨君知，杖拂親依即我師。", "一句未能參妙道，數篇空復寄新詩。", "子方奮迅雲間翮，我厭追隨世上兒。", "安得巖坰兩如志，銅瓶烏几爲君携。"]'),
('64566969-7f80-442a-a206-637641ed2aeb','自海至楚途次寄馬全玉八首  其二','張耒','宋','宋诗','song-poetry','','[]','蕭蕭柳岸野風秋，虹掛前山晚雨收。',64,'全唐诗/poet.song.65000.json','["蕭蕭柳岸野風秋，虹掛前山晚雨收。", "回首孤城空綠樹，滿川斜日放歸舟。", "年來雙淚供愁盡，去去勞生幾日休。", "試問故人思我否，夢魂猶在海邊州。"]'),
('82a3690b-5dda-4793-a0f8-873c5af52e23','自海至楚途次寄馬全玉八首  其三','張耒','宋','宋诗','song-poetry','','[]','高城欲去更徘徊，病眼登臨强一開。',64,'全唐诗/poet.song.65000.json','["高城欲去更徘徊，病眼登臨强一開。", "風物盡爲愁裏景，山川疑是夢中來。", "此身雙鬢何勞白，未老塵心可得灰。", "欲把煩愁付杯酒，祇應清夢待尊罍。"]'),
('d325a837-63e2-4a1d-841f-655629be9b95','自海至楚途次寄馬全玉八首  其四','張耒','宋','宋诗','song-poetry','','[]','生涯飄泊一航輕，浩蕩晴川送我行。',64,'全唐诗/poet.song.65000.json','["生涯飄泊一航輕，浩蕩晴川送我行。", "北望山川連海遠，南來風月近淮清。", "人家稻熟豐年滿，澤國天高秋意生。", "惟有羈愁消不得，登臨清淚落如傾。"]'),
('cc5a405a-91b8-4a20-b495-eba3bc33435a','自海至楚途次寄馬全玉八首  其五','張耒','宋','宋诗','song-poetry','','[]','少年居士正安禪，法是懷公門下傳。',64,'全唐诗/poet.song.65000.json','["少年居士正安禪，法是懷公門下傳。", "已解出塵金裏鑛，何妨離欲火中蓮。", "苦心參道嗟予晚，極口隨機恃子憐。", "若許維揚傍仁里，一廛須買許行田。"]'),
('3bc99480-eefc-4307-b328-5238f7c47e33','自海至楚途次寄馬全玉八首  其六','張耒','宋','宋诗','song-poetry','','[]','蕭蕭晚雨向風斜，村遠荒凉三四家。',64,'全唐诗/poet.song.65000.json','["蕭蕭晚雨向風斜，村遠荒凉三四家。", "野色連雲迷稼穡，秋聲催曉起蒹葭。", "愁如夜月長隨客，身似飛鴻不記家。", "極目相望何處是，海天無際落殘霞。"]'),
('d099d103-1cfa-4715-90eb-e9af0ad1ae57','自海至楚途次寄馬全玉八首  其七','張耒','宋','宋诗','song-poetry','','[]','二年海角寄東城，歲久移居亦有情。',64,'全唐诗/poet.song.65000.json','["二年海角寄東城，歲久移居亦有情。", "去路山川嗟我遠，舊時風月爲誰清。", "一廛受地今難繼，三徑懷歸久欲耕。", "何日山林有茅屋，百年無復問功名。"]'),
('08cfff26-7a2b-4947-abf4-16eab00215e1','自海至楚途次寄馬全玉八首  其八','張耒','宋','宋诗','song-poetry','','[]','紫蟹雙螯薦客盤，傾來不覺酒壺乾。',64,'全唐诗/poet.song.65000.json','["紫蟹雙螯薦客盤，傾來不覺酒壺乾。", "雨多澤國蒲魚美，秋至楚天風露寒。", "老去論交嗟我晚，尊前一笑憶君歡。", "紅蓮幕下無書檄，剩寄新詩滿卷看。"]'),
('2ac9eee8-e3a9-45ad-a210-6c90644b4704','夏日三首  其一','張耒','宋','宋诗','song-poetry','','["\u5f52\u9690", "\u751f\u6d3b", "\u590f\u5929", "\u95f2\u9002"]','長夏江村風日清，簷牙燕雀已生成。',64,'全唐诗/poet.song.65000.json','["長夏江村風日清，簷牙燕雀已生成。", "蝶衣曬粉花枝午，蛛網添絲屋角晴。", "落落疏簾邀月影，嘈嘈虛枕納溪聲。", "久拚兩鬢如霜雪，直欲樵漁過此生。"]'),
('d8fef14c-4812-4a43-adc2-dcd9aeec511f','夏日三首  其二','張耒','宋','宋诗','song-poetry','','[]','黄簾翠幕斷飛蠅，午影當軒睡未興。',64,'全唐诗/poet.song.65000.json','["黄簾翠幕斷飛蠅，午影當軒睡未興。", "枕穩海魚鎸紫石，扇凉山雪畫青繒。", "廊陰日轉雕欄樹，坐冷風生玉碗冰。", "滿案詩書塵蠹甚，故應疏懶過炎蒸。"]'),
('f9a187c4-0b5b-4e77-892b-1d59096552a3','夏日三首  其三','張耒','宋','宋诗','song-poetry','','[]','棗徑瓜畦經雨凉，白衫烏帽野人裝。',64,'全唐诗/poet.song.65000.json','["棗徑瓜畦經雨凉，白衫烏帽野人裝。", "幽花避日房房斂，翠樹含風葉葉香。", "養拙久拚藏姓氏，致身安事巧文章。", "漢庭卿相皆豪俊，不遇何妨白髮郎。"]'),
('5b201ad2-b04c-44ad-81a5-c95ddef9c395','和晁應之大暑書事','張耒','宋','宋诗','song-poetry','','[]','蓬門久閉謝來車，畏暑尤便小閣虛。',64,'全唐诗/poet.song.65000.json','["蓬門久閉謝來車，畏暑尤便小閣虛。", "青引嫩苔留鳥篆，綠垂殘葉带蟲書。", "寒泉出井功何有，白羽邀凉計已疏。", "忍待西風一蕭瑟，碧鱸斫鱠意何如。"]'),
('576bf58b-f292-4480-8889-feed00abb3c6','遣興次韵和晁應之四首  其一','張耒','宋','宋诗','song-poetry','','[]','老去詩書倦討論，一樽相對尚殷勤。',64,'全唐诗/poet.song.65000.json','["老去詩書倦討論，一樽相對尚殷勤。", "鍛爐放蕩狂中散，書閣蕭條老子雲。", "要路交親嗟隔闊，他鄉耆舊飽知聞。", "衰知多病頭風甚，解寄新文獨有君。"]'),
('9cb96001-7501-41de-a0bb-528d9780c6e1','遣興次韵和晁應之四首  其二','張耒','宋','宋诗','song-poetry','','[]','西風淅淅滿征衣，天畔危亭面翠微。',64,'全唐诗/poet.song.65000.json','["西風淅淅滿征衣，天畔危亭面翠微。", "雲解映山常漠漠，葉知辭樹亦依依。", "苦饑黄鵠猶謀食，無事輕鷗得遠飛。", "落日秋風滿江漢，杖藜三歎未能歸。"]'),
('caea9b31-9c3f-4448-89ee-2a35e2897291','遣興次韵和晁應之四首  其三','張耒','宋','宋诗','song-poetry','','[]','夜泛孤舟清洛津，宓妃輕步若爲親。',64,'全唐诗/poet.song.65000.json','["夜泛孤舟清洛津，宓妃輕步若爲親。", "清涵星漢光垂地，冷覺魚龍氣近人。", "鏡裏悲秋雙鬢髮，馬邊隨客兩京塵。", "愁心欲比東流水，滾滾無窮日日新。"]'),
('ba6cd642-2113-4900-beda-535324ace6a9','遣興次韵和晁應之四首  其四','張耒','宋','宋诗','song-poetry','','[]','蓬門鳥雀啅黄昏，歸徑牛羊各有羣。',64,'全唐诗/poet.song.65000.json','["蓬門鳥雀啅黄昏，歸徑牛羊各有羣。", "水闊魚龍陰後出，山空虎豹夜深聞。", "西來客引秦川雨，南去秋連楚澤雲。", "唐漢廢興無處問，西風禾黍但丘墳。"]'),
('8497beef-2e7e-4397-9ece-c1716c77ea2f','自巴河至蘄陽口道中得二詩示仲達與秬同賦  其一','張耒','宋','宋诗','song-poetry','','[]','落月娟娟墮半環，嘔啞鳴櫓轉荒灣。',64,'全唐诗/poet.song.65000.json','["落月娟娟墮半環，嘔啞鳴櫓轉荒灣。", "東南地缺天連水，春夏風高浪卷山。", "旅食每愁村市散，近秋已覺暑衣單。", "自慚老病心兒女，三日離家已念還。"]'),
('5ad05d19-55a7-41b3-8521-b59f6782dac1','自巴河至蘄陽口道中得二詩示仲達與秬同賦  其二','張耒','宋','宋诗','song-poetry','','[]','浩浩渾流卷白沙，中流鼓棹四無涯。',64,'全唐诗/poet.song.65000.json','["浩浩渾流卷白沙，中流鼓棹四無涯。", "喜逢山色開眉黛，愁對江雲起砲車。", "雨足郊原豐稻菽，日斜鷗鷺滿蒹葭。", "長年怕作扁舟客，頼有高談一笑譁。"]'),
('f2aefc7f-41c8-4396-a718-2ad00e1eff9e','離蘄陽守風林皇方慮風壯晚未知所止俄頃風息一食頃宿富池作詩示同行','張耒','宋','宋诗','song-poetry','','[]','老怕風波見輒驚，頼逢談笑慰危情。',64,'全唐诗/poet.song.65000.json','["老怕風波見輒驚，頼逢談笑慰危情。", "縱觀雲嶺屏風合，坐見江濤鏡面平。", "淹速人生難預計，險夷世路不須營。", "塵埃老作東州守，得得扁舟作此行。"]'),
('a078b8c9-91a8-49ec-8bc9-5d566911195e','離富池望廬岳是日入夾口直達潯陽遂舍大江之險示同行','張耒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山秀江清三百里，與君三宿一扁舟。',64,'全唐诗/poet.song.65000.json','["山秀江清三百里，與君三宿一扁舟。", "飲殘桑落溪雲暮，卧冷桃笙楚雨秋。", "舟隠長江逢夾口，眼明五老立雲頭。", "幾年澤國行將遍，歸與親朋說舊遊。"]'),
('ec51941e-f58f-46c8-a26f-18ff53439dbe','二十三日即事','張耒','宋','宋诗','song-poetry','','[]','已逢娬媚散花峽，不怕艱危道士磯。',64,'全唐诗/poet.song.65000.json','["已逢娬媚散花峽，不怕艱危道士磯。", "啼鳥似逢人勸酒，好山如爲我開眉。", "風標公子鷺得意，跋扈將軍風斂威。", "到舍將何作歸遺，江山收得一囊詩。"]'),
('e9954991-c27e-42db-b813-2a2b8339fd54','度洛因泛舟東下數里頗憶淮上','張耒','宋','宋诗','song-poetry','','[]','沄沄清洛轉山隈，渺渺東流不復回。',64,'全唐诗/poet.song.65000.json','["沄沄清洛轉山隈，渺渺東流不復回。", "輕鳥竟隨青嶂去，亂波爭泛夕陽來。", "偶驚舟楫鄉心起，乍脫塵埃病眼開。", "疑是盱眙郭門外，月明帆席過清淮。"]'),
('7843ce06-7b20-4fac-84d5-58e07b32ad0d','縣齋','張耒','宋','宋诗','song-poetry','','[]','只合門如野叟家，市朝聲利苦喧嘩。',64,'全唐诗/poet.song.65000.json','["只合門如野叟家，市朝聲利苦喧嘩。", "但知得醉頻沽酒，何處逢春不見花。", "暗樹五更雞報曉，晚庭三疊鼓催衙。", "知君宰邑端無事，吟笑何妨到暮鴉。"]'),
('5a23330f-4673-4ef7-843e-7b8492bcfd8c','和周廉彥','張耒','宋','宋诗','song-poetry','','[]','天光不動晚雲垂，芳草初長襯馬蹄。',64,'全唐诗/poet.song.65000.json','["天光不動晚雲垂，芳草初長襯馬蹄。", "新月已生飛鳥外，落霞更在夕陽西。", "花開有客時携酒，門冷無車出畏泥。", "修禊洛濱期一醉，天津春浪綠浮堤。"]'),
('2dbdca6a-15f6-4a73-9e5d-46bffc3563e8','春日遣興二首  其一','張耒','宋','宋诗','song-poetry','','[]','流光向老惜芳菲，搔首悲歌心事違。',64,'全唐诗/poet.song.65000.json','["流光向老惜芳菲，搔首悲歌心事違。", "綠野染成延晝永，辭紅吹盡放春歸。", "荆榛廢苑人閒牧，風雨空城烏夜飛。", "斷送一番桃李盡，可憐桑柘有光輝。"]'),
('65dac368-2b93-415f-ada2-f8f95afc5ae2','春日遣興二首  其二','張耒','宋','宋诗','song-poetry','','[]','日烘烟柳軟於絲，桃李成塵綠滿枝。',64,'全唐诗/poet.song.65000.json','["日烘烟柳軟於絲，桃李成塵綠滿枝。", "芳草有情隨處好，落花無頼信風吹。", "關心傷感知何處，過眼芳菲能幾時。", "一病春來妨痛飲，遣愁惟有强裁詩。"]'),
('e4f613c4-4562-4521-8943-3be48b24f1c2','錢仲珣追船及陳留','張耒','宋','宋诗','song-poetry','','[]','野岸南風百草長，沄沄汴水卷沙黄。',64,'全唐诗/poet.song.65000.json','["野岸南風百草長，沄沄汴水卷沙黄。", "扁舟轉柁迷城市，送客追船羅酒漿。", "休唱陽關傷遠別，所欣蓴菜入新堂。", "宦名衰晚君無問，便得封侯鬢已蒼。"]'),
('0eb0b1b0-927c-4643-9bf0-3c00afd2fe8f','遺興次韵和晁應之四首  其一','張耒','宋','宋诗','song-poetry','','[]','日落村虛烟靄青，草根促織晚先鳴。',64,'全唐诗/poet.song.65000.json','["日落村虛烟靄青，草根促織晚先鳴。", "羣山衮衮望中去，新月娟娟愁裏生。", "暗峽風雲秋慘淡，高城河漢夜分明。", "寄書故國還羞澀，白首蕭條老病嬰。"]'),
('b9da30b2-62e4-4f8f-815e-54d793eeba05','遺興次韵和晁應之四首  其二','張耒','宋','宋诗','song-poetry','','[]','洛陽宮殿鎖埃塵，翠輦東還幾度春。',64,'全唐诗/poet.song.65000.json','["洛陽宮殿鎖埃塵，翠輦東還幾度春。", "雙闕曉雲連太室，九門晴影動天津。", "地藏寶鼎寧無祲，龍護靈書固有神。", "遊豫此時期聖主，保釐從古仗元臣。"]'),
('c7d5b30a-4466-4a61-aa3f-fbdc8ffba2cf','遺興次韵和晁應之四首  其三','張耒','宋','宋诗','song-poetry','','[]','女几山前雲雨收，五更星斗轉西樓。',64,'全唐诗/poet.song.65000.json','["女几山前雲雨收，五更星斗轉西樓。", "蒼蒼淡月關河曉，裊裊西風觀閣秋。", "獨鶴有求時飲啄，孤雲無事任沉浮。", "可憐白髮張公子，還望西山歌四愁。"]'),
('88ee9ee3-98c7-4a5d-ab6e-a8dbeb96d0f3','遺興次韵和晁應之四首  其四','張耒','宋','宋诗','song-poetry','','[]','露下風悲螢火流，周南羈客意悠悠。',64,'全唐诗/poet.song.65000.json','["露下風悲螢火流，周南羈客意悠悠。", "山川老去三年淚，關塞秋來萬里愁。", "慣逐禽魚諳異俗，每因霜月夢滄洲。", "一拋硯井雙蓬鬢，天畔詩成獨倚樓。"]'),
('efe7a44b-0755-4bf5-886f-44f62ac5a2bd','新霽','張耒','宋','宋诗','song-poetry','','[]','園門幾日斷行蹤，新霽欣然路小通。',64,'全唐诗/poet.song.65000.json','["園門幾日斷行蹤，新霽欣然路小通。", "晚萼有情開宿雨，長林盡日舞高風。", "后皇佳植寧無橘，鸞鳳求棲亦有桐。", "不惜園林娛逐客，此情誰似主人翁。"]'),
('12bedb1d-6789-40ac-823b-82741159db1e','與李文舉登夢野亭','張耒','宋','宋诗','song-poetry','','[]','樽俎相逢散百憂，雖非吾土共登樓。',64,'全唐诗/poet.song.65000.json','["樽俎相逢散百憂，雖非吾土共登樓。", "天邊雲送荆王雨，江上楓彫宋玉秋。", "華髮不堪懷故國，清杯相與散牢愁。", "清談七澤誰强健，莫學騷人賦遠遊。"]'),
('acea1a1c-2075-47bb-9091-3d86612443bb','登夢野亭懷舊','張耒','宋','宋诗','song-poetry','','[]','曾上高臺望翠微，重來悲歎客難期。',64,'全唐诗/poet.song.65000.json','["曾上高臺望翠微，重來悲歎客難期。", "章華蒼莽尋無處，雲夢逶迤寒更遲。", "墨客多情曾痛飲，玉簫何處弄妍詞。", "請君點檢當時事，只應朱顔非舊時。"]'),
('bfbe8bbf-2aca-4518-8bf5-89382af0da08','北堂齋居示秬秸','張耒','宋','宋诗','song-poetry','','[]','窮臘貧家絺紵單，可堪過雨夜堂寒。',64,'全唐诗/poet.song.65000.json','["窮臘貧家絺紵單，可堪過雨夜堂寒。", "屏除葷酒神應爽，談笑詩書樂未閒。", "凈境眼前無俗物，清都夢到有飛翰。", "雞鳴月落紙窗白，疑是從天風馭還。"]'),
('3df26cb8-5716-43ec-b54a-19d74a54e067','送復守張坰朝奉罷歸','張耒','宋','宋诗','song-poetry','','[]','一夢西都十二年，竟陵相遇各華顛。',64,'全唐诗/poet.song.65000.json','["一夢西都十二年，竟陵相遇各華顛。", "風流家世仁人後，愷悌歌謠楚俗傳。", "學道愛君甘淡薄，倦遊嗟我久留連。", "自憐江上傷春眼，不待琵琶已泫然。"]'),
('4561b790-f88f-43c4-869d-7edda7550d1d','歲日同郡官朝天慶回偶成','張耒','宋','宋诗','song-poetry','','[]','清曉琳宮拜謁還，駝裘猶怯夜霜寒。',64,'全唐诗/poet.song.65000.json','["清曉琳宮拜謁還，駝裘猶怯夜霜寒。", "春生七澤蒼茫外，日上三山縹緲間。", "投老埃塵從馬後，異時班綴近龍顔。", "人間倚伏誰能料，一酌芳醪興未闌。"]'),
('1df92770-657b-4aad-bf88-1c5e8ecabb2a','僦居小室之西有隙地不滿十步新歲後稍暖每開戶春色鬬進戲名其戶曰嬉春因爲此詩','張耒','宋','宋诗','song-poetry','','[]','蒼蒼老檜已消雪，冉冉烟蕪欲鬭妍。',64,'全唐诗/poet.song.65000.json','["蒼蒼老檜已消雪，冉冉烟蕪欲鬭妍。", "圍得青春數畝地，斷將平楚一方天。", "春風入戶如相覓，新月低窗最可憐。", "老子婆娑便終日，一壺春酒與周旋。"]'),
('5ff3a5aa-5ea5-4660-80d2-2e90215a89de','發安化回望黄州山','張耒','宋','宋诗','song-poetry','','[]','流落江湖四見春，天恩復與兩朱輪。',64,'全唐诗/poet.song.65000.json','["流落江湖四見春，天恩復與兩朱輪。", "幾年魚鳥真相得，從此江山是故人。", "碧落已瞻新日月，故園好在舊交親。", "此生已免嘲傖父，莫避北風京洛塵。"]'),
('6cea303b-4ea1-42e6-b642-39db783f6ab4','發雲山近岐亭望光蔡接尉氏','張耒','宋','宋诗','song-poetry','','[]','白草黄茅間瘦田，郊原殘暑已蕭然。',64,'全唐诗/poet.song.65000.json','["白草黄茅間瘦田，郊原殘暑已蕭然。", "澤連楚夢悲秋野，山近堯封望日天。", "濃綠遠陂鋪晚稼，幽香秋水折殘蓮。", "熱行更益相如渴，悵望華陵陸子泉。"]'),
('161c25f7-e0ed-452b-8ec7-635abd83ff46','贈僧介然','張耒','宋','宋诗','song-poetry','','[]','寒窗寫就白雲篇，客至研茶手自煎。',64,'全唐诗/poet.song.65000.json','["寒窗寫就白雲篇，客至研茶手自煎。", "儒佛故應同是道，詩書本是不妨禪。", "長松千尺巢雲鶴，寒嶠三更嘯月猿。", "請以篇章爲佛事，要觀半偈走人天。"]'),
('d63dae76-7848-4eca-845d-d86b51d32168','寄子由二首  其一','張耒','宋','宋诗','song-poetry','','[]','萬里歸來真得仙，七年瞻望漫悁悁。',64,'全唐诗/poet.song.65000.json','["萬里歸來真得仙，七年瞻望漫悁悁。", "安閒舊得還丹訣，著論新成古史編。", "應接强顔聊復爾，是非袖手獨超然。", "門人白首侯芭在，眷戀微官愧昔賢。"]'),
('0331a09b-2912-4c1d-bbc9-a3e69135cd27','寄子由二首  其二','張耒','宋','宋诗','song-poetry','','[]','丈席他年聞至言，艱難不敢墜周旋。',64,'全唐诗/poet.song.65000.json','["丈席他年聞至言，艱難不敢墜周旋。", "文詞老去真何益，道妙平生薄有緣。", "人事眼前惟欲睡，丹經肘後更難傳。", "清秋一室林泉好，灑掃思爲杖屨先。"]'),
('1fffd038-ccf1-4726-b9d7-be95c86a7218','卧病月餘呈子由二首  其一','張耒','宋','宋诗','song-poetry','','[]','蔀室悠悠昏復朝，强披莊子說逍遙。',64,'全唐诗/poet.song.65000.json','["蔀室悠悠昏復朝，强披莊子說逍遙。", "四禪未到風猶梗，九轉無功火不燒。", "學道若爲調鹿馬，是身不實似芭蕉。", "丹砂赤箭功何有，想聽清言意自消。"]'),
('f96d4893-77ac-411a-be26-67a509e81d6d','卧病月餘呈子由二首  其二','張耒','宋','宋诗','song-poetry','','[]','風葉鳴窗已復朝，喚回歸夢故山遙。',64,'全唐诗/poet.song.65000.json','["風葉鳴窗已復朝，喚回歸夢故山遙。", "酒壺暗淡浮塵集，藥鼎青熒敗葉燒。", "閉戶獨依寒蟋蟀，移床近就雨芭蕉。", "雪深更請安心術，長日如年未易消。"]'),
('f3597293-58d1-4c10-afb4-a36d3909134e','次韵李晉裕教授九日見贈','張耒','宋','宋诗','song-poetry','','[]','滿酌聊酬菊蕊黄，登高仍在太山陽。',64,'全唐诗/poet.song.65000.json','["滿酌聊酬菊蕊黄，登高仍在太山陽。", "笑談佳節賓朋集，詩酒清歡興味長。", "倦客得閒聊欲飲，老人雖醉不成狂。", "先生莫歎虀鹽久，行見高才穎出囊。"]'),
('13c5d61b-e7fa-438a-bdac-a759314affcd','謁太昊祠','張耒','宋','宋诗','song-poetry','','[]','千里垂精帝道尊，神祠近正國西門。',64,'全唐诗/poet.song.65000.json','["千里垂精帝道尊，神祠近正國西門。", "風摇廣殿松杉老，雨入修廊羽衛昏。", "日落狐狸號草莽，年豐父老薦雞豚。", "舊遊零落今誰在，塵壁蒼茫字半存。"]'),
('e4d706f5-63a1-485a-b685-d0a36f46aa4b','上元後步西園','張耒','宋','宋诗','song-poetry','','[]','物態欣欣換舊年，收燈城市却蕭然。',64,'全唐诗/poet.song.65000.json','["物態欣欣換舊年，收燈城市却蕭然。", "風光欲到冰霜樹，日月初回雨露天。", "近水遠山情脈脈，碧雲芳草思綿綿。", "酬春欲辦千缸酒，灑掃花前作醉眠。"]'),
('4d2bfeb1-3f31-4d49-8985-dc96504af6af','上元思京輦舊遊三首  其一','張耒','宋','宋诗','song-poetry','','[]','萬雉春城逼絳霄，上元雕輦盛遊遨。',64,'全唐诗/poet.song.65000.json','["萬雉春城逼絳霄，上元雕輦盛遊遨。", "遲遲瑞日低彤傘，焯焯榮光上赭袍。", "雲捲朱簾開綵雉，山盤玉闕枕仙鰲。", "長安一別將華髮，溪竹山城夜寂寥。"]'),
('23dfb24b-d233-4571-b7fb-4305017cd78a','上元思京輦舊遊三首  其二','張耒','宋','宋诗','song-poetry','','[]','九門燈火夜交光，羅綺風來撲面香。',64,'全唐诗/poet.song.65000.json','["九門燈火夜交光，羅綺風來撲面香。", "信馬恣穿深柳巷，隨身偷看隔簾妝。", "身居薄宦安知樂，心逐流年暗減狂。", "留滯山城莫嗟歎，貂蟬從古屬金張。"]'),
('d88adef1-4084-43fd-87cd-2015251d287d','上元思京輦舊遊三首  其三','張耒','宋','宋诗','song-poetry','','[]','隨計當年寄玉京，一時交結盡豪英。',64,'全唐诗/poet.song.65000.json','["隨計當年寄玉京，一時交結盡豪英。", "倒觥凌亂迷籌飲，醉帽敧斜並轡行。", "仕路飛騰輸俊傑，山城憔悴感功名。", "佳晨强酌清樽酒，寒竹蕭蕭月正明。"]'),
('54f0ab0c-4efa-46b3-b5b9-a8a67f7e1186','文周翰惠酒以詩謝之','張耒','宋','宋诗','song-poetry','','[]','一夢東都白髮新，天涯同是弔靈均。',64,'全唐诗/poet.song.65000.json','["一夢東都白髮新，天涯同是弔靈均。", "讀書久誤平生事，飲酒聊娛現在身。", "漢上卧龍新得雨，江邊饑雁晚知春。", "黄髯相見應相問，爲道真成澤畔人。"]'),
('558dd4b3-1e48-43a5-8d21-81a0577731b3','金陵懷古','張耒','宋','宋诗','song-poetry','','[]','控带洪流古帝城，欲尋舊事半榛荆。',64,'全唐诗/poet.song.65000.json','["控带洪流古帝城，欲尋舊事半榛荆。", "六朝山色情終在，千古江聲憾未平。", "設險丘陵荒蔓草，带城桑柘接新耕。", "十年重到無人問，獨立東風一愴情。"]'),
('bf36eedb-4a6b-411a-9a06-e2eb4c21177c','都梁夜景','張耒','宋','宋诗','song-poetry','','[]','浩浩黄流注渺漫，南山峰嶺對巑岏。',64,'全唐诗/poet.song.65000.json','["浩浩黄流注渺漫，南山峰嶺對巑岏。", "青燈覆地嚴城夜，白月當天淮上寒。", "酒市歌呼迷客醉，畫樓燈火暗更殘。", "扁舟老客無餘事，擁褐高眠夜未闌。"]'),
('9b252803-1cba-46d9-a4fc-d9a747790fb2','大暑戲贈希古','張耒','宋','宋诗','song-poetry','','[]','去年揮汗對淮流，寒暑那知復一周。',64,'全唐诗/poet.song.65000.json','["去年揮汗對淮流，寒暑那知復一周。", "土潤何妨兼伏暑，火流行看放清秋。", "鬢鬚總白難相笑，觀廟俱閒好並遊。", "只怕樽前誇酒量，一揮百盞不言休。"]'),
('c89c2a0a-85a8-46db-ac81-b5f75e5ba05b','春晚有感','張耒','宋','宋诗','song-poetry','','[]','洛川三月鵯鵊鳴，游絮縈空塵不驚。',64,'全唐诗/poet.song.65000.json','["洛川三月鵯鵊鳴，游絮縈空塵不驚。", "茸茸草色鋪風軟，點點楊花著水輕。", "何處浮雲度天末，不妨微雨破春晴。", "江南有客增歸思，悵望汀洲蘋芷生。"]'),
('3f45aa6a-4c1a-408d-b31d-4e8e8951f63a','七月十五日希古生日以詩爲壽','張耒','宋','宋诗','song-poetry','','[]','蒼顔白髮老祠官，邂逅淮揚一笑歡。',64,'全唐诗/poet.song.65000.json','["蒼顔白髮老祠官，邂逅淮揚一笑歡。", "且可鯨吞巵滿酒，行看鶚立豸拏冠。", "壽觴滿對秋風舉，生日欣逢伏暑闌。", "閱世祝公松栢壽，從來霜雪不能寒。"]'),
('a6db2b32-504e-4466-9278-dea0ca99d764','中秋無月戲呈希古年兄','張耒','宋','宋诗','song-poetry','','[]','放逐江湖一釣舟，蕭條故國又逢秋。',64,'全唐诗/poet.song.65000.json','["放逐江湖一釣舟，蕭條故國又逢秋。", "炎凉始信來如舊，歲月相催逝不留。", "日落千蛩喧戶牖，風高一雁下汀洲。", "地無積潦蟾華好，誰買新醪作夜遊。"]'),
('ac8e985e-2542-455e-b650-b235c140a088','病肺齒痛對雪','張耒','宋','宋诗','song-poetry','','[]','擁庭晴雪照高堂，卧病悠悠廢舉觴。',64,'全唐诗/poet.song.65000.json','["擁庭晴雪照高堂，卧病悠悠廢舉觴。", "肺疾僅同園令渴，齒傷不爲幼輿狂。", "交飛翠斝知誰醉，獨嗅烏巾認舊香。", "惟有烹茶心未厭，故知淡泊味能長。"]'),
('eff6ad5e-c694-4212-9a51-7622806fb473','泊舟都梁亭二首  其一','張耒','宋','宋诗','song-poetry','','[]','旅枕無眠客夢勞，五更旁舍一鷄號。',64,'全唐诗/poet.song.65000.json','["旅枕無眠客夢勞，五更旁舍一鷄號。", "汴淮水闊浮梁小，城郭霜晴寶塔高。", "梅鎖冷香通雀啄，水翻新綠出漁篙。", "君恩許作還鄉客，肯對江蘺賦廣騷。"]'),
('3b0846bc-9f96-4cb7-9e4f-6e45ee6d2ef9','泊舟都梁亭二首  其二','張耒','宋','宋诗','song-poetry','','[]','微春已動陳根綠，晴日初流大澤澌。',64,'全唐诗/poet.song.65000.json','["微春已動陳根綠，晴日初流大澤澌。", "客路苦寒惟飲酒，老年便暖屢添衣。", "霜林背日梅遲拆，冰渚知春雁早飛。", "江上三年陳迹在，年年穿竹折梅時。"]'),
('cf3c7181-12f6-450b-93d2-c8b8817eb171','都梁雪天晚望','張耒','宋','宋诗','song-poetry','','[]','浮梁淮面欲飛騰，金碧浮屠間玉層。',64,'全唐诗/poet.song.65000.json','["浮梁淮面欲飛騰，金碧浮屠間玉層。", "古岸蕭條風捲雪，長河咽絕水浮冰。", "留連淮汴殘年客，蹭蹬塵埃一老僧。", "聞道都梁梅未拆，可隨桃李畏嚴凝。"]'),
('f3a69140-58aa-49c4-9eb5-34149799d482','大雪中李提舉惠玻璃泉兩榼二首  其一','張耒','宋','宋诗','song-poetry','','[]','南山春雪凍雲凝，暗火青燈急霰聲。',64,'全唐诗/poet.song.65000.json','["南山春雪凍雲凝，暗火青燈急霰聲。", "栗烈殘年新慶雪，玻璃美酒舊知名。", "饑腸未慣猶空吼，凍臉何知輒妄赬。", "隠忍且須留一榼，晴明待作探梅行。"]'),
('9126ffb5-0de7-499f-9b9d-752e42ee7726','大雪中李提舉惠玻璃泉兩榼二首  其二','張耒','宋','宋诗','song-poetry','','[]','峰高凍雪埋蒼玉，河靜黄沙咽濁流。',64,'全唐诗/poet.song.65000.json','["峰高凍雪埋蒼玉，河靜黄沙咽濁流。", "嗟我殘年爲遠客，煩君雙榼散羈愁。", "屠蘇禦歲將傳盞，綵勝宜春欲插頭。", "痛飲須知謀日富，無田何用慶來麰。"]'),
('53bce0f4-61aa-42e7-95a0-1b680710df78','戲贈張嘉甫','張耒','宋','宋诗','song-poetry','','[]','鐵鎖沉淵誰敢干，塔中古佛澹無言。',64,'全唐诗/poet.song.65000.json','["鐵鎖沉淵誰敢干，塔中古佛澹無言。", "歲窮故里何時到，舟泊危亭盡日閒。", "博士虀鹽稀把酒，腐儒冰葛慣衝寒。", "籃輿未怯浮梁險，興發猶能走馬鞍。"]'),
('923a8c77-a5c4-48b6-a197-b141bfd83638','舟中書事','張耒','宋','宋诗','song-poetry','','[]','久客益知行路難，鏡中雙鬢不須看。',64,'全唐诗/poet.song.65000.json','["久客益知行路難，鏡中雙鬢不須看。", "山川積雪堅冰地，舟楫長淮古汳間。", "饋費主人勤俗禮，書來故里勸加餐。", "北歸漸踏塵埃道，盡日危亭且看山。"]'),
('8a708e7f-b26d-4a4a-9a89-71a156230f0d','戲同小兒作望南京內門','張耒','宋','宋诗','song-poetry','','[]','別都制度擬王畿，雙闕岧嶢望太微。',64,'全唐诗/poet.song.65000.json','["別都制度擬王畿，雙闕岧嶢望太微。", "萬乘旂常難望幸，九天樓觀自相輝。", "百年龍虎興王氣，萬雉金湯却敵威。", "一夢江南尚淹泊，風塵似欲變征衣。"]'),
('5bb7390c-ff21-4616-8203-af4c97aae3c0','同榮子邕登石家寺閣','張耒','宋','宋诗','song-poetry','','[]','高樓南望一傷神，靄靄東風萬里春。',64,'全唐诗/poet.song.65000.json','["高樓南望一傷神，靄靄東風萬里春。", "地闊山川圍白日，天低觀闕近浮雲。", "驚心鳥語知時好，照眼花枝著意新。", "不是蓴羹勝羊酪，素衣真怕洛陽塵。"]'),
('579c4526-f519-43c3-ac21-86099db80495','不出偶成二首  其一','張耒','宋','宋诗','song-poetry','','[]','老人杖履一茅亭，花謝西園不復扃。',64,'全唐诗/poet.song.65000.json','["老人杖履一茅亭，花謝西園不復扃。", "翠被一方都蓋覆，紅妝數子尚娉婷。", "可憐鶯蝶狂都歇，頗覺風雲意有營。", "聞說陂田雨三尺，遠城釃水種春秔。"]'),
('62a0bde1-4ce2-419f-a745-647dd9dee173','不出偶成二首  其二','張耒','宋','宋诗','song-poetry','','[]','結茅亭下小池新，積雨通溝灧晚春。',64,'全唐诗/poet.song.65000.json','["結茅亭下小池新，積雨通溝灧晚春。", "風掠塵埃出明鏡，影吞林木卧青雲。", "泥中蘋藻生無數，江上鵁鶄坐得聞。", "太液漸臺深斗極，乘閒杖履得相親。"]'),
('359e8bb8-e983-4df9-a52b-e5c94eca0724','和李令放稅','張耒','宋','宋诗','song-poetry','','[]','晚田既廢麥初耕，冠蓋侵星獨出城。',64,'全唐诗/poet.song.65000.json','["晚田既廢麥初耕，冠蓋侵星獨出城。", "但見饑寒號歲晚，不聞簫鼓賽秋成。", "倉無農父千斯慶，稅比周人什一輕。", "撫字從來須守令，莫辜聖世念疲氓。"]'),
('8be00aa8-d568-4144-976c-72fd19236477','贈无咎','張耒','宋','宋诗','song-poetry','','[]','快哉亭下水連城，落日斷霞相映明。',64,'全唐诗/poet.song.65000.json','["快哉亭下水連城，落日斷霞相映明。", "人在捲簾尊俎裏，詩從揮麈笑談生。", "揚州何遜風流在，江夏黄香句法清。", "□□□□□□□，□□□□□□□。"]'),
('a28d7929-b4a2-4b35-9a0e-c4f3789471bc','萬松亭有感','張耒','宋','宋诗','song-poetry','','[]','犖确山行穿翠微，石雲秋露濕秋衣。',64,'全唐诗/poet.song.65000.json','["犖确山行穿翠微，石雲秋露濕秋衣。", "朦朧小睡還成夢，諷詠新詩且療饑。", "千里歸來人事改，四年辛苦舊容非。", "祇應亭下青雲蓋，依舊蒼腰聳十圍。"]'),
('d48281b4-db0a-4f2a-b51a-78d269964edd','送婿陳景初還錢塘','張耒','宋','宋诗','song-poetry','','[]','乃翁風節老彌堅，嗣子清修學有傳。',64,'全唐诗/poet.song.65000.json','["乃翁風節老彌堅，嗣子清修學有傳。", "爲愛詩書賢事業，肯羞葛練拙包纏。", "經年上國勞歸夢，一棹寒流放去船。", "飽讀陳編勤筆硯，書來寄我好文編。"]'),
('b9d9f4a3-555f-4895-9fd5-e014294daa86','登懸瓠城感吳李事','張耒','宋','宋诗','song-poetry','','[]','將軍戈甲從天下，丞相旌旗匝地來。',64,'全唐诗/poet.song.65000.json','["將軍戈甲從天下，丞相旌旗匝地來。", "堪笑怒螳猶强臂，不知蟄戶欲驚雷。", "咄嗟武相深冤洗，指顧山東逆境開。", "吏部聲名千古在，段碑何處卧蒼苔。"]'),
('075782b9-74b0-4ebe-b32c-8f16d140a909','二月十七日欲招客飲而風霾不果有作','張耒','宋','宋诗','song-poetry','','[]','欲携佳客燕高堂，園館春風又作狂。',64,'全唐诗/poet.song.65000.json','["欲携佳客燕高堂，園館春風又作狂。", "猶挾冰霜餘意氣，未分桃李好風光。", "青山無頼藏雲岫，流水生波灧野塘。", "不飲何妨還燕坐，閉門掃地獨焚香。"]'),
('a867e06e-4784-4d4a-9bb0-2b24557f6fd3','鴻軒下有薔薇予初至時生意蓋僅存耳予爲灌溉壅護今年春遂大盛仲春著花數百萼大幾如芍藥豐盛妍麗頃所未見也余有黄州之行酌酒賞別','張耒','宋','宋诗','song-poetry','','[]','堂下薔薇親灌溉，辛勤纔見一春花。',64,'全唐诗/poet.song.65000.json','["堂下薔薇親灌溉，辛勤纔見一春花。", "時如轉轂無停軌，客似飛鴻不定家。", "一歲相邀伴寂寞，明年誰復對芳華。", "驅車又向黄州去，風月相望一歎嗟。"]'),
('09a57241-de39-4915-ac44-1eb64920f4f9','早登望嵩樓望少室雪畏風不敢招客','張耒','宋','宋诗','song-poetry','','[]','臨汝城中春雪消，望嵩樓上對岧嶢。',64,'全唐诗/poet.song.65000.json','["臨汝城中春雪消，望嵩樓上對岧嶢。", "已披氛霧呈孤秀，未許春寒上泬寥。", "子晉玉笙如不隔，浮丘仙袂欲相招。", "便思喚客同清賞，苦畏春風入敝貂。"]'),
('9619ffea-7d92-4d1e-9d0b-53bf56c07412','下春風嶺','張耒','宋','宋诗','song-poetry','','[]','東歸已過春風嶺，度盡千山路漸平。',64,'全唐诗/poet.song.65000.json','["東歸已過春風嶺，度盡千山路漸平。", "人事水泡能幾日，流光駒隙却堪驚。", "居人落落多新屋，行店依依認舊程。", "世事飽諳身已老，區區來往笑浮生。"]'),
('2e2b5bc1-8bbf-4432-9f24-9977978082df','江亭別故人','張耒','宋','宋诗','song-poetry','','[]','津亭把酒燕西東，無復餘花一點紅。',64,'全唐诗/poet.song.65000.json','["津亭把酒燕西東，無復餘花一點紅。", "農事一春荒積雨，長淮千里駕東風。", "休談世事循環外，且寄騷愁醉眼中。", "船鼓已鳴篙纜起，客行何事亦匆匆。"]'),
('90a66c5b-4e09-4736-aa38-15b6562ee8f6','讀黄魯直詩','張耒','宋','宋诗','song-poetry','','[]','江南宿草一荒丘，試讀遺編涕不收。',64,'全唐诗/poet.song.65000.json','["江南宿草一荒丘，試讀遺編涕不收。", "不踐前人舊行迹，獨驚斯世擅風流。", "一尊華髮江邊客，萬里黄茅嶺外州。", "虎豹磨牙九關邃，重華可訴且南遊。"]'),
('eb87b2c3-fb2a-49a4-8933-a11858d1a9fe','登城隍廟','張耒','宋','宋诗','song-poetry','','[]','靈祠孤絕壓城頭，下瞰清濠一曲流。',64,'全唐诗/poet.song.65000.json','["靈祠孤絕壓城頭，下瞰清濠一曲流。", "盡日風埃昏几席，有時簫鼓祭春秋。", "西瞻太昊祠千樹，北望封君土一丘。", "旅客登臨一長望，春心容易起騷愁。"]'),
('395bfd52-98db-4342-810e-164c106711d7','奉議楊君予姊丈也廉靜樂道不交世俗造道微妙自得不耀未六十而終予實銘其墓其子克一又纂其遺文求書卷末懷想平昔不知涕之橫集也','張耒','宋','宋诗','song-poetry','','[]','楊君冢木已蕭蕭，筆墨遺文久寂寥。',64,'全唐诗/poet.song.65000.json','["楊君冢木已蕭蕭，筆墨遺文久寂寥。", "墮淚交親悲宿草，長饑奴僕守空瓢。", "平生好事誰能繼，後世高名骨已消。", "欲酌一杯澆墓隧，遺魂楚些倘能招。"]'),
('e5b8255a-2454-46cb-a680-c1252bf5b1a9','老舅寓陳諸况不能盡布以二詩代書得閒爲和佳也  其一','張耒','宋','宋诗','song-poetry','','[]','欲知老子居陳事，古寺蕭條屋數楹。',64,'全唐诗/poet.song.65000.json','["欲知老子居陳事，古寺蕭條屋數楹。", "幸免絕糧慚孔聖，更無環堵羨淵明。", "參差拙句何曾是，寵辱浮雲無可驚。", "斷送光陰須美酒，惟應此事費經營。"]'),
('36af881c-7a14-4e94-adb1-4e245e55bb76','老舅寓陳諸况不能盡布以二詩代書得閒爲和佳也  其二','張耒','宋','宋诗','song-poetry','','[]','浮生已老付悠悠，未免饑寒目下憂。',64,'全唐诗/poet.song.65000.json','["浮生已老付悠悠，未免饑寒目下憂。", "全仗黄庭能却老，那堪白髮更悲秋。", "所欣耳界常清浄，漸放心君得自由。", "壘塊苦消消未盡，每逢風月亦閒愁。"]'),
('09d2722d-5464-4f88-a9bb-00fe8d1c2bf9','贈邠老','張耒','宋','宋诗','song-poetry','','[]','衰疲坐甑極蒸噓，念子柯山守舊廬。',64,'全唐诗/poet.song.65000.json','["衰疲坐甑極蒸噓，念子柯山守舊廬。", "盧叟今無僧送米，董生時有吏徵租。", "上書自薦心應恥，扶策躬耕計未疏。", "虎豹九關今肅穆，王門行看曳長裾。"]'),
('3e36e200-1823-4a16-b42b-d36de9500deb','仲夏','張耒','宋','宋诗','song-poetry','','[]','雲間趙盾益可畏，淵底武侯方熟眠。',64,'全唐诗/poet.song.65000.json','["雲間趙盾益可畏，淵底武侯方熟眠。", "若無一雨爲施澤，直恐三伏便欲然。", "算商酤酒有底急，束带坐曹真欲顛。", "平生不解作熱客，且復飽食窺陳編。"]'),
('51b90846-7f89-4a9f-aa3c-7172ba2d95d1','過泗州推官王永年致仕還鄉王年四十而致仕士大夫所少也','張耒','宋','宋诗','song-poetry','','[]','爲憶田園便拂衣，休官退勇似君稀。',64,'全唐诗/poet.song.65000.json','["爲憶田園便拂衣，休官退勇似君稀。", "塵埃擺脫青衫去，閭里驚嗟白髮稀。", "南畝稻粱仍歲熟，舊山芝朮入秋肥。", "百年從此皆閒日，寄語人間浪是非。"]'),
('4c95baab-53a0-41fb-83ca-36714732baff','依韵和范三登淮亭','張耒','宋','宋诗','song-poetry','','[]','身如客雁寄汀洲，北望休登王粲樓。',64,'全唐诗/poet.song.65000.json','["身如客雁寄汀洲，北望休登王粲樓。", "殘雪朔風驚歲晚，早梅新柳動春愁。", "免遭斤斧甘無用，敢向波濤較善游。", "奔走塵埃欲歸去，勒移恐作故山羞。"]'),
('be6fc2df-ce62-48d8-a647-1e97dfa82803','離山陽入都寄徐仲車','張耒','宋','宋诗','song-poetry','','[]','孤城芳樹碧層層，村落黄昏只見燈。',64,'全唐诗/poet.song.65000.json','["孤城芳樹碧層層，村落黄昏只見燈。", "迴首事如前夕夢，出門心似下山僧。", "仕求行道時難偶，意欲謀閒力不能。", "寄語東皋多釀酒，待予歸日解行縢。"]'),
('a964081b-b93f-4a13-b16b-1ddade530cdd','題淮陰孫簿壁','張耒','宋','宋诗','song-poetry','','[]','荒凉官舍對淮流，樽酒相逢爲少留。',64,'全唐诗/poet.song.65000.json','["荒凉官舍對淮流，樽酒相逢爲少留。", "夾道老椿鴉哺子，隔牆荒草牧呼牛。", "渡頭人散前村市，天際帆來何處舟。", "自古詩人最多感，新篇應解寫騷愁。"]'),
('8132ac12-9b52-4a36-818c-9999c6beed70','題洪澤亭','張耒','宋','宋诗','song-poetry','','[]','三年淮海飄萍客，今日亭邊再艤舟。',64,'全唐诗/poet.song.65000.json','["三年淮海飄萍客，今日亭邊再艤舟。", "人似垂楊隨日老，事如流水幾時休。", "閒於萬事常難得，仕以爲生最拙謀。", "此世定知猶幾至，遑遑奔走欲何求。"]'),
('0d5a9115-e3f3-4d69-b685-82d39e6adca9','宿泗州戒壇院','張耒','宋','宋诗','song-poetry','','[]','樓上鳴鐘門夜扃，風簷送雨入疏櫺。',64,'全唐诗/poet.song.65000.json','["樓上鳴鐘門夜扃，風簷送雨入疏櫺。", "老僧坐睡依深壁，童子持經守暗燈。", "千里塵埃長旅泊，五年憂患困侵凌。", "誰知避世天然子，一見禪翁便服膺。"]'),
('ba694bf8-542d-4d8b-aceb-2b5b62c955b2','宿柳子觀音寺','張耒','宋','宋诗','song-poetry','','[]','黄塵滿道客衣穿，古寺荒凉暫息肩。',64,'全唐诗/poet.song.65000.json','["黄塵滿道客衣穿，古寺荒凉暫息肩。", "倦體收來便穩榻，汗顔濯去快寒泉。", "野僧治飯挑蔬至，童子携茶對客煎。", "夜久月高風鐸響，木魚呼覺五更眠。"]'),
('ad12a0c4-d218-4248-a83b-59803e6352f9','寄滁州邵子發同年二首  其一','張耒','宋','宋诗','song-poetry','','[]','夫子才豪官尚卑，窮城冷落有誰知。',64,'全唐诗/poet.song.65000.json','["夫子才豪官尚卑，窮城冷落有誰知。", "莫嫌五斗紆高興，且與青山賦好詩。", "得失可齊陶令酒，功名休問蜀莊蓍。", "三年流落甘憂患，一笑何當慰別離。"]'),
('e3c6b1d3-e3b7-4091-95f1-12a24a1d9547','寄滁州邵子發同年二首  其二','張耒','宋','宋诗','song-poetry','','[]','年來萬事付禪宗，兩鬢雖青心已翁。',64,'全唐诗/poet.song.65000.json','["年來萬事付禪宗，兩鬢雖青心已翁。", "欲借一廛希許子，更將五斗繼無功。", "春來行樂君應厭，老去裁詩我未工。", "聞道琅邪山色好，爲題新句寄清風。"]'),
('f1942325-a14b-4abb-b2ea-b56b9d47848b','雁','張耒','宋','宋诗','song-poetry','','[]','知時避就物之難，千里蕭蕭振羽翰。',64,'全唐诗/poet.song.65000.json','["知時避就物之難，千里蕭蕭振羽翰。", "水國稻收朝食乏，海天霜重夜飛寒。", "烟雲秋去南山暖，風日春歸朔野寬。", "九萬騰凌那可測，弋人矰繳漫多端。"]'),
('a2836188-f122-4c97-bad3-b73fabab25df','己未早春有感','張耒','宋','宋诗','song-poetry','','[]','南國柳黄鶯未知，人情何事憾春遲。',64,'全唐诗/poet.song.65000.json','["南國柳黄鶯未知，人情何事憾春遲。", "雪抽宿麥晴來葉，雨長枯榆燒後枝。", "載酒有誰尋寂寞，受薪只合學支離。", "近知壁觀安心法，亦擬平治不作詩。"]'),
('ebe170bf-c47e-4593-b663-b78529eac13d','同袁思正諸公登楚州東園樓','張耒','宋','宋诗','song-poetry','','[]','杖藜蕭颯對雲沙，白首逢春只歎嗟。',64,'全唐诗/poet.song.65000.json','["杖藜蕭颯對雲沙，白首逢春只歎嗟。", "身老易傷千里目，眼驚還見一年花。", "地平曠野連雲直，天带清淮向海斜。", "尚有風光供醉筆，我生詩酒是生涯。"]'),
('b9b1dd95-e600-48e6-9201-3cf8f62d62da','和宏父新秋詩','張耒','宋','宋诗','song-poetry','','[]','年年庭下梧桐葉，長爲騷人先報秋。',64,'全唐诗/poet.song.65000.json','["年年庭下梧桐葉，長爲騷人先報秋。", "已驚歲月悲霜鬢，更望山川歌四愁。", "浮生百感漫自苦，一醉萬慮同時休。", "瀛洲仙客莫惆悵，直泛三山烟浪舟。"]'),
('043a3b75-06f4-4fc7-9c88-bd958938ae73','送江瞻道之汝陰尉','張耒','宋','宋诗','song-poetry','','[]','少年相見已蹉跎，千里分携可奈何。',64,'全唐诗/poet.song.65000.json','["少年相見已蹉跎，千里分携可奈何。", "世路險艱知子少，人間憂患屬予多。", "二年窮巷山陽客，一棹清風潁水波。", "我爲離居感身世，援琴西望獨悲歌。"]'),
('766604ab-b5ec-4c9c-9b17-73bb01e75fc1','同周楚望飲華園','張耒','宋','宋诗','song-poetry','','[]','杖藜携手踏青苔，瀟洒池亭爲客開。',64,'全唐诗/poet.song.65000.json','["杖藜携手踏青苔，瀟洒池亭爲客開。", "柳色漸經秋雨暗，荷香時與好風來。", "斜陽似欲粧詩句，新月邀將入酒杯。", "身世已甘長寂寞，忘形頼有子徘徊。"]'),
('597840ab-5102-4ef6-87d8-9444de291170','登楚望北樓','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','裊裊危樓百尺梯，秋風有客獨攀躋。',64,'全唐诗/poet.song.65000.json','["裊裊危樓百尺梯，秋風有客獨攀躋。", "路窮流水遠更遠，目斷夕陽西復西。", "簾卷似迎輕燕入，柳深時有暗蟬嘶。", "洞庭落葉悲騷客，鵯鵊何勞著意啼。"]'),
('e3ad8799-8e33-452d-9b14-74d4595585c1','赴官壽安泛汴二首  其一','張耒','宋','宋诗','song-poetry','','[]','西來秋興日蕭條，昨夜新霜緝縕袍。',64,'全唐诗/poet.song.65000.json','["西來秋興日蕭條，昨夜新霜緝縕袍。", "開遍菊花殘蕊盡，落餘寒水舊痕高。", "蕭蕭官樹皆黄葉，處處村旗有濁醪。", "老補一官西入洛，幸聞山水頗風騷。"]'),
('4786bf5d-7cb4-42d2-bcc6-9a87a2cf0e56','赴官壽安泛汴二首  其二','張耒','宋','宋诗','song-poetry','','[]','落泊雲隨宿雨開，西風似與早寒催。',64,'全唐诗/poet.song.65000.json','["落泊雲隨宿雨開，西風似與早寒催。", "曉天雁起平沙去，霜岸風鳴敗葉來。", "擾擾勞生移歲月，紛紛過眼旋塵埃。", "求田問舍真良策，功業應須與命偕。"]'),
('3e07bbe4-a906-44e4-9b3d-7a3da904c03d','過少室','張耒','宋','宋诗','song-poetry','','[]','驅車繼日未知勞，翠靄嵐光下褐袍。',64,'全唐诗/poet.song.65000.json','["驅車繼日未知勞，翠靄嵐光下褐袍。", "日暖峰巒開少室，雪餘松柏近嵩高。", "山行歲晚風霜苦，地勢西來氣象豪。", "勝事欲歌紛滿目，烟霞深處欲誅茅。"]'),
('0ade4c07-23a2-45f2-ba5d-9c83c9d0db14','寄蔡彥規兼謝惠酥梨二首  其一','張耒','宋','宋诗','song-poetry','','[]','自煮新酥籠旋開，秦霜猶污紫梨腮。',64,'全唐诗/poet.song.65000.json','["自煮新酥籠旋開，秦霜猶污紫梨腮。", "舊園歌舞唐宮廢，灌頂醍醐佛國來。", "寄我遠傳千里意，憾君不舉百分杯。", "西來新味饒鄉思，淮蟹湖魚幾日迴。"]'),
('c3d8e970-57c0-4cc7-b614-dce254b1940d','寄蔡彥規兼謝惠酥梨二首  其二','張耒','宋','宋诗','song-poetry','','[]','洛川北岸錦屏西，竹樹蕭蕭面翠微。',64,'全唐诗/poet.song.65000.json','["洛川北岸錦屏西，竹樹蕭蕭面翠微。", "風月有情常似舊，山川信美不如歸。", "文章送老甘無用，魚鳥從游久息機。", "寄語長安倦游客，年來何事素書稀。"]'),
('441d397e-82b7-41d1-b799-11042b66705e','三鄉懷古','張耒','宋','宋诗','song-poetry','','[]','清洛東流去不還，漢唐遺事有無間。',64,'全唐诗/poet.song.65000.json','["清洛東流去不還，漢唐遺事有無間。", "廟荒古木連空谷，宮廢春蕪入亂山。", "南陌絮飛人寂寂，空城花落鳥關關。", "登臨幾度遊人老，又對東風鬢欲斑。"]'),
('eec40a72-9e00-4c89-8753-192a9068963f','壽安懷古','張耒','宋','宋诗','song-poetry','','[]','蕭王積甲事空傳，子晉吹笙去不還。',64,'全唐诗/poet.song.65000.json','["蕭王積甲事空傳，子晉吹笙去不還。", "千里荒蕪山色在，百年興廢水聲間。", "雉飛隴麥新耕地，花落叢祠舊戰關。", "旅宦遠遊仍弔古，苦無樽酒奈愁顔。"]'),
('ce42be8e-1a8e-4018-a081-3c6186ea2c46','水軒書事招壽安僚友','張耒','宋','宋诗','song-poetry','','[]','官閒不覺簿書勞，一簟清風午枕高。',64,'全唐诗/poet.song.65000.json','["官閒不覺簿書勞，一簟清風午枕高。", "靜拂小屏圖女几，就書新竹記離騷。", "城空鬭雉孤飛健，柳暗雛鶯學語嬌。", "東縣官曹誰過我，欲沽村酒具山庖。"]'),
('3d851eea-c242-405b-ae49-50144a776e58','連昌宮','張耒','宋','宋诗','song-poetry','','[]','長安王氣已消磨，弔古遺墟恨愴多。',64,'全唐诗/poet.song.65000.json','["長安王氣已消磨，弔古遺墟恨愴多。", "宮殿成塵新草木，丘陵無主故山河。", "雨餘耕隴尋遺寶，夜靜溪泉響細波。", "才子已銷泉下骨，百年獨諷舊時歌。"]'),
('a51ca17a-cdc0-48d4-aecf-1fadbc9c2b91','觀洛漲','張耒','宋','宋诗','song-poetry','','[]','雨鎖山川晝不開，洛波一夕漲如催。',64,'全唐诗/poet.song.65000.json','["雨鎖山川晝不開，洛波一夕漲如催。", "西來勢蹴諸山動，東轉聲包厚地迴。", "一片曉光吳陣甲，萬桴南響會稽雷。", "何人共此乘桴志，直到蓬瀛亦壯哉。"]'),
('4d4fd8f6-6b8c-4be6-8372-19f17f966f14','芳華閣','張耒','宋','宋诗','song-poetry','','[]','玉仗無蹤輦路摧，舊名猶得榜高臺。',64,'全唐诗/poet.song.65000.json','["玉仗無蹤輦路摧，舊名猶得榜高臺。", "月斜曉樹鳴鵯鵊，日暖春蕪放雉媒。", "清洛夜聲縈谷轉，錦屏晴色照人來。", "悽凉滿眼興亡恨，誰是蕪城作賦才。"]'),
('f097ee62-814b-4c2e-bf17-36d70efd3c0d','福昌雜詠五首  其一','張耒','宋','宋诗','song-poetry','','[]','張翰飄然欲鱠鱸，周南久客意何如。',64,'全唐诗/poet.song.65000.json','["張翰飄然欲鱠鱸，周南久客意何如。", "風悲故國荆榛地，日落空城雉兔墟。", "明月搗衣聞洛杵，故人憑雁寄南書。", "旅歌辛苦空彈鋏，誰念朝盤未食魚。"]'),
('6ff98fa1-7899-439a-bfe3-4bf826f9bf54','福昌雜詠五首  其二','張耒','宋','宋诗','song-poetry','','[]','東望川原拱別都，漢唐冠蓋已丘墟。',64,'全唐诗/poet.song.65000.json','["東望川原拱別都，漢唐冠蓋已丘墟。", "地橫嵩少雄中夏，天險轘轅困萬夫。", "宮殿荒凉興廢恨，山河慘淡戰爭餘。", "登臨不見淮南道，只有風塵滿客裾。"]'),
('4cfe724e-6f6a-4508-a2b7-32feb0a449a9','福昌雜詠五首  其三','張耒','宋','宋诗','song-poetry','','[]','乘雲飛去不辭家，女几荒祠一逕斜。',64,'全唐诗/poet.song.65000.json','["乘雲飛去不辭家，女几荒祠一逕斜。", "溪入亂雲鳴珮玦，樹蟠蒼石老龍蛇。", "夜寒玉鏡懸清月，天碧霓衣曳彩霞。", "陵谷易遷塵骨老，衰顔更欲服丹砂。"]'),
('c92c5880-9c9a-4ab0-8639-27eabf544992','福昌雜詠五首  其四','張耒','宋','宋诗','song-poetry','','[]','天倚岡巒翠萬重，倚樓搔首更書空。',64,'全唐诗/poet.song.65000.json','["天倚岡巒翠萬重，倚樓搔首更書空。", "莓苔古屋荒秋雨，草木空山起夜風。", "漢帛北來邀塞雁，楚招南望憶江楓。", "塵埃流落悲生事，白髮年來擬見攻。"]'),
('920d06e1-2a86-48d6-be58-a913953a240d','福昌雜詠五首  其五','張耒','宋','宋诗','song-poetry','','[]','滿目凄凉供客愁，斷霞殘照想滄洲。',64,'全唐诗/poet.song.65000.json','["滿目凄凉供客愁，斷霞殘照想滄洲。", "風雲蕭瑟三川夜，星斗縱橫萬壑秋。", "騎省衰遲空作賦，荆蠻留滯感登樓。", "迷魂不待巫陽些，自有騷詞繼遠遊。"]'),
('5d3dc4b1-517c-4763-ad30-497d7b0de1e5','福昌','張耒','宋','宋诗','song-poetry','','[]','故苑芳華路已迷，連昌宮闕露沾衣。',64,'全唐诗/poet.song.65000.json','["故苑芳華路已迷，連昌宮闕露沾衣。", "繁華冠蓋當時事，戰伐山河萬古悲。", "野色蒼凉新雨地，秋聲蕭瑟夕陽枝。", "塵埃未有東歸計，天畔登臨且賦詩。"]'),
('81ab3f17-c149-4002-a8a2-9607bb27c1ab','牛谷口','張耒','宋','宋诗','song-poetry','','[]','十萬全師一戰擒，谷盤蒼硤路幽深。',64,'全唐诗/poet.song.65000.json','["十萬全師一戰擒，谷盤蒼硤路幽深。", "凄凉今古興亡事，遼闊英雄割據心。", "漲洛暮連諸谷雨，秋雲低抱半山陰。", "文皇功業今何處，磨滅荒碑蔓草侵。"]'),
('0e96b25a-3e41-4a25-9d20-7681b4046386','歸馬二首  其一','張耒','宋','宋诗','song-poetry','','[]','歸馬駸駸不受鞭，晚霞如畫照晴川。',64,'全唐诗/poet.song.65000.json','["歸馬駸駸不受鞭，晚霞如畫照晴川。", "蕭疏黄葉孤舟岸，零落秋雲斷雁天。", "臨水登山悲楚客，烹雞酌酒愛諸仙。", "任從老逐霜毛至，莫遣愁來玉盞邊。"]'),
('1a7fcc9c-67ae-40c2-8d39-234ba94a84c0','歸馬二首  其二','張耒','宋','宋诗','song-poetry','','[]','蕭蕭霜鬢獨驚秋，病眼天邊暮倚樓。',64,'全唐诗/poet.song.65000.json','["蕭蕭霜鬢獨驚秋，病眼天邊暮倚樓。", "已老馮唐猶不遇，思歸庾信正多愁。", "溪通積雨流方壯，山入重雲翠未休。", "一夢淮南經歲別，菊林還向洛陽浮。"]'),
('5223511a-0036-4bf2-b502-708805a0f82e','官舍歲暮感懷書事五首  其一','張耒','宋','宋诗','song-poetry','','[]','衙鼓鼕鼕送夕陽，經時無客上高堂。',64,'全唐诗/poet.song.65000.json','["衙鼓鼕鼕送夕陽，經時無客上高堂。", "淵明柳老秋多雨，子敬氈寒夜有霜。", "山樹葉稀晴摘果，齋爐灰煖曉焚香。", "經綸自有英雄在，閒散須教屬漫郎。"]'),
('3f9371eb-ba2b-4001-8b91-4c17c79b983c','官舍歲暮感懷書事五首  其二','張耒','宋','宋诗','song-poetry','','[]','修竹高槐交映門，公居瀟灑近山雲。',64,'全唐诗/poet.song.65000.json','["修竹高槐交映門，公居瀟灑近山雲。", "醉眠多似陶彭澤，官况貧於鄭廣文。", "秋菊擣塵供曉餌，寒松收子和香焚。", "經年門巷無車馬，只有清風伴此君。"]'),
('770afacd-dfe1-4e79-9cd1-5287665d22ce','官舍歲暮感懷書事五首  其三','張耒','宋','宋诗','song-poetry','','[]','霜菊娟娟尚有花，蕭條廳樹暮啼鴉。',64,'全唐诗/poet.song.65000.json','["霜菊娟娟尚有花，蕭條廳樹暮啼鴉。", "萬竿修竹開侯府，十里青山隠相家。", "麋鹿並遊諳野性，詩書相對是生涯。", "冷官自有貧中樂，敢向朱門肉食誇。"]'),
('e504663a-066a-4775-98b0-6f66beb242ae','官舍歲暮感懷書事五首  其四','張耒','宋','宋诗','song-poetry','','[]','北風吹雁去翩翩，流滯周南又一年。',64,'全唐诗/poet.song.65000.json','["北風吹雁去翩翩，流滯周南又一年。", "田爲歲荒陶令秫，酒無人乞廣文錢。", "香籠鉢水清晨咒，坐暖蒲團後夜禪。", "更謝晴明好山色，數峰殘雪在簷前。"]'),
('985b9824-f980-4407-9a4c-d0fd9be1c734','官舍歲暮感懷書事五首  其五','張耒','宋','宋诗','song-poetry','','[]','筆床茶竈素圍屏，瀟洒幽齋燈火明。',64,'全唐诗/poet.song.65000.json','["筆床茶竈素圍屏，瀟洒幽齋燈火明。", "木落風霜初十月，坐寒星斗欲三更。", "消磨永夜書盈案，分付閒愁酒滿觥。", "干世愈疏身漸老，官閒何苦厭山城。"]'),
('3c5ad86c-7d9e-4ab0-bb2a-85a3c14355d9','望女几雪','張耒','宋','宋诗','song-poetry','','[]','萬戟高攢女几晴，卷簾初見雪崢嶸。',64,'全唐诗/poet.song.65000.json','["萬戟高攢女几晴，卷簾初見雪崢嶸。", "光迎曉日峰千疊，氣入陰風夜五更。", "晴色北臨秦甸白，寒威東抱洛陽清。", "坐看溝壑承餘澤，付與春田次第耕。"]'),
('aa39df0b-ef05-4234-af05-3dc9ead7d546','永濟橋','張耒','宋','宋诗','song-poetry','','[]','墟廟無人弔毀垣，故橋遺址至今存。',64,'全唐诗/poet.song.65000.json','["墟廟無人弔毀垣，故橋遺址至今存。", "侵波野岸生新草，齧石老沙留舊痕。", "金殿有基藏兔穴，玉輿無路半樵村。", "甘棠古道輪蹄斷，落日空山暮雨昏。"]'),
('2cd0827e-4ebd-41ac-a612-c58d5b3f57c1','雪晴野望','張耒','宋','宋诗','song-poetry','','[]','蕭蕭空谷隠山雲，渡水人歸何處村。',64,'全唐诗/poet.song.65000.json','["蕭蕭空谷隠山雲，渡水人歸何處村。", "樵逕雪迷唐苑路，鳥聲寒集漢祠門。", "公堂吏散惟修竹，近嶺林疏見飲猿。", "客坐無氈君莫笑，陶潜亦有酒盈樽。"]'),
('7ef43a37-c5ea-46b7-8504-a87967ec2215','福昌南望','張耒','宋','宋诗','song-poetry','','[]','朝市推遷不復還，暮雲平野水潺潺。',64,'全唐诗/poet.song.65000.json','["朝市推遷不復還，暮雲平野水潺潺。", "山川寂寞繁華後，都邑蕭條魚鳥閒。", "鶴柱千年無故老，仙棋一局換人間。", "興亡今古知何極，莫向雍琴妄慘顔。"]'),
('af7931fb-5955-4c30-bc0a-3632890bdae6','戒醉','張耒','宋','宋诗','song-poetry','','[]','平生嗜酒愛離騷，痛飲須知屬我曹。',64,'全唐诗/poet.song.65000.json','["平生嗜酒愛離騷，痛飲須知屬我曹。", "仕宦低回要斗粟，功名迂闊欲霜毛。", "直須減省樽罍費，莫厭沉迷簿領勞。", "醉吐相茵君勿恃，邴公遺事久寥寥。"]'),
('6f50c9b5-fd37-479b-a625-343242983a0f','醉宿慈氏院晨起','張耒','宋','宋诗','song-poetry','','[]','痛飲淋漓半夜醒，披衣坐待曉窗明。',64,'全唐诗/poet.song.65000.json','["痛飲淋漓半夜醒，披衣坐待曉窗明。", "風松一夕清無限，罏火三更暖有情。", "孤閣鳴鐘天黯慘，寒山戴雪晚崢嶸。", "年來漸向深杯怯，强學劉伶欲解酲。"]'),
('4791585d-5864-45e9-b247-eb48b234f4a8','梅花','張耒','宋','宋诗','song-poetry','','[]','北風萬木正蒼蒼，獨占新春第一芳。',64,'全唐诗/poet.song.65000.json','["北風萬木正蒼蒼，獨占新春第一芳。", "調鼎自期終有實，論花天下更無香。", "月娥服御無非素，玉女精神不尚粧。", "洛岸苦寒相見晚，曉來魂夢到江鄉。"]'),
('1b5cd7d8-ece6-4711-8643-a06aad719528','送丁宣德赴邕州僉判','張耒','宋','宋诗','song-poetry','','[]','邕南亭障久消兵，莫厭扁舟萬里行。',64,'全唐诗/poet.song.65000.json','["邕南亭障久消兵，莫厭扁舟萬里行。", "嶺外山川從古秀，幕中談笑屬時平。", "天連漲海鵬飛近，風卷孤城颶母生。", "勿爲跕鳶思款段，古來男子重功名。"]'),
('4702074c-5cff-43b2-b7f9-0b8d97e90442','同陳器之題迎福院軒','張耒','宋','宋诗','song-poetry','','[]','東風吹面酒楹樽，臘後一番梅柳新。',64,'全唐诗/poet.song.65000.json','["東風吹面酒楹樽，臘後一番梅柳新。", "殘雪作寒山向晚，橫烟不動野浮春。", "地留京洛豪華氣，川带秦韓戰伐塵。", "今古悠悠君莫問，祇應沉醉是天真。"]'),
('46c92001-9d68-4ead-9714-30b90dee4d48','春陰二首  其一','張耒','宋','宋诗','song-poetry','','[]','漠漠重雲向晚低，臘寒新去有餘威。',64,'全唐诗/poet.song.65000.json','["漠漠重雲向晚低，臘寒新去有餘威。", "風捎簷滴難開幌，潤引爐香易著衣。", "把酒自傾金錯落，探春誰污錦障泥。", "山城冷落無歌舞，只有芳醪取次携。"]'),
('38639382-7d7d-4a5d-b7da-a47612e7c260','春陰二首  其二','張耒','宋','宋诗','song-poetry','','[]','溪樹昏昏鎖暮雲，晚山愁黛對含顰。',64,'全唐诗/poet.song.65000.json','["溪樹昏昏鎖暮雲，晚山愁黛對含顰。", "不甘小雪猶妨暖，長恨閒陰每占春。", "寶带金貂侯第客，鈿車珂馬帝京塵。", "王城自古繁華地，回首高歌悵望頻。"]'),
('5040b9cb-0c61-42ac-b550-1321d51b7c12','寒食贈遊客','張耒','宋','宋诗','song-poetry','','[]','陰陰畫幕映雕欄，一縷微香寶篆殘。',64,'全唐诗/poet.song.65000.json','["陰陰畫幕映雕欄，一縷微香寶篆殘。", "寒食園林三月近，落花風雨五更寒。", "箏調寶柱弦初穩，酒滿金壺飲未乾。", "明日踏青郊外去，綠楊門巷繫雕鞍。"]'),
('72c0861f-2796-434b-9f66-d38c1fb68a2b','登穀州故城','張耒','宋','宋诗','song-poetry','','[]','控扼兵屯事已遼，傾敧遺堞隠蓬蒿。',64,'全唐诗/poet.song.65000.json','["控扼兵屯事已遼，傾敧遺堞隠蓬蒿。", "春蕪滿野牛羊散，秋稼連雲雉兔驕。", "苔卧斷碑昏故刻，雨飄殘枿带餘燒。", "人間興廢知何極，莫謂荆榛便寂寥。"]'),
('220d97cd-8fb7-4cb1-9940-3aa5d3592a9e','東池','張耒','宋','宋诗','song-poetry','','[]','東池暮春風景妍，汩汩淺渠鳴細泉。',64,'全唐诗/poet.song.65000.json','["東池暮春風景妍，汩汩淺渠鳴細泉。", "菖蒲遶堤青似劍，荷葉出水大如錢。", "薔薇著花方未已，楊柳飛絮任飄然。", "鄰翁芍藥正足雨，預計開時須醉眠。"]'),
('aa460274-0db7-492a-8a69-ba1b9e4e37a6','暮春贈陳器之','張耒','宋','宋诗','song-poetry','','[]','牡丹開過解鞦韆，鵯鵊鳴時三月天。',64,'全唐诗/poet.song.65000.json','["牡丹開過解鞦韆，鵯鵊鳴時三月天。", "盡日好風吹絮雪，一池春水泛蓮錢。", "溪邊蒲筍供朝飯，堂上圖書伴晝眠。", "端坐窮城何所得，只收風月入新篇。"]'),
('49c7fdae-a72e-44db-b5b8-e452255774e7','離光山驛','張耒','宋','宋诗','song-poetry','','[]','郵亭結束問殘更，斜月西南雞未鳴。',64,'全唐诗/poet.song.65000.json','["郵亭結束問殘更，斜月西南雞未鳴。", "草草勞人常少睡，綿綿遠道苦無情。", "田家稔熟人情好，野路雨餘秋氣清。", "老得一州藏拙去，鵷鸞臺閣盡豪英。"]'),
('f6ed8b12-0e4e-4c3b-b913-c678b9107487','內生日','張耒','宋','宋诗','song-poetry','','[]','從我奔馳走四方，清貧殊不厭糟糠。',64,'全唐诗/poet.song.65000.json','["從我奔馳走四方，清貧殊不厭糟糠。", "黔婁環堵貧常醉，壽母高堂老亦康。", "夷險百爲吾有命，窮通一意子真剛。", "今年生日心無事，好爲兒孫舉壽觴。"]'),
('f39f4559-950a-44e1-a37f-0a8729e2ae8d','次韵張公遠二首  其一','張耒','宋','宋诗','song-poetry','','[]','襄王坐上微詞客，子建車前步水妃。',64,'全唐诗/poet.song.65000.json','["襄王坐上微詞客，子建車前步水妃。", "瞥過低鬟流盼處，爭先含笑獨來時。", "東邊日下終無雨，闕上書時合有碑。", "腸斷吳王烟水國，扁舟何日逐鴟夷。"]'),
('1df57d4d-1ed8-4457-ab12-f26d9d1189ab','次韵張公遠二首  其二','張耒','宋','宋诗','song-poetry','','[]','平淡春雲捧額浮，秋光劍戟近人流。',64,'全唐诗/poet.song.65000.json','["平淡春雲捧額浮，秋光劍戟近人流。", "無腸可斷方爲憾，有藥能治不是愁。", "可待挑琴知有術，未傳驅豆更無謀。", "遙知添得春窗夢，尤在樽前燭下羞。"]'),
('35d68b18-249b-4e6f-a142-6fa32e99c239','和陳器之謝王澠池牡丹','張耒','宋','宋诗','song-poetry','','[]','十首新詩換牡丹，故邀春色入深山。',64,'全唐诗/poet.song.65000.json','["十首新詩換牡丹，故邀春色入深山。", "御袍黄粉天然薄，醉臉胭脂分外殷。", "開晚東君留意厚，落遲晴晝伴春閒。", "狂來滿插烏紗帽，未擬尊前感鬢斑。"]'),
('b6ebb65e-812c-44a2-aad8-e40cecea3c97','和聞鶯','張耒','宋','宋诗','song-poetry','','[]','冉冉東風萬柳絲，啼鶯常自與春期。',64,'全唐诗/poet.song.65000.json','["冉冉東風萬柳絲，啼鶯常自與春期。", "妝殘玉枕朝醒後，繡倦紗窗晝夢時。", "文羽自奇非谷隠，好音應合有人知。", "風流潘令多才思，爲爾春來幾首詩。"]'),
('99e306b2-a3f7-45c6-b186-b9c29dd4a7cd','同器之遊大宋陂值雨','張耒','宋','宋诗','song-poetry','','[]','微雲護日曉陰陰，春去餘芳尚可尋。',64,'全唐诗/poet.song.65000.json','["微雲護日曉陰陰，春去餘芳尚可尋。", "詩倚醉豪連卷寫，酒逢勍敵百分斟。", "山光左右雙屏畫，雨脚崢嶸萬羽林。", "沙路晚晴歸馬疾，一梳新月上烟岑。"]'),
('84cafeef-0344-40d9-aee8-7efef163fe6c','和陳器之苦雨','張耒','宋','宋诗','song-poetry','','[]','急雨凄風未肯歸，三川烟樹遠凄迷。',64,'全唐诗/poet.song.65000.json','["急雨凄風未肯歸，三川烟樹遠凄迷。", "瀉山漲潦千霆怒，到地重雲萬幕低。", "擾擾泥塗同野鶩，蕭蕭昏曉聽鄰雞。", "爲君一借扶摇便，靜掃平郊散馬蹄。"]'),
('cd4c846d-90f0-4a4e-800f-19b61e253310','依韵和晁十七見招之什','張耒','宋','宋诗','song-poetry','','[]','斷送春光酒萬壺，敢辭羸馬爲君驅。',64,'全唐诗/poet.song.65000.json','["斷送春光酒萬壺，敢辭羸馬爲君驅。", "桑田日暖鳩呼婦，楊柳葉深鶯哺雛。", "詩冷有情尋水石，年豐無盜起萑蒲。", "河陽潘令風騷客，醉倒樽前許我無。"]'),
('cc193db0-7316-4469-8687-ef4e034a45e8','鹿仙山','張耒','宋','宋诗','song-poetry','','[]','溪清山秀隠神仙，乘鹿真人去幾年。',64,'全唐诗/poet.song.65000.json','["溪清山秀隠神仙，乘鹿真人去幾年。", "天地壺中無客到，方書肘後有誰傳。", "秦皇採藥迷蓬島，漢武燒金得紫烟。", "真境寥寥在何處，未容塵世妄攀緣。"]'),
('8cb9500a-69fa-41e2-ac15-ca8db38e30d7','寄晁應之二首  其一','張耒','宋','宋诗','song-poetry','','[]','强讀詩書歎白頭，一官飄泊寄東周。',64,'全唐诗/poet.song.65000.json','["强讀詩書歎白頭，一官飄泊寄東周。", "匏瓜有繫身難去，人足無音境更幽。", "晚接賢豪寬病思，老將文字寫離憂。", "相思一夕親談笑，夢斷雲山相對愁。"]'),
('3528d988-7b76-41dd-ae13-54d92ecefd95','寄晁應之二首  其二','張耒','宋','宋诗','song-poetry','','[]','瑜珥瑶環豁眼明，碧梧翠竹照人清。',64,'全唐诗/poet.song.65000.json','["瑜珥瑶環豁眼明，碧梧翠竹照人清。", "同車汲黯今難忮，挾彈潘郎舊有名。", "自是風流襲家世，行看談笑取公卿。", "塵埃落魄誰如我，一事無成白髮生。"]'),
('09372d07-b3fa-4388-a1c0-4bc820fcee60','喬木','張耒','宋','宋诗','song-poetry','','[]','舍北參天喬木長，依憑清蔭護高堂。',64,'全唐诗/poet.song.65000.json','["舍北參天喬木長，依憑清蔭護高堂。", "鳥啼杳杳重陰合，風到翩翩翠葉凉。", "已許孤高凌夏日，不妨堅老要秋霜。", "投身麋鹿無人地，非爾煩憂未易忘。"]'),
('04b19c6f-ae5c-4a7b-9d9a-47c97888d431','竹堂','張耒','宋','宋诗','song-poetry','','[]','誰道清貧守冷官，遶家十萬翠琅玕。',64,'全唐诗/poet.song.65000.json','["誰道清貧守冷官，遶家十萬翠琅玕。", "直應流水深相與，不待清風已自寒。", "學得鳳鳴真自許，化成龍去不終蟠。", "知君何世無來者，可是王郎獨與歡。"]'),
('36454e89-01f4-4623-962f-f854956e7268','夏日二首  其一','張耒','宋','宋诗','song-poetry','','[]','詩書老去信無功，偷得閒官許養慵。',64,'全唐诗/poet.song.65000.json','["詩書老去信無功，偷得閒官許養慵。", "山影當庭初轉日，水聲穿竹自來風。", "晚催萱蕊昏還斂，日射榴房午更紅。", "覽物賦詩成底事，蕭蕭雙鬢欲衰翁。"]'),
('ed6b66f0-14cd-4c7e-93bc-401980443ca4','夏日二首  其二','張耒','宋','宋诗','song-poetry','','[]','重雲卷雨過山來，遍洒中田到曉迴。',64,'全唐诗/poet.song.65000.json','["重雲卷雨過山來，遍洒中田到曉迴。", "錯落晴山移斗極，陰森暗峽宿風雷。", "佳人夜夜齊紈恨，騷客年年鵯鵊哀。", "欲見清秋近消息，月明白露濕蒼苔。"]'),
('9853804d-9642-425f-8672-c56a58605347','至日有感二首  其一','張耒','宋','宋诗','song-poetry','','[]','兩逢至日驚身老，遠寄周南覽物悲。',64,'全唐诗/poet.song.65000.json','["兩逢至日驚身老，遠寄周南覽物悲。", "佳節風烟長慘慘，他鄉人物自熙熙。", "荆榛崤澠秦關破，草樹芳華隋苑隳。", "悵望高歌一回首，茲辰尊酒莫相違。"]'),
('5f67a55f-065c-4d3f-82d7-c4209ffd6d63','至日有感二首  其二','張耒','宋','宋诗','song-poetry','','[]','一卧孤村兩見冬，獨搔華髮思無窮。',64,'全唐诗/poet.song.65000.json','["一卧孤村兩見冬，獨搔華髮思無窮。", "荒山極目漫汗雪，老樹當庭晝夜風。", "佳節妻兒具樽酒，茅齋斟酌慰愁翁。", "未央曉賀瞻天冕，正在爐烟縹緲中。"]'),
('47cea287-19d5-4bb2-9c1e-dc8a09fdaba6','歲暮福昌懷古四首 穀州故城','張耒','宋','宋诗','song-poetry','','[]','原北荒城舊穀州，文皇功業莽悠悠。',64,'全唐诗/poet.song.65000.json','["原北荒城舊穀州，文皇功業莽悠悠。", "天戈揮去開東夏，金甲歸來獻二囚。", "想像英姿輝日月，蒼茫故國委林丘。", "山川慘慘空回首，落日悲風蔓草秋。"]'),
('b71f7141-a8cf-4f43-b212-b8263ac25ff3','歲暮福昌懷古四首 張子房','張耒','宋','宋诗','song-poetry','','[]','謀臣何處不知名，誰與留侯敢抗衡。',64,'全唐诗/poet.song.65000.json','["謀臣何處不知名，誰與留侯敢抗衡。", "籌下興亡分楚漢，幄中談笑走韓彭。", "懼誅老將爭梟首，高卧成功更養生。", "戡亂直須希世哲，乘時兒女漫縱橫。"]'),
('b5f27295-a902-4b9b-9e59-340532256888','歲暮福昌懷古四首 李賀宅','張耒','宋','宋诗','song-poetry','','[]','少年詞筆動時人，末俗文章久失真。',64,'全唐诗/poet.song.65000.json','["少年詞筆動時人，末俗文章久失真。", "獨愛詩篇超物象，祇應山水與精神。", "清溪水拱荒凉宅，幽谷花開寂寞春。", "天上玉樓終恍惚，人間遺事已埃塵。"]'),
('f85f5f95-4f14-49bb-b328-b9403ece24a2','歲暮福昌懷古四首 連昌宮','張耒','宋','宋诗','song-poetry','','[]','欲問興亡已慘顔，桑田滄海變人間。',64,'全唐诗/poet.song.65000.json','["欲問興亡已慘顔，桑田滄海變人間。", "無情野水青春在，不動南山白日閒。", "伐木清溪寒剝啄，鳴禽高柳曉緡蠻。", "蛾眉皓齒終黄土，誰道仙宮有使還。"]'),
('bc8badbe-4ad8-4f5a-8167-f63fb142b763','以病在告寄楊器之','張耒','宋','宋诗','song-poetry','','[]','飲冷寒中不自知，故應病骨易尪羸。',64,'全唐诗/poet.song.65000.json','["飲冷寒中不自知，故應病骨易尪羸。", "老人素懶何妨病，太守兼容得自私。", "雨汗欺風元自濕，火雲挾日故行遲。", "江樓清絕真孤負，正是齋居禁酒時。"]'),
('b22d86cf-3483-4b72-8f2f-90d0d0678349','予元豐戊午歲自楚至宋由柘城至福昌年二十有五後十年當元祐二年再過宋都追感存歿悵然有懷','張耒','宋','宋诗','song-poetry','','[]','宋玉臺前官樹林，十年孤客獨沾襟。',64,'全唐诗/poet.song.65000.json','["宋玉臺前官樹林，十年孤客獨沾襟。", "白頭青鬢隔存歿，落日斷霞無古今。", "暮雲梁苑雁鶩暗，久泛吳船江海深。", "閱世悲歡嗟老眼，呼兒取酒十分斟。"]'),
('10c2c8a3-74e2-4fef-a728-fe9fd365a68d','宿馬莊寺','張耒','宋','宋诗','song-poetry','','[]','衝泥我馬僵欲仆，空村落日不逢人。',64,'全唐诗/poet.song.65000.json','["衝泥我馬僵欲仆，空村落日不逢人。", "開門野寺凈如掃，迎客老僧閒更真。", "佛案青黄園果細，齋厨汲洗野蔬頻。", "年來到處無餘念，靜對同龕金色身。"]'),
('3ea795ce-00b4-48ab-8178-88e9011b0049','永城道中','張耒','宋','宋诗','song-poetry','','[]','東行十日何所有，衰草白茅梁宋陂。',64,'全唐诗/poet.song.65000.json','["東行十日何所有，衰草白茅梁宋陂。", "大風官樹吹半折，欲雨野雲垂不飛。", "十年所遇半陳迹，千里獨愁懷所思。", "他日江湖片帆去，白頭青鏡久相期。"]'),
('c97b8e0f-34c5-48de-9f94-8b4a4acb74f5','贈柘城簿王微之','張耒','宋','宋诗','song-poetry','','[]','青衫得祿苦不足，白髮生頭頗有餘。',64,'全唐诗/poet.song.65000.json','["青衫得祿苦不足，白髮生頭頗有餘。", "賦就相如猶滌器，詩成賈島獨騎馿。", "先生五斗不挂眼，漫郎一官聊讀書。", "自古好賢慚好色，何人朝夕駕於株。"]'),
('fda33a5a-f93f-46ab-98c8-875826ce839c','夜泊泗上阻風雨','張耒','宋','宋诗','song-poetry','','[]','雨昏古岸斷人迹，天黑孤城閉水關。',64,'全唐诗/poet.song.65000.json','["雨昏古岸斷人迹，天黑孤城閉水關。", "燈火樽前初擁膝，風雲淮上欲移山。", "避人魚鳥那足怪，吹浪蛟龍不自閒。", "便使乘桴亦何事，滄波歲晚合知還。"]'),
('4c939858-5a30-40de-b70b-f33862915c6a','喜七兄疾愈二首  其一','張耒','宋','宋诗','song-poetry','','[]','凈名居士本非病，五禽先生能養身。',64,'全唐诗/poet.song.65000.json','["凈名居士本非病，五禽先生能養身。", "家人但訝少林觀，鄉里不知顔子貧。", "身內固知精是藥，人間惟有道通神。", "喜聞漸離烏皮几，花氣晴來欲逼人。"]'),
('c235613c-4a6c-4d6c-b718-9418d09c06e7','喜七兄疾愈二首  其二','張耒','宋','宋诗','song-poetry','','[]','南鄰隠士龍虎鼎，東寺比丘堅密身。',64,'全唐诗/poet.song.65000.json','["南鄰隠士龍虎鼎，東寺比丘堅密身。", "欲知十室有信處，顧此兩賢非世人。", "戰勝天魔初起定，寶成丹竈不妨貧。", "何時共此閒居士，紫領長衫樂社神。"]'),
('91c769fd-c312-4893-bfd5-0b880c147adf','送曹子方赴福建運判','張耒','宋','宋诗','song-poetry','','[]','平生鄴下曹公子，家世風流合有文。',64,'全唐诗/poet.song.65000.json','["平生鄴下曹公子，家世風流合有文。", "橫槊尚傳瞞相國，紫髯不是畫將軍。", "詔書寬大民何怨，刺史威嚴吏合勤。", "好作楚詞更下俚，雲中一降武夷君。"]'),
('2af393d3-9388-469a-a89f-b3a9404aad77','次韵盛居中夜飲','張耒','宋','宋诗','song-poetry','','[]','吳衣厭拂洛陽塵，夢寐一樽淮海濱。',64,'全唐诗/poet.song.65000.json','["吳衣厭拂洛陽塵，夢寐一樽淮海濱。", "每願脫巾常漉酒，况逢投轄苦留賓。", "蒼龍挂斗寒垂夜，翡翠浮花暖作春。", "上界高真足官府，追隨却屬散仙人。"]'),
('10510506-6a16-4c55-bbd7-ddd2022dd064','送麻田吳子野還山','張耒','宋','宋诗','song-poetry','','[]','麻田老仙身馭風，萬里一息如飛蓬。',64,'全唐诗/poet.song.65000.json','["麻田老仙身馭風，萬里一息如飛蓬。", "行窮山川出天外，閱盡世界歸壺中。", "經過賣藥勾漏客，鄉里高年南極翁。", "我亦有心遊八極，從公一借葛陂龍。"]'),
('f90da6ca-8806-4c29-a9e3-87bcaab4b57b','和无咎二首  其一','張耒','宋','宋诗','song-poetry','','[]','年芳經雨能幾許，客愁得暖不肯融。',64,'全唐诗/poet.song.65000.json','["年芳經雨能幾許，客愁得暖不肯融。", "眼看乳燕行已哺，手種小桃隨分紅。", "世情付睡莫涇渭，物態逢春無異同。", "清時頼是未禁酒，須惜紅紫轉頭空。"]'),
('390ca08e-e474-4d41-a4e9-5cad9e81a42d','和无咎二首  其二','張耒','宋','宋诗','song-poetry','','[]','愛酒苦無阿堵物，尋春奈有主人家。',64,'全唐诗/poet.song.65000.json','["愛酒苦無阿堵物，尋春奈有主人家。", "未容黄蜂釀成蜜，已怕惡雨不容花。", "雲間明月無可攬，海中蟠桃良未涯。", "浮名誤人不得脫，黑髮減來那得加。"]'),
('593b9c55-a3f8-49b5-af75-284ac188b946','和門下相公從駕幸學','張耒','宋','宋诗','song-poetry','','[]','繼聖文明舉舊章，儒宮傳蹕駐膠庠。',64,'全唐诗/poet.song.65000.json','["繼聖文明舉舊章，儒宮傳蹕駐膠庠。", "地疑闕里弦歌宅，經奏周書隸古行。", "遣子東夷思入學，受成西旅佇來王。", "魯侯在泮猶歌誦，盛事須刊孔子堂。"]'),
('c95b4200-f882-450a-a14d-355b06fc895d','效白體二首  其一','張耒','宋','宋诗','song-poetry','','[]','功名富貴付悠悠，高卧山城又過秋。',64,'全唐诗/poet.song.65000.json','["功名富貴付悠悠，高卧山城又過秋。", "燕坐香燈爲靜侶，閒行麋鹿是同遊。", "青黄草木新霜過，瀟灑溪山夜雨收。", "回首十年梁苑客，枉教白却少年頭。"]'),
('4b64b5cd-ab8d-44a5-a468-ed0f7cf623c6','效白體二首  其二','張耒','宋','宋诗','song-poetry','','[]','州貧須惜尊罍費，俗陋兼無妓樂名。',64,'全唐诗/poet.song.65000.json','["州貧須惜尊罍費，俗陋兼無妓樂名。", "幸有蒲團供燕坐，不妨藜杖助閒行。", "看炊香稻供齋飯，自採寒蔬試野羹。", "身外無營內無事，近來心氣儘和平。"]'),
('30b42e0b-18ad-48d8-af7e-4ae9bbc705cb','效白體贈楊補之','張耒','宋','宋诗','song-poetry','','[]','青衫居士斷葷血，一榻蕭然如在山。',64,'全唐诗/poet.song.65000.json','["青衫居士斷葷血，一榻蕭然如在山。", "堂下黄花驚歲晚，尊中綠酒覺官閒。", "胸中已了一事大，鏡裏莫驚兩鬢斑。", "我亦久懷伊洛興，煩君先爲卜禪關。"]'),
('ca80e77b-80ec-4f2b-95a1-430eaa0679dc','雙槐晚秀三月一日初見新葉','張耒','宋','宋诗','song-poetry','','[]','東皇無處著繁華，亦復分張到我家。',64,'全唐诗/poet.song.65000.json','["東皇無處著繁華，亦復分張到我家。", "他日老蒼悲敗枿，今晨嫩綠出新芽。", "禿翁承弁纖纖髮，村婦縈鬟草草花。", "桃李蹊中人絕跡，綠陰門巷正藏鴉。"]'),
('f1b05f19-1b93-42eb-b3ad-e08913859be6','休日不出聞西池遊人之盛','張耒','宋','宋诗','song-poetry','','[]','三日春風塵漲天，溝泥愁污破鞍韉。',64,'全唐诗/poet.song.65000.json','["三日春風塵漲天，溝泥愁污破鞍韉。", "掃門靜閉無來客，隠几深居學坐禪。", "薄雨掠塵時點點，細蟾窺夜獨娟娟。", "都人解與殘春競，半在西池聽管弦。"]'),
('c318518f-7efc-4634-85aa-dfb050a947f1','送李公輔赴宰宣城','張耒','宋','宋诗','song-poetry','','[]','與君騎竹即同遊，抱子相看髮已秋。',64,'全唐诗/poet.song.65000.json','["與君騎竹即同遊，抱子相看髮已秋。", "莫惜往來勤馬足，未須容易轉船頭。", "君方搜句窗間岫，我已懸情天際舟。", "抱槧石渠無所欲，勞君時致管城侯。"]'),
('cb7f81c7-4924-4da3-8f59-9e53af952d8d','休日不出','張耒','宋','宋诗','song-poetry','','[]','久厭衣冠塵土浸，賜休何苦馬駸駸。',64,'全唐诗/poet.song.65000.json','["久厭衣冠塵土浸，賜休何苦馬駸駸。", "窮冬積雪春不雨，昨日殘紅今綠陰。", "却掃不知門外事，安禪深得靜中心。", "讀書陶令非求解，禁酒揚雄不待箴。"]'),
('e5821688-cc15-4c6a-a78a-9c48b22b802d','次韵王敏仲至西池會飲','張耒','宋','宋诗','song-poetry','','[]','聖朝無復用舟師，戲遣艨艟插戟枝。',64,'全唐诗/poet.song.65000.json','["聖朝無復用舟師，戲遣艨艟插戟枝。", "沸浪有聲黄帽動，春風無力彩旗垂。", "不勝杯酌寧辭醉，傳語風光共此嬉。", "遠比永和真繼軌，臨摹繭紙看他時。"]'),
('7e42e1c1-b07d-48f8-a04d-9037d3b02d22','次韵王敏仲池上','張耒','宋','宋诗','song-poetry','','[]','春晚餘芳尚可尋，晴雷沙岸走車音。',64,'全唐诗/poet.song.65000.json','["春晚餘芳尚可尋，晴雷沙岸走車音。", "苑分廣樂和聲度，池受晴天倒影深。", "席上宮花輝御醴，坐中瓊樹間瑶林。", "歸人自畏嚴城鼓，却望橋西日未沉。"]'),
('0168fe1f-39fa-4887-9fc6-a759a9d1788b','題外甥楊克一詩篇末','張耒','宋','宋诗','song-poetry','','[]','十年不復上天津，閒却西都幾度春。',64,'全唐诗/poet.song.65000.json','["十年不復上天津，閒却西都幾度春。", "里巷夢中迷向背，山河句裏見精神。", "藝成斧鑿真須棄，學富篇章自不貧。", "莫倚詠兒兼贈婦，須知漸與老爲鄰。"]'),
('16e201ca-4b80-4de2-8060-b349f06a50b2','題李方叔文卷末','張耒','宋','宋诗','song-poetry','','[]','他日東坡譽子文，瀾翻健筆欲凌雲。',64,'全唐诗/poet.song.65000.json','["他日東坡譽子文，瀾翻健筆欲凌雲。", "决科正爾真餘事，射策如何但報聞。", "詭御獲禽雖可鄙，挽弓射葉亦徒勤。", "莫辭更擬相如作，寂寞思玄未放君。"]'),
('80f9a96f-a6af-4c36-b090-0fa8395b6313','劉景文許惠氈裘未至督之','張耒','宋','宋诗','song-poetry','','[]','塞上寒羊剪氈毛，軟於春絮膩於膏。',64,'全唐诗/poet.song.65000.json','["塞上寒羊剪氈毛，軟於春絮膩於膏。", "虀鹽倦客愁無褐，詩禮將軍許贈袍。", "雅服何妨冠蘇帽，瘦腰兼稱束郿絛。", "想公封寄應多憾，不挂長身襯佩刀。"]'),
('1ebfb901-1624-4473-832f-afe3b1d36824','耒嘗病痹親友以酒爲戒作小詩戲答','張耒','宋','宋诗','song-poetry','','[]','離騷僅得比痛飲，旨酒何曾廢善言。',64,'全唐诗/poet.song.65000.json','["離騷僅得比痛飲，旨酒何曾廢善言。", "因病細斟尤有味，無人獨酌亦成歡。", "何須巾漉醅浮螘，不待杯邀月入樽。", "但看井眉瓶作土，鴟夷仍自穩隨軒。"]'),
('c1d82f8d-5324-484e-bea5-2924392c819e','和呂與叔秘書省觀蘭','張耒','宋','宋诗','song-poetry','','[]','千里猗猗誰取將，忽驚顔色照文房。',64,'全唐诗/poet.song.65000.json','["千里猗猗誰取將，忽驚顔色照文房。", "每憐墜露時施澤，更許光風爲汎香。", "獨秀已先梁苑草，託根寧復楚天霜。", "坐令黄菊羞粗俗，只合蕭條籬下芳。"]'),
('28f1858e-d906-49d9-9045-f9e681aac7ed','次韵秦七寄道潜','張耒','宋','宋诗','song-poetry','','[]','衰疲久厭五更朝，每愧冥鴻在泬寥。',64,'全唐诗/poet.song.65000.json','["衰疲久厭五更朝，每愧冥鴻在泬寥。", "顧我塵冠彫舊鬢，愛君山桂長新條。", "文詞畫虎工逾拙，世味春冰老益消。", "只欲歸依香火社，高堂時聽法音潮。"]'),
('1cba4d7d-67fb-4cea-b527-b68babf13302','和宋二上元迎駕','張耒','宋','宋诗','song-poetry','','[]','拜揖清光咫尺間，彫輿欲動更移班。',64,'全唐诗/poet.song.65000.json','["拜揖清光咫尺間，彫輿欲動更移班。", "蓬萊不動鰲頭穩，閶闔未開天上閒。", "老去一官羞簡策，春來歸夢滿淮山。", "自慚衰病獨隨俗，醉逐遊人月下還。"]'),
('e1d64d34-f683-4b39-a225-4649dee1b2b2','和張提舉','張耒','宋','宋诗','song-poetry','','[]','刺舉威寒江國東，自慚多病幸優容。',64,'全唐诗/poet.song.65000.json','["刺舉威寒江國東，自慚多病幸優容。", "喜來丈室談何妙，往拜高軒願莫從。", "宛水春生初縐縠，鍾山雪盡見蟠龍。", "新年强起尋芳物，零落宮梅白一重。"]'),
('e318dd3f-dd68-4ebf-a158-d1c02ea6a96c','書壁','張耒','宋','宋诗','song-poetry','','[]','晴窗浴罷試春衣，芳草江南三月時。',64,'全唐诗/poet.song.65000.json','["晴窗浴罷試春衣，芳草江南三月時。", "陰合園林禽語樂，風和庭院絮飛遲。", "漫郎官事只畫諾，騷客生涯惟賦詩。", "極目江天已多恨，何須木落長年悲。"]'),
('285ce64f-d1b4-42fe-8fa1-57373ec18e0d','和上維道祈雨有應','張耒','宋','宋诗','song-poetry','','[]','江鄉長夏亢陽驕，太息秋原稻穗焦。',64,'全唐诗/poet.song.65000.json','["江鄉長夏亢陽驕，太息秋原稻穗焦。", "暑氣暮收秦地火，雨聲秋響浙江潮。", "夜齋凉送簷間滴，曉枕清聞竹上飄。", "椒醑禮神慚德薄，聖朝當宁四時調。"]'),
('63a07f56-97c3-4140-9f41-bdfda47786ef','早秋感懷','張耒','宋','宋诗','song-poetry','','[]','一行爲吏百事廢，幸此村州終日閒。',64,'全唐诗/poet.song.65000.json','["一行爲吏百事廢，幸此村州終日閒。", "莫疑虎兕率曠野，正見虎豹守天關。", "櫳簾晝靜燕已去，陂澤風高雁欲還。", "老見功名真戲事，惱人何苦鬢毛斑。"]'),
('946dfc25-4544-470f-9531-34c8a61df47e','木芙蓉菊花盛開','張耒','宋','宋诗','song-poetry','','[]','空山岑寂何所有，晚菊芙蓉相對幽。',64,'全唐诗/poet.song.65000.json','["空山岑寂何所有，晚菊芙蓉相對幽。", "伴我悠悠過閒日，憐渠灼灼媚窮秋。", "清香但欲持供佛，醉舞何妨插滿頭。", "此生萍梗難前料，知復明年相見不。"]'),
('5bf03974-0613-466d-879c-95adca883a71','正月八日坐局沽酒','張耒','宋','宋诗','song-poetry','','[]','爲問里閭何蹀躞，上元楚俗習張燈。',64,'全唐诗/poet.song.65000.json','["爲問里閭何蹀躞，上元楚俗習張燈。", "新春此時最佳處，獨我坐曹如定僧。", "霜林夢澤蒼茫野，烟草江邊寂寞城。", "小飲未能來喚藁，雙眸終日冷如冰。"]'),
('8d6ea7e4-2be8-4fa4-b5ea-717c85c3bb0e','神宗皇帝挽詞三首  其一','張耒','宋','宋诗','song-poetry','','[]','獨化陶鈞運聖謨，八方寥廓入雄圖。',64,'全唐诗/poet.song.65000.json','["獨化陶鈞運聖謨，八方寥廓入雄圖。", "將軍已勒邊山頌，博士初修玉檢書。", "西望忽驚新石闕，東來不是舊金輿。", "編年誰秉丹青筆，流落周南一腐儒。"]'),
('bcd31820-a55e-496f-9d5e-8c5207b6d0c3','神宗皇帝挽詞三首  其二','張耒','宋','宋诗','song-poetry','','[]','三百年成玉鼎丹，縞帷驚變紫宸班。',64,'全唐诗/poet.song.65000.json','["三百年成玉鼎丹，縞帷驚變紫宸班。", "遺弓有淚哀何及，嘶馬無蹤去不還。", "霜露無情金闕暗，山川常在石麟閒。", "青衫曾賜當年桂，欲附龍髯不可攀。"]'),
('8c44101f-4a4e-4732-88f0-83d1c98d787a','神宗皇帝挽詞三首  其三','張耒','宋','宋诗','song-poetry','','[]','風霆武略走夷蠻，雲漢文章著不刊。',64,'全唐诗/poet.song.65000.json','["風霆武略走夷蠻，雲漢文章著不刊。", "萬世基扃傳夏啟，百年威德畏軒轅。", "月游渭水儀空在，舞罷西陵淚未乾。", "腸斷反虞歌徹後，滿山松栢夜霜寒。"]'),
('ae6de046-71ef-4d28-b741-996ad4721e97','太皇太后挽詞','張耒','宋','宋诗','song-poetry','','[]','坐安民物由修己，默合神明爲至公。',64,'全唐诗/poet.song.65000.json','["坐安民物由修己，默合神明爲至公。", "他日已占懷月夢，後來方信補天功。", "四時化育坤無事，六合清明日正中。", "九載憂勤已陳迹，空留雙闕對青嵩。"]'),
('c46bd89c-1ae7-485d-929b-63f827c0c551','范忠宣挽歌二首  其一','張耒','宋','宋诗','song-poetry','','[]','晚生長恨老成空，猶及風流正始中。',64,'全唐诗/poet.song.65000.json','["晚生長恨老成空，猶及風流正始中。", "經國謀猷號名相，傳家正直似先公。", "回天巨力章猶在，拯溺深言老更忠。", "誰念人心弔邦國，新阡客泣白楊風。"]'),
('36f21cbf-d9eb-46bd-ae50-c07f18fa9ec5','范忠宣挽歌二首  其二','張耒','宋','宋诗','song-poetry','','[]','瀟湘卧病弔纍沉，賜詔君王用意深。',64,'全唐诗/poet.song.65000.json','["瀟湘卧病弔纍沉，賜詔君王用意深。", "多士方懷宣父日，蒼生竟失傅巖霖。", "氈裘他日瞻吾父，丹扆何人附舊箴。", "白首門生恩未報，悲詞空想薤歌音。"]'),
('654a66d7-72be-40bb-b9fa-a29eb94a889e','黄幾道哀挽','張耒','宋','宋诗','song-poetry','','[]','風流正始久無聲，頗復因公到後生。',64,'全唐诗/poet.song.65000.json','["風流正始久無聲，頗復因公到後生。", "千里族人分俸祿，百年鄉黨守題評。", "青雲脫屣烏臺峻，白首含香畫省清。", "但得將軍桃李在，寧須公相寫銘旌。"]'),
('a8ead2ea-24f5-4fb4-9364-2dfc729fa287','鄧慎思學士挽詞','張耒','宋','宋诗','song-poetry','','[]','青衫獻賦逢知己，白首耽書還誤身。',64,'全唐诗/poet.song.65000.json','["青衫獻賦逢知己，白首耽書還誤身。", "名著道山傳故事，政行兩郡泣遺民。", "文成典午羣疑泮，詩和少陵佳句新。", "歎息苦身成底事，湖墳宿草已愁人。"]'),
('62a7a64d-2cd0-4d0e-ab87-55b7b32afa7b','潘處士挽詩','張耒','宋','宋诗','song-poetry','','[]','異時輕士老才良，况復程能翰墨場。',64,'全唐诗/poet.song.65000.json','["異時輕士老才良，况復程能翰墨場。", "酒裏浮沈真得計，生涯落魄定何亡。", "德尊故社江山永，文付諸孫虎豹章。", "環堵如今空五柳，蕭然風物似紫桑。"]'),
('6b2d86fb-26e7-42c5-8423-e373619c019a','挽李少卿','張耒','宋','宋诗','song-poetry','','[]','幾年林下遠埃塵，儒雅風流誰與鄰。',64,'全唐诗/poet.song.65000.json','["幾年林下遠埃塵，儒雅風流誰與鄰。", "筆尾病來猶壯健，詩情老去更清新。", "幽齋昔日琴書換，新冢東風草木春。", "懷想只疑高興在，一吟遺句淚沾巾。"]'),
('98d1ef09-6845-4101-9deb-158c917f27e8','上文潞公生日','張耒','宋','宋诗','song-poetry','','[]','盛德元勳絕等倫，麟符虎節冠宗臣。',128,'全唐诗/poet.song.65000.json','["盛德元勳絕等倫，麟符虎節冠宗臣。", "靈椿上古身千載，一柱明堂力萬鈞。", "伐叛豹韜威尚凜，刊名金鼎鑄來新。", "風謠四海占賢相，笑咏山川是主人。", "萬里山河供氣概，九秋鵰鶚入精神。", "光華稷契無窮譽，强健喬松不老身。", "坐鎖熊羆瞻繡衮，燕居松鶴伴綸巾。", "只應便是神仙事，方丈蓬萊却未真。"]'),
('9f30a38e-42b5-46cb-b6f1-29032e83bb8f','至日有感','張耒','宋','宋诗','song-poetry','','[]','前年至日在何處，寒事蕭蕭客許昌。',128,'全唐诗/poet.song.65000.json','["前年至日在何處，寒事蕭蕭客許昌。", "乞火夜溫行客酒，披裘曉冒五更霜。", "暮投陽翟荒凉驛，正見人家燈火光。", "饑馬卧嘶毛瑟縮，羸童曉對色蒼茫。", "二年旅宦孤村僻，東望歸心洛水長。", "佳節幾逢長索寞，我生何事苦凄凉。", "更無賓客青山滿，只有風霜老樹蒼。", "昭代寧須厭留滯，馮公白首任爲郎。"]'),
('59f06b09-947c-435c-98ed-68ac51e0001b','清明卧病有感二首  其一','張耒','宋','宋诗','song-poetry','','[]','支離卧病逢佳節，漂泊西遊寄洛城。',96,'全唐诗/poet.song.65000.json','["支離卧病逢佳節，漂泊西遊寄洛城。", "重帽畏風惟益睡，青筇扶步不禁行。", "紅飄殘萼知風急，綠滿新枝聽鳥聲。", "不見賈生遺宅處，空傳金谷舊園名。", "悲歌身世驚將老，悵望古今空復情。", "笑看家人競時節，爭持新火照清明。"]'),
('a1ac53bc-c96b-423d-8f3f-5b08cc4982d7','清明卧病有感二首  其二','張耒','宋','宋诗','song-poetry','','[]','飄萍著處即爲家，伏枕悠悠對物華。',96,'全唐诗/poet.song.65000.json','["飄萍著處即爲家，伏枕悠悠對物華。", "處處鞦韆競男女，年年寒食亂風花。", "藥囊親坐勞頻檢，酒甕生塵亦可嗟。", "未老會尋吳市卒，苦貧須種邵平瓜。", "雲烟南望羣山會，水樹東浮去路斜。", "行止此身應有命，不須辛苦問生涯。"]'),
('e6b6549f-11e1-4075-a4d1-1398d5b10417','江上二首  其一','張耒','宋','宋诗','song-poetry','','[]','相別亦何事，相逢盡偶然。',24,'全唐诗/poet.song.65000.json','["相別亦何事，相逢盡偶然。", "愁腸貫綵筆，離夢繞朱弦。"]'),
('225a8669-3319-481d-bb27-75551141fb89','江上二首  其二','張耒','宋','宋诗','song-poetry','','[]','紛紛渾是夢，黯黯只消魂。',24,'全唐诗/poet.song.65000.json','["紛紛渾是夢，黯黯只消魂。", "江上浪無限，舟中酒一樽。"]'),
('34ae4a38-5e55-44ad-bfbb-03aa6b6d69e4','暇日六詠 雙白鴨','張耒','宋','宋诗','song-poetry','','[]','已斷鷹隼猜，仍叨主人惠。',24,'全唐诗/poet.song.65000.json','["已斷鷹隼猜，仍叨主人惠。", "皎潔靜天姿，雙棲莫相忌。"]'),
('b9466e31-8614-4e5b-8a3f-75c1f761cc1c','暇日六詠 蛙','張耒','宋','宋诗','song-poetry','','[]','越國未亡吳，曾動君王意。',24,'全唐诗/poet.song.65000.json','["越國未亡吳，曾動君王意。", "句踐自有心，憑車汝無恃。"]'),
('45d5cf0a-f0fd-49ab-bb65-95e7fce075a7','暇日六詠 百舌','張耒','宋','宋诗','song-poetry','','[]','曉語月斜樹，晝啼春霽天。',24,'全唐诗/poet.song.65000.json','["曉語月斜樹，晝啼春霽天。", "胸中自有激，不是故多言。"]'),
('49cf5c04-9388-4a8a-8444-420834069258','暇日六詠 柳絮','張耒','宋','宋诗','song-poetry','','[]','零亂委空風，悠揚點芳草。',24,'全唐诗/poet.song.65000.json','["零亂委空風，悠揚點芳草。", "却爲身最輕，華堂等閒到。"]'),
('ac59d0d8-0f76-4b04-b382-06c3ded7012c','暇日六詠 龜','張耒','宋','宋诗','song-poetry','','[]','映日漾清淵，沿沙暴玄甲。',24,'全唐诗/poet.song.65000.json','["映日漾清淵，沿沙暴玄甲。", "愛爾千歲姿，藏身一蓮葉。"]'),
('ee77101f-73d3-42e6-bc21-4725f7def187','暇日六詠 槐庭','張耒','宋','宋诗','song-poetry','','[]','清陰滿我庭，蒼蒼六槐老。',24,'全唐诗/poet.song.65000.json','["清陰滿我庭，蒼蒼六槐老。", "野性苦避人，青苔不須掃。"]'),
('e3c8bd63-9c6b-492f-8f33-bd140bbdf188','春日書事','張耒','宋','宋诗','song-poetry','','[]','禪宮門寂寂，庭草無行迹。',24,'全唐诗/poet.song.65000.json','["禪宮門寂寂，庭草無行迹。", "東風自掃階，疑是開簾客。"]'),
('0b9bb91f-9c26-47ad-bdf7-0f67e8232c73','鹿邑道中','張耒','宋','宋诗','song-poetry','','[]','去歲秋時去，今年秋又來。',24,'全唐诗/poet.song.65000.json','["去歲秋時去，今年秋又來。", "浮名何所得，歲月苦相催。"]'),
('d9ce28a3-115d-4c02-9621-ebd3819e71ae','予元祐六年六月罷著作佐郎除祕書丞是歲仲冬復除著作郎兼史院檢討復至舊局題屏','張耒','宋','宋诗','song-poetry','','[]','庭樹應如我，相逢益老蒼。',24,'全唐诗/poet.song.65000.json','["庭樹應如我，相逢益老蒼。", "別來秋苦雨，但覺瓦松長。"]'),
('d61e4bba-c470-4168-be01-86bc02f4ed63','絕句','張耒','宋','宋诗','song-poetry','','[]','雨麥渾漫壠，風梅已退粧。',24,'全唐诗/poet.song.65000.json','["雨麥渾漫壠，風梅已退粧。", "高鴻望燕塞，飛疾不成行。"]'),
('9ef37e75-3299-4f46-a4c9-36c45c0d1f1c','晝卧口占二首  其一','張耒','宋','宋诗','song-poetry','','[]','人事日益遠，秋居何颯然。',24,'全唐诗/poet.song.65000.json','["人事日益遠，秋居何颯然。", "苔隨牆半雨，葉放樹中天。"]'),
('cb9d8f6b-3f8e-44fb-a55d-0e35f7cde8a4','晝卧口占二首  其二','張耒','宋','宋诗','song-poetry','','[]','擾擾終何得，蕭蕭亦自如。',24,'全唐诗/poet.song.65000.json','["擾擾終何得，蕭蕭亦自如。", "將求解牛道，要解斲輪書。"]'),
('d1b076a2-0290-4a8b-b91b-6bec3344c326','發金陵折柳亭二首  其一','張耒','宋','宋诗','song-poetry','','[]','匆匆十日事，回首亦凄凉。',24,'全唐诗/poet.song.65000.json','["匆匆十日事，回首亦凄凉。", "何處無芳草，行人休斷腸。"]'),
('324a0e17-9c71-4a52-b8d5-dd7476985bf1','發金陵折柳亭二首  其二','張耒','宋','宋诗','song-poetry','','[]','瞿曇昔教我，林下一宵行。',24,'全唐诗/poet.song.65000.json','["瞿曇昔教我，林下一宵行。", "何事春江上，依依作俗情。"]'),
('4ee7f533-146f-49d7-93f9-ef80c25aac36','昔蘇先生遊廬山詩云平日懷真賞神遊杳靄間如今不是夢真個有廬山輒繼一首','張耒','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','人生孰非夢，夢裏見廬山。',24,'全唐诗/poet.song.65000.json','["人生孰非夢，夢裏見廬山。", "若了元無夢，何曾有往還。"]'),
('9f973707-fbdb-4ef4-a6b6-e864bbc8d04b','蘇先生詩云芒鞋青竹杖自掛百錢遊何事春山裏人人識故侯輒繼其後','張耒','宋','宋诗','song-poetry','','[]','齋心禮仙聖，不是愛山遊。',24,'全唐诗/poet.song.65000.json','["齋心禮仙聖，不是愛山遊。", "山中笑何等，白髮故諸侯。"]'),
('ec9cc452-ff28-4bb9-9c9f-fb826e4e5047','登山望海四首  其一','張耒','宋','宋诗','song-poetry','','[]','江闊風烟易晚，山高草木先秋。',28,'全唐诗/poet.song.65000.json','["江闊風烟易晚，山高草木先秋。", "獨倚闌干盡日，此身與世悠悠。"]'),
('e1a20ca6-b601-4e4a-af89-4a019bbe284d','登山望海四首  其二','張耒','宋','宋诗','song-poetry','','[]','仕宦此身漫爾，功名已老茫然。',28,'全唐诗/poet.song.65000.json','["仕宦此身漫爾，功名已老茫然。", "山鳥不須驚客，相親此復窮年。"]'),
('bd222703-2290-4ed6-8ff9-a54f3a3c970a','登山望海四首  其三','張耒','宋','宋诗','song-poetry','','[]','西望揚州何處，雲中雙塔巑岏。',28,'全唐诗/poet.song.65000.json','["西望揚州何處，雲中雙塔巑岏。", "山外雲濤斷日，夕陽應近長安。"]'),
('fc87e7e8-bbbd-4928-ac63-356b19c343e1','登山望海四首  其四','張耒','宋','宋诗','song-poetry','','[]','鳥去蒼烟古木，人歸綠野孤舟。',28,'全唐诗/poet.song.65000.json','["鳥去蒼烟古木，人歸綠野孤舟。", "信美雖非吾土，消憂且復登樓。"]'),
('d2d69211-4c28-48ba-9bd9-d89c615acddf','書寺中所見四首  其一','張耒','宋','宋诗','song-poetry','','[]','江市樵蘇早散，山家燈火常昏。',28,'全唐诗/poet.song.65000.json','["江市樵蘇早散，山家燈火常昏。", "紗帽搘筇獨立，龕中佛像無言。"]'),
('1a7e350e-999f-4681-8233-a9da0ef3bed2','書寺中所見四首  其二','張耒','宋','宋诗','song-poetry','','[]','日出鄰僧乞食，鐘鳴老叟關門。',28,'全唐诗/poet.song.65000.json','["日出鄰僧乞食，鐘鳴老叟關門。", "誰見春宵浄境，娟娟霽月當軒。"]'),
('36038776-dd1a-4333-97fa-adf0db8bdd71','書寺中所見四首  其三','張耒','宋','宋诗','song-poetry','','[]','叩戶誰驚午睡，烹茶聽客論詩。',28,'全唐诗/poet.song.65000.json','["叩戶誰驚午睡，烹茶聽客論詩。", "病裏雖成禁酒，興發何妨杖藜。"]'),
('0d01e945-c7af-4569-a6c8-1f36b80af612','書寺中所見四首  其四','張耒','宋','宋诗','song-poetry','','[]','閑裏光陰最好，病多談笑無多。',28,'全唐诗/poet.song.65000.json','["閑裏光陰最好，病多談笑無多。", "夢幻世間種種，楞枷卷裏消磨。"]'),
('2d64da02-0822-4b05-90cf-0afd96837ce2','讀潘郎文卷','張耒','宋','宋诗','song-poetry','','[]','霜鬢我猶謫宦，蝟鬚子合封侯。',28,'全唐诗/poet.song.65000.json','["霜鬢我猶謫宦，蝟鬚子合封侯。", "老拙何勞咄咄，疏慵且復悠悠。"]'),
('1243842f-baf1-44e3-a0e5-317a44d13141','夜坐三首  其一','張耒','宋','宋诗','song-poetry','','[]','門庭草草是客，寢室泠泠似僧。',28,'全唐诗/poet.song.65000.json','["門庭草草是客，寢室泠泠似僧。", "春寒猶須篝火，夜書頗復明燈。"]'),
('295a5598-ddde-4fc9-8687-465b4ed5fb8b','夜坐三首  其二','張耒','宋','宋诗','song-poetry','','[]','靈通寺前老圃，畦蔬想見如雲。',28,'全唐诗/poet.song.65000.json','["靈通寺前老圃，畦蔬想見如雲。", "謀拙嗟予飄泊，歸來與爾知聞。"]'),
('9325ce03-37da-4902-ad7e-f7acc0f297be','夜坐三首  其三','張耒','宋','宋诗','song-poetry','','[]','微寒騷屑窗竹，淡月朦朧夜天。',28,'全唐诗/poet.song.65000.json','["微寒騷屑窗竹，淡月朦朧夜天。", "路暗城頭傳警，漏稀更士高眠。"]'),
('36b5b891-18c5-4855-94b0-ad657c1e96b0','贈廣靖上人','張耒','宋','宋诗','song-poetry','','[]','七十龐眉禪客，曾見天衣老人。',28,'全唐诗/poet.song.65000.json','["七十龐眉禪客，曾見天衣老人。", "旃檀林中香氣，悠然時有餘氤。"]'),
('00d003c4-6f4e-49ae-b96f-bac43ea9475e','六言','張耒','宋','宋诗','song-poetry','','[]','青春要去便去，美酒得斟且斟。',28,'全唐诗/poet.song.65000.json','["青春要去便去，美酒得斟且斟。", "莫問世間蹀躞，須知老境侵尋。"]'),
